INSERT INTO public.photos VALUES (22308, 'Laboratorios ULTA 1966', 'Archivo Municipal. Gerardo Sancho Ramo. 10-02-1966. "Laboratorios ULTA". (Versi‚Ēú‚Ēān oficial, c‚Ēú‚Ēāmoda, del telediario). Fueron fundados en 1930 por el m‚Ēú¬ģdico F. Cuenca Villoro, centrados en la elaboraci‚Ēú‚Ēān de especialidades farmac‚Ēú¬ģuticas, veterinarias y productos diet‚Ēú¬ģticos. En 1966 inauguraron un nuevo y flamante laboratorio de la imagen, en la calle Juan Pablo Bonet 5-11, entre el Huerva y el Paseo del General Mola. All‚Ēú¬° se instal‚Ēú‚Ēā el primer microscopio electr‚Ēú‚Ēānico de la ciudad, para investigaci‚Ēú‚Ēān de la biolog‚Ēú¬°a molecular. En los a‚Ēú‚Ėíos 70 se constituy‚Ēú‚Ēā all‚Ēú¬° la secci‚Ēú‚Ēān "Diet‚Ēú¬ģticos ULTA" centrada en la comercializaci‚Ēú‚Ēān de productos diet‚Ēú¬ģticos (leches infantiles), que continu‚Ēú‚Ēā en esta ubicaci‚Ēú‚Ēān hasta los a‚Ēú‚Ėíos 80, en que cerraron sus instalaciones. El inmueble fue reconvertido, en los 90, en el actual bloque de viviendas. Imagen de los Laboratorios ULTA capturada, unos meses antes de su oficial inauguraci‚Ēú‚Ēān, desde el balc‚Ēú‚Ēān de un edificio que ya no existe, en el chafl‚Ēú√≠n de Maestro Marquina con Juan Pablo Bonet y Paseo General Mola.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63997500, -0.88735100, '0101000020E61000002A55A2EC2D65ECBFF9A067B3EAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15650042675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15650042675.webp', 'https://www.flickr.com/photos/zaragozaantigua/15650042675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22320, 'Parque Pignatelli 1969', 'Imagen desde cierta altura del parque de Pignatelli, bastante remozado al comienzo de la d‚Ēú¬ģcada, lo que le dio un nuevo aire a esta veterana zona verde de la ciudad, durante muchas d‚Ēú¬ģcadas "el parque" de todos los barrios que le rodean. A la derecha, y en primer t‚Ēú¬ģrmino, la zona de atracciones infantiles. A continuaci‚Ēú‚Ēān, la espesa atalaya que bordea los dep‚Ēú‚Ēāsitos de agua. Al fondo, la torre con los restos de los italianos fascistas que murieron por el triunfo del fascismo espa‚Ēú‚Ėíol. A la izquierda, el paseo de Cu‚Ēú¬ģllar bordea el parque, con la enorme sombra de los altos bloques que sustituyeron a las anteriores edificaciones del barrio "de los Chiflaos". A‚Ēú‚ēĎn quedaba alguna parcela por normalizar. La imagen se ha podido tomar desde la altura del reciente n‚Ē¨‚ēĎ 80 del paseo de Mola. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.63868300, -0.88600800, '0101000020E6100000DDD1FF722D5AECBF6EC1525DC0D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15870228181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15870228181.webp', 'https://www.flickr.com/photos/zaragozaantigua/15870228181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22321, 'P.‚Ē¨‚ēĎ del General Mola 1969', 'Imagen del andador central del paseo de Mola ocupado por Cabezudos y marabunta infantil bajando hacia el Centro urbano. Un gigante se atisba al fondo, entre la foresta. La captura se ha realizado cuando la comitiva acaba de cruzar la avenida de Goya, y llega a la zona donde a la izquierda queda la calle de La Paz, y a la derecha, Alar del Rey. Precisamente eso permite una m‚Ēú¬°nima visual, a la derecha, de dos de los elementos del paseo piqueteados pocos a‚Ēú‚Ėíos despu‚Ēú¬ģs, y sustituidos por as‚Ēú¬ģpticas y descontextualizadas moles de viviendas: el oblongo solar entre Alar del Rey y Goya, donde estuvo la f‚Ēú√≠brica de Manuel Vi‚Ēú‚Ėíado hasta 1925, luego el Colegio de las Hermanas Carmelitas de la Caridad, hasta 1949, y luego la Academia preparatoria de acceso a la AGM "La Figuera", hasta 1971; y el hotelito de los Palomar, con jard‚Ēú¬°n y estatua, que hac‚Ēú¬°a esquina entre Mola y Goya (b‚Ēú√≠rbara mezcolanza), a punto de ser derribado Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.64258600, -0.88618800, '0101000020E6100000DA71C3EFA65BECBF096F0F4240D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15872039932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15872039932.webp', 'https://www.flickr.com/photos/zaragozaantigua/15872039932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22348, 'Parque Pignatelli 1961', 'El Parque de Pignatelli era veterana zona verde desde que en 1904 fuera aqu‚Ēú¬° trasplantada la estatua del pr‚Ēú‚Ēācer que le da nombre. La imagen ha sido realizada tras una reciente remodelaci‚Ēú‚Ēān y puesta a punto del parque, con bancos nuevos, farolas trasplantadas del Paseo Independencia (tras su conversi‚Ēú‚Ēān en autopista central), y una manita de pintura en los muros del terrapl‚Ēú¬ģn sobre el que se encuentran los antiguos Dep‚Ēú‚Ēāsitos de agua. La chiquiller‚Ēú¬°a y juventud de entonces recuerdan esta sencilla escultura asociada a una fuente del parque. Tras la reforma del Parque en 1986, fue hecha desaparecer. Fuente visual: foto de Jos‚Ēú¬ģ Mar‚Ēú¬°a Rey, en www.rafaelcastillejo.com/torrero.htm', 1961, 1961, 1961, 'Anos 60', 'UNIVERSIDAD', 41.63582000, -0.88515000, '0101000020E6100000A5BDC1172653ECBF4512BD8C62D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20320774121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20320774121.webp', 'https://www.flickr.com/photos/zaragozaantigua/20320774121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22411, 'Juan Pablo Bonet 1966', 'Imagen de los reci‚Ēú¬ģn inaugurados "Laboratorios ULTA", en la calle Juan Pablo Bonet, ya con el r‚Ēú‚Ēātulo indicativo colocado en su sitio. Fuente visual: Gerardo Sancho Ramo, Archivo P‚Ēú‚ēĎblico Municipal.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63997500, -0.88735100, '0101000020E61000002A55A2EC2D65ECBFF9A067B3EAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24911502692.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24911502692.webp', 'https://www.flickr.com/photos/zaragozaantigua/24911502692/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22414, 'Parque de Pignatelli c.1963', 'Luminosa imagen del parque de Pignatelli tras su remodelaci‚Ēú‚Ēān de 1961, con la referencial estatua del pr‚Ēú‚Ēācer que le dio nombre, tras su destierro de la plaza de Arag‚Ēú‚Ēān. Fuente: www.todocoleccion.net/', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.63686900, -0.88504400, '0101000020E61000003BAC70CB4752ECBF096B63EC84D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25347087749.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25347087749.webp', 'https://www.flickr.com/photos/zaragozaantigua/25347087749/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22432, 'P.‚Ē¨‚ēĎ del General Mola 1967', 'Imagen de una unidad motor+remolque de la serie 100 en servicio en la l‚Ēú¬°nea 5 del tranv‚Ēú¬°a, "Torrero-Delicias", bajando por el paseo del general Mola en direcci‚Ēú‚Ēān al barrio de Delicias. La captura se ha realizado en el cruce del paseo con la avenida de Goya. Al fondo, el hotelito de la familia de Jos‚Ēú¬ģ Palomar esquinero entre ambos viales, poco antes de su demolici‚Ēú‚Ēān. Detr‚Ēú√≠s, emerge la cuadrangular torre del "Santuario de N‚Ē¨¬¨ S‚Ē¨¬¨ del Perpetuo Socorro". Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.64208400, -0.88620000, '0101000020E6100000EBE2361AC05BECBF76A4FACE2FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29617431453.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29617431453.webp', 'https://www.flickr.com/photos/zaragozaantigua/29617431453/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22496, 'Parque de Pignatelli c.1965', 'Colorista imagen capturada en el parque de Pignatelli junto al monumento dedicado al hom‚Ēú‚Ēānimo pr‚Ēú‚Ēācer ilustrado responsable, entre otras, de la magn‚Ēú¬°fica empresa del Canal Imperial de Arag‚Ēú‚Ēān. Originalmente estuvo enclavado en la Glorieta a la que dio nombre, entre 1865 y 1904, cuando fue expulsada del centro urbano y reubicada en un secarral que, con el tiempo, se convertir‚Ēú¬°a en frondoso parque urbano. El acu‚Ēú√≠tico aspecto del entorno al monumento le fue conferido por una importante reforma del parque acometida en 1961, hasta que otra gran reforma llevada a cabo en 1985 le dar‚Ēú¬°a su actual aspecto', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63688700, -0.88511800, '0101000020E6100000CD3AE3FBE252ECBFB01F628385D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48323107027.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48323107027.webp', 'https://www.flickr.com/photos/zaragozaantigua/48323107027/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22536, 'P.‚Ē¨‚ēĎ del General Mola 1971', 'Para empezar, se trata de una imagen mediocre, tomada desde el paseo del General Mola. Estamos cerca del encuentro con el final del Camino de las Torres, donde avanzaba la erecci‚Ēú‚Ēān del proyecto de "Edificio Residencial" a la altura del n‚Ēú‚ēĎmero 64 del Paseo. Uno m‚Ēú√≠s entre las decenas y decenas de construcciones desarrollistas de la Zaragoza del momento. Destacar, tal vez, lo na‚Ēú¬Ľf del dibujo del cartel publicitario, que representa un edificio postmoderno y funcional, absolutamente descontextualizado de su entorno, de 9 alturas m‚Ēú√≠s bajos. La importancia de la imagen es lo que se atisba parcialmente a su derecha: el "hotelito" o vivienda que empez‚Ēú‚Ēā siendo el n‚Ē¨‚ēĎ 26 duplicado, y ahora era el n‚Ē¨‚ēĎ 62, a‚Ēú‚ēĎn superviviente del burgu‚Ēú¬ģs ensanche conformado por el antiguo paseo de Sagasta. Esta fue "Villa Dolores", la cl‚Ēú¬°nica del Doctor Arpal, edificio exento, de tres plantas, identificable por su airosa, lateral y semicircular galer‚Ēú¬°a orientada hacia el sur. Ten‚Ēú¬°a el preceptivo jardincillo de los n‚Ēú‚ēĎmeros pares del paseo, por donde el ingreso principal. Otro acceso trasero daba al camino del S‚Ēú√≠bado, que en este tramo hoy se denomina calle Maestro Marquina. Tantos y tan burgueses antecedentes no le evitaron el trance de la piqueta, y unos a‚Ēú‚Ėíos despu‚Ēú¬ģs de tomada la imagen en color fue derribado por el emprendedor Colmenero para ganar edificabilidad, altura y plusval‚Ēú¬°as. A los nuevos ricos de la ciudad les motivan m‚Ēú√≠s otras cosas. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1971, 1971, 1971, 'Anos 70', 'UNIVERSIDAD', 41.64051100, -0.88657200, '0101000020E6100000F793313ECC5EECBF37DDB243FCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14851750022.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14851750022.webp', 'https://www.flickr.com/photos/zaragozaantigua/14851750022/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22551, 'P.‚Ē¨‚ēĎ del General Mola 1977', 'Airoso palacete que fuera de los Escoriaza-Averly en el n‚Ē¨‚ēĎ 32 del paseo, derribado sin contemplaciones, como muchos de sus compa‚Ēú‚Ėíeros, en la acera par del paseo de Sagasta de Zaragoza, con Cervantes. Poco le faltaba: la foto es de 1977 y en su lugar hay una mole monstruosa. Fuente visual: foto Jos‚Ēú¬ģ Monge, en www.rafaelcastillejo.com/', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64380300, -0.88624000, '0101000020E610000079060DFD135CECBF8908FF2268D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15026608165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15026608165.webp', 'https://www.flickr.com/photos/zaragozaantigua/15026608165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22559, 'P.‚Ē¨‚ēĎ del General Mola 1977', 'Fotograf‚Ēú¬°a de C‚Ēú¬ģsar S‚Ēú√≠nchez V‚Ēú√≠zquez. 1977. Imagen parcial del hotelito del Paseo de Sagasta n‚Ē¨‚ēĎ 52. Fue construido en 1919 por encargo de Luis L‚Ēú‚Ēāpez Ferrer al arquitecto Teodoro R‚Ēú¬°os Balaguer, que lo dise‚Ēú‚Ėí‚Ēú‚Ēā en l‚Ēú¬°neas ecl‚Ēú¬ģcticas. En 1961 su propietaria era Elena Valenzuela vendi‚Ēú‚Ēā el inmueble al Ministerio de la Vivienda y, posteriormente, al Ministerio de Cultura. Desaparecido por derribo a finales de los a‚Ēú‚Ėíos 90 del siglo XX.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64169800, -0.88655000, '0101000020E6100000029A081B9E5EECBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208824779.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208824779.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208824779/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22561, 'P.‚Ē¨‚ēĎ del General Mola 1977', 'Fotograf‚Ēú¬°a de C‚Ēú¬ģsar S‚Ēú√≠nchez V‚Ēú√≠zquez. 1977. Imagen del edificio de Sagasta 37. Supervive, con una adici‚Ēú‚Ēān construida en vertical sobre la galer‚Ēú¬°a acristalada de la derecha. El edificio a su izquierda (Sagasta 35), no.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64116000, -0.88613700, '0101000020E610000052D158FB3B5BECBF6EC0E78711D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208918499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208918499.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208918499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22562, 'P.‚Ē¨‚ēĎ del General Mola 1977', 'Fotograf‚Ēú¬°a de C‚Ēú¬ģsar S‚Ēú√≠nchez V‚Ēú√≠zquez. 1977. Imagen del hotelito del Paseo de Sagasta 52 (desaparecido). Al fondo, la iglesia de Ntra. Sra. del Perpetuo Socorro. A su derecha, avanzada construcci‚Ēú‚Ēān de la mole de 9 alturas de Sagasta 50, sobre hotelito desaparecido. A su izquierda, las vallas anunciadoras de la inminente construcci‚Ēú‚Ēān "de esmerada calidad" del horror de 9 alturas que sustituy‚Ēú‚Ēā al reci‚Ēú¬ģn desaparecido hotelito de Emerenciano Garc‚Ēú¬°a (Sagasta, 54).', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64169800, -0.88655000, '0101000020E6100000029A081B9E5EECBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15209597427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15209597427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15209597427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22571, 'P.‚Ē¨‚ēĎ del General Mola 1974', 'S‚Ēú√≠nchez Mill‚Ēú√≠n. 1974. Imagen de la vivienda modernista de Julio Juncosa en el paseo de Sagasta 11, proyectada por Jos‚Ēú¬ģ de Yarza en colaboraci‚Ēú‚Ēān con Ricardo Magdalena en 1903 y concluida en 1906. A pesar de que la foto est‚Ēú√≠ tomada en la d‚Ēú¬ģcada de los setenta, donde la mortalidad de casas, hotelitos y dem‚Ēú√≠s residencias de principios del siglo XX, era muy alta, este edificio sobrevive. Su vecina de la izquierda, de la que apenas se ve un pedazo, ha sido deconstruida totalmente, y recrecida. Fuente visual: Revista "Triunfo" (1974)', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.64342300, -0.88583000, '0101000020E61000000D1AFA27B858ECBF423F53AF5BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15342538943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15342538943.webp', 'https://www.flickr.com/photos/zaragozaantigua/15342538943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22572, 'P.‚Ē¨‚ēĎ del General Mola 1977', 'Fotograf‚Ēú¬°a de C‚Ēú¬ģsar S‚Ēú√≠nchez V‚Ēú√≠zquez. Imagen del edificio de Sagasta 40, esquina con la calle Zumalac‚Ēú√≠rregui. Supervive, restaurado y limpio, y conserva su zona de acceso con plantas y verja. Las vallas de la derecha se corresponden con el solar sobre el que m‚Ēú√≠s tarde se levantar‚Ēú√≠ la mole de 9 alturas de Sagasta 32-38, previo piqueteo de los hotelitos de los n‚Ēú‚ēĎmeros 32, 34, 36 y 38 del Paseo.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64330900, -0.88634100, '0101000020E6100000725303CDE75CECBF7A1C06F357D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15395961155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15395961155.webp', 'https://www.flickr.com/photos/zaragozaantigua/15395961155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22587, 'Laboratorios Verkos 1977', 'En una familiar rebotica nacieron en 1918 los Laboratorios Verkos. En 1938 levantaron, con proyecto del arquitecto Teodoro R‚Ēú¬°os Balaguer, un nuevo e interesante edificio en la calle Gil de Jasa n‚Ē¨‚ēĎ 16, esquina con calle Cervantes. All‚Ēú¬° investigaron, probaron y produjeron los productos de la marca comercial "Kemphor", como su elixir bucal (desde 1940), y su pasta de dientes (a‚Ēú‚Ėíos 50), adem‚Ēú√≠s de otros elementos secundarios. En 1976 abandonaron estas instalaciones, y se trasladaron a su actual ubicaci‚Ēú‚Ēān, en la carretera de Logro‚Ēú‚Ėío, km. 20, al lado de Pinseque. En 1979 la piqueta derrib‚Ēú‚Ēā el inmueble, y en su solar se levantaron las actuales viviendas. En la imagen el edificio de Laboratorio Verkos, en una captura realizada desde la calle Cervantes. Al fondo, tras el Huerva, los bloques de viviendas de la manzana entre Goya y Gran V‚Ēú¬°a. Fuente visual: "La evoluci‚Ēú‚Ēān urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64395000, -0.88680200, '0101000020E610000065E08096AE60ECBF2D211FF46CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15725815116.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15725815116.webp', 'https://www.flickr.com/photos/zaragozaantigua/15725815116/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22602, 'Avenida de Goya 1973', 'Foto del reciente derribo del edificio de la avenida Goya 2, esquina con el paseo del General Mola (hoy Sagasta). A la izquierda, parroquia del Perpetuo Socorro. Fuente: Diario Amanecer, 21 de marzo de 1973.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64264000, -0.88673500, '0101000020E610000072FE26142260ECBFFC8C0B0742D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18761537963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18761537963.webp', 'https://www.flickr.com/photos/zaragozaantigua/18761537963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22603, 'Avenida de Goya 1973', 'Foto Monge, 1973. Imagen tomada para noticiar con alborozo el inminente derribo del inmueble esquinero del paseo del General Mola con la avenida de Goya 2 (a la izquierda). Esta casa fue colegio de las Carmelitas de la Caridad entre 1925 y 1949 y luego academia La Figuera hasta 1971. Hab‚Ēú¬°a sido levantada sobre los terrenos de la f‚Ēú√≠brica de r‚Ēú‚Ēātulos esmaltados Vi‚Ēú‚Ėíado, sita all‚Ēú¬° entre 1902 y 1925. Fuente: Diario Amanecer, 16 de enero de 1973.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64264000, -0.88673500, '0101000020E610000072FE26142260ECBFFC8C0B0742D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18782536894.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18782536894.webp', 'https://www.flickr.com/photos/zaragozaantigua/18782536894/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22652, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1977', 'Imagen del que fuera hotelito de Raimundo Balet tras la parcelaci‚Ēú‚Ēān de un terreno inmediato a los dep‚Ēú‚Ēāsitos de agua de Pignatelli, en el n‚Ē¨‚ēĎ 15 (actual n‚Ē¨‚ēĎ 41) del paseo de Ruise‚Ēú‚Ėíores, en la primera d‚Ēú¬ģcada del siglo XX. Ten‚Ēú¬°a como vecinos a los "hotelitos" de ‚Ēú√ľngel An‚Ēú‚Ēās o Villa Rosita (a la izquierda) y el de Sebasti‚Ēú√≠n Rodr‚Ēú¬°guez (a la derecha, fuera de plano), todos de singular y notable f‚Ēú√≠brica, con entrada desde el paseo, y unas espaciosas traseras para jardines. Unos a‚Ēú‚Ėíos m‚Ēú√≠s tarde los tres ser‚Ēú¬°an recompuestos en formas y maneras m‚Ēú√≠s postmodernas, al gusto de las nuevas econom‚Ēú¬°as dirigentes. Fuente visual: "La evoluci‚Ēú‚Ēān urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63635700, -0.88902300, '0101000020E6100000B189CC5CE072ECBF53CA6B2574D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21200905842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21200905842.webp', 'https://www.flickr.com/photos/zaragozaantigua/21200905842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22653, 'Casa Palomar 1970', 'Entrada del hotelito de la familia de Jos‚Ēú¬ģ Palomar (construido en 1850), en la esquina del paseo del General Mola 50 con la Avenida Goya 1. Fue derribado poco despu‚Ēú¬ģs de esta captura fotogr‚Ēú√≠fica.. Fuente visual: revista "Arag‚Ēú‚Ēān tur‚Ēú¬°stico y monumental" (1970).', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64236500, -0.88654400, '0101000020E61000007AE1CE85915EECBF2A8C2D0439D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21305265178.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21305265178.webp', 'https://www.flickr.com/photos/zaragozaantigua/21305265178/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22681, '&quot;Rastro de Pignatelli&quot; 1973', 'La resaca de las fiestas mayores de 1973 incluy‚Ēú‚Ēā el anuncio de un proyecto "francamente avanzado" que, por supuesto, iba a influir poderosamente en el futuro de la ciudad: la realizaci‚Ēú‚Ēān de un "Rastro" en los antiguos dep‚Ēú‚Ēāsitos de agua de Pignatelli, algo que pondr‚Ēú¬°a a Zaragoza a la altura de ciudades como Madrid, Par‚Ēú¬°s, o Londres, al menos en este asunto. La propuesta supon‚Ēú¬°a cubrir los antiguos dep‚Ēú‚Ēāsitos al aire, y convertirlos en ocho grandes pabellones permanentes que cobijar‚Ēú¬°an docenas y docenas de tenderetes, a modo de galer‚Ēú¬°as de artesanos y vendedores de antig‚Ēú‚ēĚedades, cer‚Ēú√≠mica, forja, libros de lance, pinturas, flores, et caetera. El entorno ser‚Ēú¬°a convenientemente embellecido con jardines de rocalla, ‚Ēú√≠rboles (pl‚Ēú√≠tanos de sombra, chopos, cipreses), am‚Ēú¬ģn de florestas y rosales trepadores; muchos bancos para sentarse; varias fuentes de agua potable, y una grande ornamental; servicios p‚Ēú‚ēĎblicos, y dos quioscos con bar, flanqueando una plataforma cubierta para banda de m‚Ēú‚ēĎsica, o actuaciones teatrales. Los dep‚Ēú‚Ēāsitos subterr‚Ēú√≠neos ser‚Ēú¬°an reconvertidos en permanente sala de exposiciones de artesan‚Ēú¬°a. La realizaci‚Ēú‚Ēān de este proyecto ten‚Ēú¬°a un coste estimado de diez millones de pesetas, aunque por diversas circunstancias no fue realizado, entrando a formar parte, por ello, en el poblado territorio on‚Ēú¬°rico zaragozano, esas vastas geograf‚Ēú¬°as cohabitadas por los sue‚Ēú‚Ėíos y las pesadillas de la ciudad, en todas sus dimensiones. La imagen reproduce, coloreado, el proyectado "Rastro". Al sur, los accesos desde el parque de Pignatelli. A la derecha, los l‚Ēú¬°mites recayentes al paseo de los Ruise‚Ēú‚Ėíores, A la izquierda, el muro separador con las traseras de Maestro Estremiana. Al norte, muro junto a la calle (sin salida) de Santiago Guallar. Fuente visual: "Heraldo de Arag‚Ēú‚Ēān". Cromatismo a‚Ēú‚Ėíadido por GAZA.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63629500, -0.88602900, '0101000020E6100000BAD7497D595AECBFDDCD531D72D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26365421172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26365421172.webp', 'https://www.flickr.com/photos/zaragozaantigua/26365421172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22766, 'Alar del Rey 1972', 'Imagen bien poco postalera de la calle Alar del Rey, entre el primer tramo de la calle del Arzobispo Dom‚Ēú¬ģnech, y el paseo del General Mola, al fondo, sometida a una intensa intervenci‚Ēú‚Ēān relacionada con la renovaci‚Ēú‚Ēān de la red de alcantarillado de la zona. A la izquierda, traseras de las parcelas 13 y 15 recayentes a la calle de Zumalac‚Ēú√≠rregui, que perduran, oh sorpresa. Un poco m‚Ēú√≠s adelante, colegio femenino Santo Tom‚Ēú√≠s de Aquino instalado en la antigua "Villa Teresa", esquinera con Gil de Jasa. A la derecha, academia La Figuera, recientemente clausurada. Al fondo, el n‚Ē¨‚ēĎ 21 del paseo del General Mola, recayente a la calle de la Paz, y a su derecha, apenas visible, la cl‚Ēú¬°nica del doctor Bandragen. Fuente visual: AMZ.', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.64314100, -0.88788600, '0101000020E6100000B07092E68F69ECBFBEDBBC7152D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33229001000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33229001000.webp', 'https://www.flickr.com/photos/zaragozaantigua/33229001000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22808, 'Parque de Pignatelli 1973', 'Imagen capturada en el "mini-parque de atracciones" habilitado a la derecha de la entrada norte al parque de Pignatelli y recayente a la glorieta de Diego Vel‚Ēú√≠zquez. La escena se centra en la zona de camas el‚Ēú√≠sticas donde los peques brincaban que te brincaban. Adem‚Ēú√≠s, este recoleto recinto contaba tambi‚Ēú¬ģn con un singular circuito acu‚Ēú√≠tico de barquitos y una zona de cochecitos de choque. Todo un oasis para la chiquiller‚Ēú¬°a de los barrios lim‚Ēú¬°trofes.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63873100, -0.88634100, '0101000020E6100000725303CDE75CECBF7FF8F9EFC1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51530365811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51530365811.webp', 'https://www.flickr.com/photos/zaragozaantigua/51530365811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22937, 'Gil de Jasa 1980', 'Acristaladas traseras de la casa del n‚Ē¨‚ēĎ 40 del paseo de Sagasta, dise‚Ēú‚Ėíada en 1910 por Luis de la Figuera. Poco despu‚Ēú¬ģs de capturar esta imagen fue recrecida en una altura y esta parte, recayente a la calle de Antonio Gil de Jasa, ser‚Ēú¬°a remozada sustituyendo la quejumbrosa y provinciana solanera caracter‚Ēú¬°stica de los hotelitos del antiguo paseo, por una m‚Ēú√≠s moderna fachada compuesta por vanos y ladrillo caravista. A la izquierda, la calle de Tom‚Ēú√≠s Zumalac‚Ēú√≠rregui. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1980, 1980, 1980, 'Anos 80', 'UNIVERSIDAD', 41.64331900, -0.88654300, '0101000020E610000063EDEF6C8F5EECBF9DF2E84658D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32534749632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32534749632.webp', 'https://www.flickr.com/photos/zaragozaantigua/32534749632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22991, 'Parque Pignatelli a‚Ēú‚Ėíos 90', 'Vista del Parque Pignatelli de Zaragoza desde la torre de la iglesia de San Antonio. A su izquierda, los dep‚Ēú‚Ēāsitos de agua hom‚Ēú‚Ēānimos a‚Ēú‚ēĎn en funcionamiento en la ‚Ēú¬ģpoca de la imagen.', 1990, 1990, 1999, 'Anos 90', 'UNIVERSIDAD', 41.63742900, -0.88528100, '0101000020E610000048A5D8D13854ECBFD042024697D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20985535940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20985535940.webp', 'https://www.flickr.com/photos/zaragozaantigua/20985535940/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23038, 'Paseo de Sagasta 1990', 'Imagen capturada desde la altura del veterano inmueble del n‚Ē¨‚ēĎ 72 del paseo de Sagasta, con una buena vista del tramo de este paseo que confluye, en primer t‚Ēú¬ģrmino, con el arranque de la calle de Juan Pablo Bonet, hacia la izquierda, y el final del camino de las Torres, desde la derecha. La configuraci‚Ēú‚Ēān edilicia definitiva de esta zona del ensanche burgu‚Ēú¬ģs de principios del siglo XX, se fue completando con nuevos inmuebles que desde la d‚Ēú¬ģcada de los a‚Ēú‚Ėíos 50 fueron sustituyendo las originales viviendas unifamiliares que determinaban el estilo y escala del paseo en la escena que la imagen representa. A‚Ēú‚ēĎn en los a‚Ēú‚Ėíos 90 hubo dos casos, uno relacionado con el "desatasque" del pol‚Ēú¬ģmico edificio del emprendedor inmobiliario Colmenero, que construido en los a‚Ēú‚Ėíos 70 en el n‚Ē¨‚ēĎ 62, a la izquierda del paseo, estuvo en barbecho durante casi veinte a‚Ēú‚Ėíos hasta que finalmente fue legalmente ocupado. Y en la acera de enfrente, el veterano edificio del n‚Ē¨‚ēĎ 37 fue objeto de una importante rehabilitaci‚Ēú‚Ēān terminada casi al principio de esta d‚Ēú¬ģcada. A su izquierda, el n‚Ē¨‚ēĎ 35 ser‚Ēú¬°a finalmente remodelado a‚Ēú‚Ėíos despu‚Ēú¬ģs con proyecto de Jos‚Ēú¬ģ Manuel P‚Ēú¬ģrez Latorre, ya en el principio de la siguiente d‚Ēú¬ģcada y siglo.', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.64039100, -0.88638400, '0101000020E6100000435376FA415DECBF8DD31055F8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50376532331.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50376532331.webp', 'https://www.flickr.com/photos/zaragozaantigua/50376532331/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23434, 'Calle de Gil de Jasa 1969', 'Imagen de la antigua "Villa Teresa", singular casa de post‚Ēú¬°n esquinera entre las calles de Gil de Jasa y de la Cadena y construida en bizarras formas neog‚Ēú‚Ēāticas en los albores del siglo XX, cuando a‚Ēú‚ēĎn no era obligatorio presentar proyecto de obra ni planos ante el Ayuntamiento. Por ello, esta es una de las pocas referencias visuales de que este edificio fue una realidad, no una enso‚Ēú‚Ėíaci‚Ēú‚Ēān. Desde el a‚Ēú‚Ėío 1950 aqu‚Ēú¬° estuvo establecido el Hogar-Residencia Femenino "Isabel de Arag‚Ēú‚Ēān" del Auxilio Social, con capacidad para cuarenta chicas que cursaban estudios de Bachiller, Magisterio, Filosof‚Ēú¬°a y Letras... En el momento de capturar esta fotograf‚Ēú¬°a la casa estaba alquilada por la familia propietaria (Delgado Yarza) al colegio femenino de bachillerado "Santo Tom‚Ēú√≠s de Aquino", sito en la calle Gil de Jasa n‚Ē¨‚ēĎ 24, esquina con la calle Alar del Rey. La desconcertante arquitectura del inmueble propici‚Ēú‚Ēā que haya pasado a la memoria de la ciudad con una panoplia de fant‚Ēú√≠sticas denominaciones: "Casa o Mansi‚Ēú‚Ēān de las Hadas", "Casa de las Brujas"..., seguramente por el extravagante remate del torreoncillo de la izquierda. Pocos a‚Ēú‚Ėíos despu‚Ēú¬ģs, tras el cese de actividad educativa, esta simpar construcci‚Ēú‚Ēān fue derribada, y sobre el solar resultante se levant‚Ēú‚Ēā el actual Colegio Mayor Pe‚Ēú‚Ėíalba, con capacidad para 62 residentes numerarias femeninas del Opus Dei (por a‚Ēú‚Ėío acad‚Ēú¬ģmico). Al fondo a la izquierda, los bloques de los n‚Ēú‚ēĎmeros 11-13 y 15 de la calle de Zumalac‚Ēú√≠rregui, que a‚Ēú‚ēĎn existen. El resto de edificios han sido sustituidos por otros nuevos, modernos.', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.64301300, -0.88693200, '0101000020E6100000F2D3B837BF61ECBF91F3FE3F4ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14652008628.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14652008628.webp', 'https://www.flickr.com/photos/zaragozaantigua/14652008628/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23482, 'Calle de Gil de Jasa c.1960', 'Imagen parcial de la antigua "Villa Teresa", singular casa de post‚Ēú¬°n esquinera entre las calles de Gil de Jasa y de la Cadena (luego Alar del Rey) y construida en bizarras formas neog‚Ēú‚Ēāticas en los albores del siglo XX, cuando a‚Ēú‚ēĎn no era obligatorio presentar proyecto de obra ni planos ante el Ayuntamiento. Por ello, esta es una de las pocas referencias visuales de que este edificio fue una realidad, no una enso‚Ēú‚Ėíaci‚Ēú‚Ēān. En el momento de capturar esta fotograf‚Ēú¬°a la casa, propiedad de la familia Delgado Yarza, llevaba poco tiempo alquilada como sede del colegio femenino de bachillerado "Santo Tom‚Ēú√≠s de Aquino", sito en la calle Gil de Jasa n‚Ē¨‚ēĎ 24. La desconcertante arquitectura neomedieval del inmueble propici‚Ēú‚Ēā que haya pasado a la memoria de la ciudad con una panoplia de fant‚Ēú√≠sticas y/o rom‚Ēú√≠nticas denominaciones: "Casa o Mansi‚Ēú‚Ēān de las Hadas", "Casa de las Brujas"..., seguramente por el extravagante chapitel que remata el torreoncillo de la izquierda, que en esta imagen no llega a verse en su integridad. A principios de la prodigiosa (en t‚Ēú¬ģrminos urban‚Ēú¬°sticos) d‚Ēú¬ģcada de los a‚Ēú‚Ėíos setenta, poco despu‚Ēú¬ģs del cese de actividad educativa, esta simpar construcci‚Ēú‚Ēān fue derribada. Fuente visual: www.rafaelcastillejo.com/', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.64294800, -0.88697900, '0101000020E61000001EA4A7C82162ECBFA983BC1E4CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44478146955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44478146955.webp', 'https://www.flickr.com/photos/zaragozaantigua/44478146955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23484, 'Calle de Gil de Jasa 1960', 'Dibujo representando la singular estampa de la antigua "Villa Teresa" construida en bizarras formas neog‚Ēú‚Ēāticas en los albores del siglo XX, y con ingreso principal por la calle de Gil de Jasa, en primer t‚Ēú¬ģrmino. A la izquierda, la calle de Alar del Rey. La casa, propiedad de la familia Delgado Yarza, estaba reci‚Ēú¬ģn alquilada para acoger el bachillerato femenino del colegio Santo Tom‚Ēú√≠s de Aquino, y as‚Ēú¬° ser‚Ēú¬°a hasta el principio de la d‚Ēú¬ģcada siguiente, cuando este colegio fue trasladado a unas nuevas instalaciones en la calle del Maestro Estremiana n‚Ē¨‚ēĎ 48. Fuente visual: "Grabado en la mente. Historia del Colegio Santo Toma‚ē†√ľs Aquino de Zaragoza", Santiago Sancho Vallest‚Ēú¬°n.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.64294800, -0.88697900, '0101000020E61000001EA4A7C82162ECBFA983BC1E4CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44859897284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44859897284.webp', 'https://www.flickr.com/photos/zaragozaantigua/44859897284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23485, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1928', 'Imagen de la fachada principal de la nueva y singular casa de Jos‚Ēú¬ģ Sol‚Ēú√≠ proyectada por Regino Borobio y construida en el arranque del paseo de Ruise‚Ēú‚Ėíores, desde donde se ha capturado la fotograf‚Ēú¬°a. Sus formas entre racionalistas y regionalistas definen un edificio de tres alturas y planta en ele, con amplia zona de huerto y estanque en las traseras lindando con el inmediato parque de Pignatelli cuando por su interior todav‚Ēú¬°a circulaba la tranviaria l‚Ēú¬°nea de Torrero. En 1959 esta casa fue reformada por el propio Regino Borobio por encargo de las Religiosas Mercedarias Misioneras para convertirlo en la nueva sede del Colegio de Nuestra Se‚Ēú‚Ėíora de la Merced (dejando as‚Ēú¬° su hasta entonces domicilio en la calle Moncayo del barrio de Cari‚Ēú‚Ėíena), hasta hoy. En los a‚Ēú‚Ėíos setenta fue construida una moderna ampliaci‚Ēú‚Ēān edilicia del colegio sobre buena parte de la antigua zona de huerto y estanque traseros. Fuente visual: Archivo Borobio, en M‚Ēú‚Ēānica V‚Ēú√≠zquez Astorga, "Recorrido por el pasado de una zona urbana residencial: el paseo de Ruise‚Ēú‚Ėíores de Zaragoza".', 1928, 1928, 1928, 'Anos 20', 'UNIVERSIDAD', 41.63817200, -0.88656500, '0101000020E610000058E71890BD5EECBF889CBE9EAFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45264183611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45264183611.webp', 'https://www.flickr.com/photos/zaragozaantigua/45264183611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24008, 'Colegio Alem‚Ēú√≠n 1937', '"Un aspecto de la patri‚Ēú‚Ēātica fiesta celebrada en el Colegio Alem‚Ēú√≠n, con motivo del 48‚Ē¨‚ēĎ aniversario del nacimiento del Canciller alem‚Ēú√≠n Hitler". El Colegio Alem‚Ēú√≠n estaba situado en la calle de Cervantes, y albergaba una colonia nazi que prest‚Ēú‚Ēā sus servicios al bando fascista local, usurpadores de la democracia entre 1936 y 1977. En el centro de la foto, retrato de Adolf Hitler. Fuente: Revista Arag‚Ēú‚Ēān, mayo de 1937.', 1937, 1937, 1937, 'Anos 30', 'UNIVERSIDAD', 41.64397500, -0.88708100, '0101000020E61000002EE57CB1F762ECBF8638D6C56DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23976258180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23976258180.webp', 'https://www.flickr.com/photos/zaragozaantigua/23976258180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24107, 'Calle de Cervantes, c.1942', 'Imagen capturada durante un homenaje a la bandera nacionalsocialista alemana realizado en el patio del Colegio Alem‚Ēú√≠n sito en la calle de Miguel de Cervantes n‚Ē¨‚ēĎ 9. La derrota militar en mayo de 1945 del r‚Ēú¬ģgimen nazi provoc‚Ēú‚Ēā, entre otras consecuencias, el cierre de los colegios alemanes en el extranjero. El de Zaragoza ser‚Ēú¬°a reabierto en 1956, muy distinto del de la fotograf‚Ēú¬°a.', 1942, 1942, 1942, 'Anos 40', 'UNIVERSIDAD', 41.64398300, -0.88742400, '0101000020E6100000A6EF3504C765ECBF0917F2086ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51789271991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51789271991.webp', 'https://www.flickr.com/photos/zaragozaantigua/51789271991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24179, 'Avenida de Goya c.1962', 'Cubrimiento de la zanja del ferrocarril en el tramo entre el paseo del General Mola, desde donde est‚Ēú√≠ capturada la escena, y el paseo de Fernando el Cat‚Ēú‚Ēālico. A la izquierda, el hotelito de los Palomar, luego derribado. A su lado, arbolado espacio junto a la iglesia del Perpetuo Socorro. Al fondo, ins‚Ēú‚Ēālita vista de la chaflanera esquina del original taller de hierro forjado de Pascual Gonz‚Ēú√≠lez, luego derribado, a la entrada del camino del S‚Ēú√≠bado. A la derecha, e inmediata, la academia de La Figuera, luego derribada.', 1962, 1962, 1962, 'Anos 60', 'UNIVERSIDAD', 41.64236500, -0.88654400, '0101000020E61000007AE1CE85915EECBF2A8C2D0439D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15428838548.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15428838548.webp', 'https://www.flickr.com/photos/zaragozaantigua/15428838548/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24186, 'Calle del Tenor Fleta 1951', 'Imagen de la calle del Tenor Fleta en su tramo cercano a General Mola, hacia donde se dirige la mirada. La trinchera del ferrocarril sin cubrir ha sido capturada desde uno de los puentes sobre las v‚Ēú¬°as. Al fondo, el puente que salvaba el Paseo de Mola, y detr‚Ēú√≠s, el inmueble esquinero del paseo del General Mola con la avenida de Goya, que fue colegio de las Carmelitas de la Caridad entre 1925 y 1949 y luego academia La Figuera hasta 1971. Hab‚Ēú¬°a sido levantada sobre los terrenos de la f‚Ēú√≠brica de r‚Ēú‚Ēātulos esmaltados Vi‚Ēú‚Ėíado, sita all‚Ēú¬° entre 1902 y 1925. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64209800, -0.88595500, '0101000020E61000002849D74CBE59ECBFDB696B4430D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20131601148.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20131601148.webp', 'https://www.flickr.com/photos/zaragozaantigua/20131601148/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24462, 'F‚Ēú√≠brica de calzado 1924', 'F‚Ēú√≠brica de calzado de Jos‚Ēú¬ģ Sorrosal, 1924. En 1916, Jos‚Ēú¬ģ Sorrosal traslad‚Ēú‚Ēā su f‚Ēú√≠brica de zapatos al Camino del S‚Ēú√≠bado 1, esquina con la calle Benavente (foto). En 1926 la f‚Ēú√≠brica cambi‚Ēú‚Ēā de due‚Ēú‚Ėío, pasando a ser Mat‚Ēú¬°as Peyrona. As‚Ēú¬°, tambi‚Ēú¬ģn dejaron de comercializarse los Calzados Sorrosal en la tienda de Coso 24. El torre‚Ēú‚Ēān de la izquierda estaba dedicado a vivienda del propietario. Fuente: M‚Ē¨¬¨ Pilar Biel Ib‚Ēú√≠‚Ēú‚Ėíez, Zaragoza y la industrializaci‚Ēú‚Ēān: la arquitectura industrial 1875-1936, IFC, 2004.', 1924, 1924, 1924, 'Anos 20', 'UNIVERSIDAD', 41.64293200, -0.88835800, '0101000020E61000009E7AA4C16D6DECBFA4C684984BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19780485706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19780485706.webp', 'https://www.flickr.com/photos/zaragozaantigua/19780485706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24486, 'F‚Ēú√≠brica de calzado 1934', 'F‚Ēú√≠brica de calzado instalada en 1916 entre el Camino del S‚Ēú√≠bado y la calle Benavente. Desde 1926, propiedad de Mat‚Ēú¬°as Peyrona. Vemos el edificio desde la la calle del ferrocarril a Barcelona (actual avenida de Goya) con la calle del Camino del S‚Ēú√≠bado (actual Arzobispo Domenech), y la de Benavente, a la izquierda. Al fondo a la derecha, el r‚Ēú¬°o Huerva. Fuente: www.todocoleccon.net', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.64293200, -0.88835800, '0101000020E61000009E7AA4C16D6DECBFA4C684984BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24300027703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24300027703.webp', 'https://www.flickr.com/photos/zaragozaantigua/24300027703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24522, 'P.‚Ē¨‚ēĎ de Torrero 1899', 'Dibujo de la antigua f‚Ēú√≠brica de harinas de Almech ya reconvertida como f‚Ēú√≠brica "La Pilar" de la Sociedad Espa‚Ēú‚Ėíola del Acumulador Tudor, ubicada en el paseo de Torrero en la estrat‚Ēú¬ģgica ubicaci‚Ēú‚Ēān entre el camino de las Torres (izquierda) y el camino de las Alcachoferas (derecha). En primer t‚Ēú¬ģrmino, una unidad de la tranviaria de tracci‚Ēú‚Ēān animal en servicio en l‚Ēú¬°nea de Torrero, en descenso hacia la plaza de la Constituci‚Ēú‚Ēān. A la derecha, la caudalosa acequia de las Adulas o de San Jos‚Ēú¬ģ que abastec‚Ēú¬°a de agua y energ‚Ēú¬°a a la f‚Ēú√≠brica. La vecina torre de Forni‚Ēú¬ģs, al fondo, a‚Ēú‚Ėíos despu‚Ēú¬ģs se acumular‚Ēú¬°a al per‚Ēú¬°metro industrial de esta destacable empresa durante una de las notables expansiones. Fuente visual: Hauser y Menet, en Universidad de Sevilla', 1899, 1899, 1899, 'Siglo XIX', 'UNIVERSIDAD', 41.63940900, -0.88593500, '0101000020E610000061376C5B9459ECBF50E27327D8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39498948395.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39498948395.webp', 'https://www.flickr.com/photos/zaragozaantigua/39498948395/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24876, 'Casa de la Paz a‚Ēú‚Ėíos 80', 'Paseo de Sagasta 52. En 1987, colectivos de okupaci‚Ēú‚Ēān de Zaragoza reutilizaron el edificio. Era un chal‚Ēú¬ģ de arquitectura ecl‚Ēú¬ģctica, construido en 1919 y abandonado en 1961. Fue desalojado en 1993 y derribado posteriormente. Hoy ocupa el solar un centro de salud. M‚Ēú√≠s informaci‚Ēú‚Ēān: www.zaragozarebelde.org/una-vision-parcial-de-la-ocupacio...', 1980, 1980, 1989, 'Anos 80', 'UNIVERSIDAD', 41.64169800, -0.88655000, '0101000020E6100000029A081B9E5EECBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14761552780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14761552780.webp', 'https://www.flickr.com/photos/zaragozaantigua/14761552780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24884, 'Casa de la Paz c.1989', 'Paseo de Sagasta 52. En 1987, colectivos de okupaci‚Ēú‚Ēān de Zaragoza reutilizaron el edificio. Era un chal‚Ēú¬ģ de arquitectura ecl‚Ēú¬ģctica, construido en 1919 y abandonado en 1961. Fue desalojado en 1993 y derribado posteriormente. Hoy ocupa el solar un centro de salud. M‚Ēú√≠s informaci‚Ēú‚Ēān: www.zaragozarebelde.org/una-vision-parcial-de-la-ocupacio...', 1989, 1989, 1989, 'Anos 80', 'UNIVERSIDAD', 41.64172000, -0.88652200, '0101000020E610000086E7A562635EECBF359886E123D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14916167836.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14916167836.webp', 'https://www.flickr.com/photos/zaragozaantigua/14916167836/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24886, 'P.‚Ē¨‚ēĎ de Sagasta 1925', 'Archivo Mora. "Casa Faci", encargo de ‚Ēú√ľngel Faci a Regino Borobio, en su localizaci‚Ēú‚Ēān del Paseo de Sagasta, chafl‚Ēú√≠n con el inicio de Camino de las Torres. La notorieda de este edificio, en el que se entroncan las corrientes estil‚Ēú¬°sticas antiguas y modernas, no pas‚Ēú‚Ēā desapercida, y fue rese‚Ēú‚Ėíado en la madrile‚Ēú‚Ėía revista "Arquitectura" (n‚Ēú‚ēĎm. 98, 1927). Pero las cosas son como son, y ser‚Ēú√≠ derribada en 1971 para dar paso a un bloque de viviendas m‚Ēú√≠s aprovechadico en lo vertical.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.64011800, -0.88620700, '0101000020E61000008A8F4FC8CE5BECBF5CCAF962EFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14930631405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14930631405.webp', 'https://www.flickr.com/photos/zaragozaantigua/14930631405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24902, 'P.‚Ē¨‚ēĎ del General Mola c.1973', 'Foto: Gonzalo Borr‚Ēú√≠s. Fachada de la desaparecida residencia modernista de Pedro Marcola‚Ēú¬°n, en el paseo de Sagasta n‚Ē¨‚ēĎ 20 tripl. Proyectada por Jos‚Ēú¬ģ Graner Prat en 1903. Derribada poco despu‚Ēú¬ģs de esta captura fotogr‚Ēú√≠fica, su lugar lo ocupa hoy la mole de nueve alturas de los n‚Ēú‚ēĎmeros 32 al 38, previo piqueteo de este hotelito y sus inmediatos vecinos. Fuente visual: "La modernidad y la Exposici‚Ēú‚Ēān Hispano Francesa de Zaragoza en 1908", Universidad de Zaragoza, 2004.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64365200, -0.88622200, '0101000020E6100000DFDC5F3DEE5BECBFA400513063D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15535230465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15535230465.webp', 'https://www.flickr.com/photos/zaragozaantigua/15535230465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24907, 'P.‚Ē¨‚ēĎ del General Mola 1976', 'Aspecto parcial de la casa de Emerenciano Garc‚Ēú¬°a, ejemplo del modernismo zaragozano y obra de Manuel mart‚Ēú¬°nez de Ubago de 1909. Fue derribada en 1976. Al fondo, el n‚Ēú‚ēĎmero 56, mostrando el retranqueo de la casa fotografiada, que ocupaba el 54 del paseo del General Mola. Fuente: foto Gonzalo Borr‚Ēú√≠s, en Zaragoza a principios del s. XX: el modernismo. Librer‚Ēú¬°a General, 1977.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64136900, -0.88637300, '0101000020E610000049D6E1E82A5DECBF88D51F6118D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19406597966.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19406597966.webp', 'https://www.flickr.com/photos/zaragozaantigua/19406597966/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24999, 'Acequia de San Jos‚Ēú¬ģ 1925', 'Desde el Canal Imperial de Arag‚Ēú‚Ēān y a trav‚Ēú¬ģs del Parque de Buenavista, bajaba por gravedad la acequia de las Adulas, tambi‚Ēú¬ģn llamada de San Jos‚Ēú¬ģ por el antiguo y referencial convento, luego penal y finalmente cuartel. En este tramo flu‚Ēú¬°a al aire y en sinuoso paralelo al paseo de los Ruise‚Ēú‚Ėíores, y cruzaba (soterrada) el paseo de Sagasta para luego seguir su recorrido nuevamente al aire por el camino de las Torres tras surtir a la f‚Ēú√≠brica La Pilar de la Tudor. La imagen se habr‚Ēú¬°a capturado justo desde el principio del paseo de los Ruise‚Ēú‚Ėíores, junto al transformador el‚Ēú¬ģctrico sobre la acequia, en una despejada zona que en los a‚Ēú‚Ėíos treinta ser‚Ēú¬°a urbanizada como zona verde, eliminando el edificio de "Las tres BBB", y colocando isletas de jard‚Ēú¬°n y arbustos. Al fondo, construcciones de la antigua casa de Victoriano Zorraquino. A su lado, y sobre el cauce de la acequia, la pasarela que conectaba la calle de Sevilla con el paseo de Ruise‚Ēú‚Ėíores.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.63881900, -0.88638400, '0101000020E6100000435376FA415DECBF1E882CD2C4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14943152450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14943152450.webp', 'https://www.flickr.com/photos/zaragozaantigua/14943152450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25005, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1930', '"Vista de la subida de coches y estancia" del "Restaurant Ruise‚Ēú‚Ėíores" de Zaragoza, tarjeta postal editada por "Huecograbado Mumbr‚Ēú‚ēĎ S.C. Barcelona". En 1930, el arquitecto Marcelino Securun Orga dise‚Ēú‚Ėí‚Ēú‚Ēā el "Restaurante de verano de Francisco Gargallo", localizado al principio del paseo de Ruise‚Ēú‚Ėíores. En la imagen, empinado acceso rodado desde el paseo, que queda a la izquierda, donde se encontraba la entrada principal. Este lugar, al principio de los a‚Ēú‚Ėíos 30 del pasado siglo, quedaba bastante lejos de lo que entonces se consideraba ciudad. A la derecha, muros perimetrales de los extensos dep‚Ēú‚Ēāsitos de agua lindantes con la avenida de Wilson y los jardines de Pignatelli, el destino final del monumento al ilustrado pr‚Ēú‚Ēācer tras su destierro de la plaza de Arag‚Ēú‚Ēān. A la izquierda, fuera de plano, aunque inmediata, la galer‚Ēú¬°a y traseras de la "casa del Poeta", sufragada por la ciudad para el renombrado bardo Alberto Casa‚Ēú‚Ėíal Shakery, entonces en construcci‚Ēú‚Ēān. Este "restaurant", que inclu‚Ēú¬°a una concurrida pista de baile, y que era lugar de moda para comidas y cenas de posibles, a los pocos a‚Ēú‚Ėíos fue clausurado, y las construcciones de la imagen quedaron abandonadas y en ruinas, hasta que al comienzo de los a‚Ēú‚Ėíos 50 este entorno fue nuevamente edificado, ahora con viviendas. La dura cuesta de acceso ha sido cerrada con verja, pues forma parte del privado espacio edilicio al que se accede desde la actual calle de Santiago Guallar. Fuente visual: www.todocoleccion.net/', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.63690500, -0.88806700, '0101000020E6100000C504357C0B6BECBF56D4601A86D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24594386414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24594386414.webp', 'https://www.flickr.com/photos/zaragozaantigua/24594386414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25007, 'Escuelas de Torrero 1885', 'En el bienio 1884-85 fueron creadas en la ciudad varias escuelas p‚Ēú‚ēĎblicas, sobre todo en barrios rurales y zonas de la periferia entre las que se encontraba Torrero, denominaci‚Ēú‚Ēān que inclu‚Ēú¬°a unas cuantas terrazas por debajo del Canal Imperial, y buena parte del camino de Torrero, luego paseo de Sagasta. As‚Ēú¬°, en el paseo de Cu‚Ēú¬ģllar, entre los dep‚Ēú‚Ēāsitos de agua y el cauce al aire de la nueva acequia del Plano derivada del Canal, fue construido un edificio de 680 m2 con capacidad para unos 100 ni‚Ēú‚Ėíos, en materiales muy econ‚Ēú‚Ēāmicos: adobe y mamposter‚Ēú¬°a, y ladrillo en las zonas estructurales. La escuela se encontraba en la planta calle, y la planta superior se habilit‚Ēú‚Ēā para vivienda del maestro, plaza que fue ocupada por Marcelino L‚Ēú‚Ēāpez Ornat, posiblemente quien aparece en la fotograf‚Ēú¬°a, rodeado de la abundante tropilla colegial, en un grupal posado donde las traseras de la escuela. Fue la existencia de esta instalaci‚Ēú‚Ēān educativa la que determin‚Ēú‚Ēā que el nuevo vial luego abierto para conectar con el paseo de Ruise‚Ēú‚Ėíores fuera denominado, precisamente, calle de las Escuelas. M‚Ēú√≠s tarde ser‚Ēú¬°a redenominado Maestro Estremiana como homenaje a Pablo Estremiana, que trabaj‚Ēú‚Ēā aqu‚Ēú¬° de maestro en la segunda y tercera d‚Ēú¬ģcadas del siglo XX. Fuente visual: Foto Estudio Coyne, AHPZ.', 1885, 1885, 1885, 'Siglo XIX', 'UNIVERSIDAD', 41.63564600, -0.88552400, '0101000020E6100000DE567A6D3656ECBFA7EA1ED95CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30829414034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30829414034.webp', 'https://www.flickr.com/photos/zaragozaantigua/30829414034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25016, 'Casa Juncosa c.1909', 'Archivo y Hemeroteca Municipales de Zaragoza, entre 1906 y 1910. Vivienda modernista de Julio Juncosa en el paseo de Sagasta 11, proyectada por Jos‚Ēú¬ģ de Yarza en colaboraci‚Ēú‚Ēān con Ricardo Magdalena en 1903 y concluida en 1906. Sobrevive. Fuente visual: "Ricardo Magdalena. Arquitecto municipal de Zaragoza", IFC, 2012.', 1909, 1909, 1909, 'Anos 1900', 'UNIVERSIDAD', 41.64342300, -0.88583000, '0101000020E61000000D1AFA27B858ECBF423F53AF5BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14920526584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14920526584.webp', 'https://www.flickr.com/photos/zaragozaantigua/14920526584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25000, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1922', 'El burgu‚Ēú¬ģs ensanche de Sagasta ten‚Ēú¬°a un brazo que se extend‚Ēú¬°a por el paseo de Ruise‚Ēú‚Ėíores, con notables muestras de viviendas unifamiliares u hotelitos historicistas, modernistas, e incluso alguna rareza del racionalismo de vanguardia. En la imagen, ins‚Ēú‚Ēālita vista del n‚Ē¨‚ēĎ 24, nov‚Ēú¬°sima casa de Victoriano Carbon‚Ēú¬ģ como segunda residencia de este pr‚Ēú‚Ēācer local, presidente de la Uni‚Ēú‚Ēān Ultramarina de Dependientes de Zaragoza, y concejal. Fue proyectada por Francisco Albi‚Ēú‚Ėíana Corral‚Ēú¬ģ pocos a‚Ēú‚Ėíos antes. A la izquierda, puerta de ingreso al Colegio Pompiliano de las Madres Escolapias, en el n‚Ē¨‚ēĎ 26. A ambos lados del terroso paseo, peque‚Ēú‚Ėíos riegos para canalizar el agua, entubados en los accesos a las viviendas. Fuente visual: Archivo Fotogr‚Ēú√≠fico Julio Requejo, en AHPZ.', 1922, 1922, 1922, 'Anos 20', 'UNIVERSIDAD', 41.63649400, -0.88940900, '0101000020E6100000FB93F8DC0976ECBFD40CA9A278D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15129204712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15129204712.webp', 'https://www.flickr.com/photos/zaragozaantigua/15129204712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25017, 'P.‚Ē¨‚ēĎ del General Mola 1978', 'Este "hotelito" del Paseo de Sagasta fue construido en 1919 por Teodoro R‚Ēú¬°os para Luis L‚Ēú‚Ēāpez, en la parcela del n‚Ē¨‚ēĎ 24 dpdo. (luego n‚Ē¨‚ēĎ 52), justo al lado del impresionante hotelito de Emerenciano Garc‚Ēú¬°a (izquierda, fuera de plano). Las posteriores vicisitudes de este hotelito forman parte de la reciente historia de los movimientos sociales de la ciudad: abandonado desde 1950, en marzo de 1987 el edificio fue ocupado como "Casa de la Paz y la Solidaridad", sede del feminismo, antimilitarismo, ecologismo, anticapitalismo, antisistemismo, desde una perspectiva radical. En diciembre de 1993, tras seis intensos a‚Ēú‚Ėíos de activismo, con sus luces y sombras, miserias y grandezas, la casa fue desalojada. Luego fue derribada, y su propietario (el INSALUD), levant‚Ēú‚Ēā el actual Centro de Salud Jos‚Ēú¬ģ Ram‚Ēú‚Ēān Mu‚Ēú‚Ėíoz Fern‚Ēú√≠ndez. Su ecl‚Ēú¬ģctica arquitectura presentaba 540 m2 ‚Ēú‚ēĎtiles de vivienda, repartidos entre un semis‚Ēú‚Ēātano, dos plantas, y un ‚Ēú√≠tico, y mas de 150m2 de jard‚Ēú¬°n (incluyendo un gallinero). Hasta su derribo, fue el ‚Ēú‚ēĎltimo de los hotelitos del burgu‚Ēú¬ģs Paseo de Sagasta. Queda y perdura en la memoria de toda la gente que pas‚Ēú‚Ēā por ‚Ēú¬ģl. En la captura, imagen del n‚Ē¨‚ēĎ 52 del Paseo Sagasta, abandonado y aprisionado entre el moderno bloque del n‚Ē¨‚ēĎ 50, a la derecha (reci‚Ēú¬ģn inaugurado), y el bloque del n‚Ē¨‚ēĎ 54, a la izquierda y fuera de plano, tambi‚Ēú¬ģn de nueva factura. Fuente visual: "La evoluci‚Ēú‚Ēān urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1978, 1978, 1978, 'Anos 70', 'UNIVERSIDAD', 41.64169800, -0.88655000, '0101000020E6100000029A081B9E5EECBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14922703769.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14922703769.webp', 'https://www.flickr.com/photos/zaragozaantigua/14922703769/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25021, 'P.‚Ē¨‚ēĎ de Sagasta 1906', 'F‚Ēú√≠brica de hierro esmaltado Vi‚Ēú‚Ėíado y Burbano. 1906 Manuel Vi‚Ēú‚Ėíado mont‚Ēú‚Ēā en 1890, en la calle Cinco de Marzo n‚Ē¨‚ēĎ 4, una f‚Ēú√≠brica de r‚Ēú‚Ēātulos esmaltados. En 1902 se traslad‚Ēú‚Ēā, por ampliaci‚Ēú‚Ēān de negocio, al Paseo de Sagasta n‚Ē¨‚ēĎ 22 (duplicado), a una manzana delimitada por un breve frontal al Paseo de Sagasta, y dos largas fachadas, una al Camino de la Cadena (luego, Alar del Rey), y otra a la trinchera del ferrocarril MZA (mucho m‚Ēú√≠s tarde, Avenida de Goya). La nueva factor‚Ēú¬°a fue dise‚Ēú‚Ėíada por Julio Bravo, e inclu‚Ēú¬°a una vivienda, adem‚Ēú√≠s de la f‚Ēú√≠brica y almacenes. En 1925, con la denominaci‚Ēú‚Ēān "Vi‚Ēú‚Ėíado Hermanos", la f‚Ēú√≠brica fue desmantelada, y trasladada al camino del Terminillo. Ese a‚Ēú‚Ėío se abri‚Ēú‚Ēā en este lugar el Colegio de las Hermanas Carmelitas de la Caridad, hasta el 1949, en que se reubicaron en su actual sede de Madre Vedruna-Le‚Ēú‚Ēān XIII. Luego se instal‚Ēú‚Ēā luego la Academia preparatoria de acceso a la AGM "La Figuera", hasta 1971, en que se trasladan a Cant‚Ēú¬°n y Gamboa. La imagen se corresponde con un anuncio publicado en "Zaragoza, Gu‚Ēú¬°a del Viajero. A‚Ēú‚Ėío 1906", de Jos‚Ēú¬ģ Mar‚Ēú¬°a Casi. La fotograf‚Ēú¬°a est‚Ēú√≠ tomada desde el paseo de Sagasta.', 1906, 1906, 1906, 'Anos 1900', 'UNIVERSIDAD', 41.64264000, -0.88673500, '0101000020E610000072FE26142260ECBFFC8C0B0742D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15436979227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15436979227.webp', 'https://www.flickr.com/photos/zaragozaantigua/15436979227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25022, 'Verkos 1940', 'Imagen de los Laboratorios Verkos, instalados desde 1938 en este edificio en la calle Gil de Jasa n‚Ē¨‚ēĎ 16, esquina con calle Cervantes, donde la Farmacia de los Laboratorios ten‚Ēú¬°a su entrada propia en el n‚Ē¨‚ēĎ 3 de esa calle. En 1976 abandonaron estas instalaciones, y se trasladaron a su actual ubicaci‚Ēú‚Ēān, en la carretera de Logro‚Ēú‚Ėío, km. 20, al lado de Pinseque. En 1979 la piqueta derrib‚Ēú‚Ēā el inmueble, y en su solar se levantaron las actuales viviendas. Una moderna farmacia fue habilitada donde estuviera la antigua. Fuente visual: Foto Gabriel Casas i Galobardes para Laboratorios Verkos, en Arxiu Nacional de Catalunya.', 1940, 1940, 1940, 'Anos 40', 'UNIVERSIDAD', 41.64395000, -0.88680200, '0101000020E610000065E08096AE60ECBF2D211FF46CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15509220684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15509220684.webp', 'https://www.flickr.com/photos/zaragozaantigua/15509220684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25025, 'Casa sin Duende 1976', 'El inmueble esquinero entre Gasc‚Ēú‚Ēān de Gotor y Juan Pablo Bonet desde los a‚Ēú‚Ėíos 30 del pasado siglo era denominado "La Casa del Duende", por un episodio de moderada histeria colectiva basado en el enga‚Ēú‚Ėío, la superstici‚Ēú‚Ēān y el sensacionalismo de los medios de comunicaci‚Ēú‚Ēān de masas. Por la fuerza de la costumbre, que es nuestra gu‚Ēú¬°a y lumbre, el edificio de nueva planta que lo ha sustituido es denominado "Edificio Duende", para que la realidad no acabe distorsionando las improbables fantas‚Ēú¬°as. En la imagen, los andamios se‚Ēú‚Ėíalan el inminente derribo. En los bajos, pintadas con algunas de las reivindicaciones del momento: libertad de los presos pol‚Ēú¬°ticos, no a los yanquis, no a las bases. A la izquierda, los controvertidos laboratorios ULTA y su fachada a la calle Gasc‚Ēú‚Ēān de Gotor. Fuente visual: Gerardo Sancho Ramo en AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63985000, -0.88714900, '0101000020E610000038BBB54C8663ECBF3D2CD49AE6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19709494442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19709494442.webp', 'https://www.flickr.com/photos/zaragozaantigua/19709494442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25026, 'Av. de la Rep‚Ēú‚ēĎblica 1935', 'Imagen en altura del solar previsto para la construcci‚Ēú‚Ēān de la "Casa Social", o edificio de servicios varios de la Confederaci‚Ēú‚Ēān Hidrogr‚Ēú√≠fica del Ebro en la avenida de la Rep‚Ēú‚ēĎblica. Dentro del solar, dos casas que luego ser‚Ēú¬°an derribadas. A la izquierda, vista parcial de la "Casa del Ebro" o casa-oficina central de la Confederaci‚Ēú‚Ēān Sindical Hidrogr‚Ēú√≠fica del Ebro (CSHE) construida a finales de los a‚Ēú‚Ėíos veinte con proyecto del arquitecto Pascual Bravo Sanfeliu. Entre este edificio y el solar de la imagen, vista de la nueva calle de servicio abierta entre el paseo de Sagasta y la calle Gil de Jasa desde la que se acced‚Ēú¬°a a la casa-oficina de la entidad hidrogr‚Ēú√≠fica. Tras el solar, la calle Gil de Jasa, y al fondo, ins‚Ēú‚Ēālita visi‚Ēú‚Ēān directa del edificio de las Cl‚Ēú¬°nicas Universitarias, y de la Facultad de Medicina. A la derecha, la calle Mariano Lagasca, con la cl‚Ēú¬°nica del Doctor Lozano. El inicio de las obras de este nuevo edificio, con proyecto de los hermanos Borobio, estaba previsto desde 1934, aunque no comenzaron hasta finales de 1936, para terminarse una d‚Ēú¬ģcada despu‚Ēú¬ģs (diciembre de 1946). Fuente visual: foto Mar‚Ēú¬°n Chivite, en "La Cr‚Ēú‚Ēānica" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64452000, -0.88630900, '0101000020E61000009AD024B1A45CECBF18CFA0A17FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21884362772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21884362772.webp', 'https://www.flickr.com/photos/zaragozaantigua/21884362772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25194, 'Ciudad Universitaria 1935', 'Planta de emplazamiento de la Facultad de Filosof‚Ēú¬°a y Letras en la Ciudad Universitaria. Regino Borobio y Jos‚Ēú¬ģ Beltr‚Ēú√≠n, Zaragoza, 1935. Plano del proyecto de Ciudad Universitaria en el que se remarca el lugar donde ser‚Ēú√≠ levantada la Facultad de Filosof‚Ēú¬°a y Letras en 1940. La iniciativa de construir un campus junto a la plaza de Espa‚Ēú‚Ėía (hoy San Francisco) proviene de 1933. El recinto fue de uso militar entre 1936 y 1939. La Facultad de Derecho se levant‚Ēú‚Ēā en 1945 y la de Ciencias en 1950. Fuente: www.facebook.com/photo.php?fbid=1496903440626884&set=...', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64187100, -0.89815500, '0101000020E6100000E8A4F78DAFBDECBF1BA034D428D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21973612358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21973612358.webp', 'https://www.flickr.com/photos/zaragozaantigua/21973612358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25027, 'P.‚Ē¨‚ēĎ del General Mola 1976', 'Aspecto del ascendente paseo del General Mola en donde finaliza, desde la izquierda, el camino de las Torres, y desde donde arranca Juan Pablo Bonet, hacia la derecha. Salvo algunos peque‚Ēú‚Ėíos detalles, su imagen es el resultado de la mutaci‚Ēú‚Ēān que este paseo hab‚Ēú¬°a padecido en la segunda mitad del siglo. A la izquierda, ‚Ēú‚ēĎltimos momentos del hotelito dise‚Ēú‚Ėíado por Pascual Bravo en el antiguo n‚Ē¨‚ēĎ 33. A la derecha, continuaban las obras en el controversial bloque de Colmenero, uno de los varios pufos de este destacado emprendedor. La conversi‚Ēú‚Ēān del andador central del paseo en aparcamiento gratis para privados veh‚Ēú¬°culos a motor de explosi‚Ēú‚Ēān, resultado del colapso de un sistema que inund‚Ēú‚Ēā con decenas de miles de estas unidades una trama viaria que nunca podr‚Ēú¬°a absorber en superficie el problema de la geom‚Ēú¬ģtrica explosi‚Ēú‚Ēān y ocupaci‚Ēú‚Ēān del espacio p‚Ēú‚ēĎblico que el desarrollismo, el mercado, y los intereses privados, hab‚Ēú¬°an creado. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23714237259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23714237259.webp', 'https://www.flickr.com/photos/zaragozaantigua/23714237259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25030, 'Juan Pablo Bonet 1977', 'Imagen con la fachada de los Laboratorios ULTA decorada con pintadas alusivas a las movilizaciones protagonizadas por sus trabajadores en la primavera de ese a‚Ēú‚Ėío. Una de ellas dice "Toda la plantilla de ULTA despedida por el capricho de un hombre (Fernando Cuenca Villoro, propietario) que cree puede jugar con 110 familias". Otra pintada, del PCE, reivindicaba la abstenci‚Ēú‚Ēān en el refer‚Ēú¬ģndum sobre el Proyecto de Ley para la Reforma Pol‚Ēú¬°tica celebrado el 15 de diciembre del a‚Ēú‚Ėío anterior, donde se ped‚Ēú¬°a ratificar la Ley para la Reforma Pol‚Ēú¬°tica (incluyendo la de las Cortes), que ya hab‚Ēú¬°a sido aprobada previamente en las Cortes franquistas. Esta fue la traducci‚Ēú‚Ēān efectiva del archipublicitado y mel‚Ēú‚Ēādico "jingle" (sonsonete) del "Habla, pueblo, habla". Aparcado en la calzada, un R-6. Fuente visual: Archivo Hist‚Ēú‚Ēārico CCOO Arag‚Ēú‚Ēān-AHCCOOAR.FFT.1977/001.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63997500, -0.88735100, '0101000020E61000002A55A2EC2D65ECBFF9A067B3EAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30904961722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30904961722.webp', 'https://www.flickr.com/photos/zaragozaantigua/30904961722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25040, 'Calle de Cervantes 1940', '"Farm‚Ēú√°cia de l''empresa farmac‚Ēú¬Ņutica Laboratorios Verkos". Imagen capturada en el interior de la farmacia que Laboratorios Verkos hab‚Ēú¬°a habilitado en los bajos del nov‚Ēú¬°simo edificio proyectado por el arquitecto Teodoro R‚Ēú¬°os Balaguer en moderno estilo racionalista como sede de estos laboratorios farmac‚Ēú¬ģuticos. Mientras que el ingreso a los laboratorios se realizaba desde la calle de Gil de Jasa, el de este despacho de farmacia estaba en la calle de Cervantes (al fondo de la imagen). As‚Ēú¬° fue hasta mediados de la d‚Ēú¬ģcada de los a‚Ēú‚Ėíos setenta. De vecino inmediato ten‚Ēú¬°a al Colegio Alem‚Ēú√≠n y la Jefatura Provincial del "Ortsgruppe" (Grupo Local) del NSDAP (por las siglas en alem‚Ēú√≠n del Partido Nacionalsocialista Obrero Alem‚Ēú√≠n) en Zaragoza. Fuente visual: foto Gabriel Casas i Galobardes para Laboratorios Verkos, en Arxiu Nacional de Catalunya.', 1940, 1940, 1940, 'Anos 40', 'UNIVERSIDAD', 41.64395000, -0.88680200, '0101000020E610000065E08096AE60ECBF2D211FF46CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42337836452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42337836452.webp', 'https://www.flickr.com/photos/zaragozaantigua/42337836452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25050, 'P.‚Ē¨‚ēĎ de Sagasta 1907', 'Imagen de la casa del n‚Ē¨‚ēĎ 20 duplicado del paseo de Sagasta capturada desde la zona central del paseo, por la que todav‚Ēú¬°a circulaban los coches de la l‚Ēú¬°nea Torrero del tranv‚Ēú¬°a. Esta era la imponente vivienda dise‚Ēú‚Ėíada en 1903 por el arquitecto Luis de la Figuera y Lezcano para Nicol‚Ēú√≠s Escoriaza y Fabro, patriarca de esta poderosa y referencial familia local. Adem‚Ēú√≠s, aqu‚Ēú¬° estuvo temporalmente radicado el consulado de B‚Ēú¬ģlgica. En el centro de la imagen y en la terraza del primer piso posa la familia de Nicol‚Ēú√≠s Escoriaza. A la derecha queda el ingreso a la calle de Miguel de Cervantes. Este inmueble fue derribado en la segunda mitad de los convulsos a‚Ēú‚Ėíos setenta del pasado siglo, y junto con los solares de las siguientes propiedades sirvi‚Ēú‚Ēā de base sobre la que finalmente fue construida una tremenda mole moderna de nueve alturas que desde entonces impera en el lugar.', 1907, 1907, 1907, 'Anos 1900', 'UNIVERSIDAD', 41.64385400, -0.88626600, '0101000020E6100000C8D0B1834A5CECBF0BB3D0CE69D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51803780153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51803780153.webp', 'https://www.flickr.com/photos/zaragozaantigua/51803780153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25051, 'Calle la Paz 1935', 'El 8 de junio de 1934, el doctor Roncal‚Ēú¬ģs pidi‚Ēú‚Ēā autorizaci‚Ēú‚Ēān al Ayuntamiento para la reforma de su cl‚Ēú¬°nica, sita en la calle de la Paz n‚Ēú‚ēĎmero 5. El proyecto, firmado por Teodoro R‚Ēú¬°os, result‚Ēú‚Ēā ser de nueva construcci‚Ēú‚Ēān. El establecimiento resultante fue denominado Cl‚Ēú¬°nica de San Ignacio, y fueron sus due‚Ēú‚Ėíos los doctores Roncal‚Ēú¬ģs, Val-Carreres Gotor y Julio Ari‚Ēú‚Ėío. La cl‚Ēú¬°nica contaba con dos pisos, en los que hab‚Ēú¬°a 20 habitaciones de las que faltaba el n‚Ēú‚ēĎmero 13, debido a la presencia habitual all‚Ēú¬° de profesionales taurinos. Las enfermeras eran hermanas de Santa Ana. La cl‚Ēú¬°nica se cerr‚Ēú‚Ēā en 1989 y el edificio fue derribado.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64263100, -0.88532200, '0101000020E6100000EDBC8DCD8E54ECBFA9328CBB41D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51982322459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51982322459.webp', 'https://www.flickr.com/photos/zaragozaantigua/51982322459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25053, 'P.‚Ē¨‚ēĎ del General Mola 1977', 'Imagen capturada en el paseo del General Mola cuando por ‚Ēú¬ģl transitaba el cortejo organizado por la Asociaci‚Ēú‚Ēān de Vecinos de Venecia que escenificaba el ‚Ē¨¬Ĺentierro‚Ē¨‚ēó de las hasta entonces "fiestas carcas, oficiales, religiosas√Ē√á¬™etc.", que desde este sure‚Ēú‚Ėío barrio llegar‚Ēú¬°a hasta la Lonja, tradicional edificio donde las tradicionalistas autoridades y "gente de orden" celebraban sus particulares fiestas del Pilar, mientras que al pueblo com‚Ēú‚ēĎn se le dejaba la tarea de aplaudir y vitorear... pero desde fuera del recinto. En la imagen, la comitiva camina por el bulevar central del paseo a la altura, a la derecha, del mastod‚Ēú‚Ēāntico nuevo gran inmueble en construcci‚Ēú‚Ēān de los n‚Ēú‚ēĎmeros 32-38 del paseo, resultado de la destrucci‚Ēú‚Ēān previa de todos los "hotelitos" que all‚Ēú¬° se encontraban desde principios de siglo. Abre la marcha un carrito de beb‚Ēú¬ģ con un cartel que reza "Nucleares, no", mientras tras ‚Ēú¬ģl varias personas portan el ataud que representaba a las viejas fiestas, repleto para la ocasi‚Ēú‚Ēān de bebidas espirituosas con que "aguantar con buen humor el largo funeral". Ese a‚Ēú‚Ėío fue ‚Ēú¬ģl ‚Ēú‚ēĎltimo en que la "Zaragoza de bien" organiz‚Ēú‚Ēā el espect‚Ēú√≠culo de la "Reina de las Fiestas" celebrado en la Lonja, que en esta postrera edici‚Ēú‚Ēān recay‚Ēú‚Ēā (como era tradicional, de forma digital) en Mar‚Ēú¬°a Cristina Ruiz Santos.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.64350100, -0.88613700, '0101000020E610000052D158FB3B5BECBFBEF8A23D5ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54845967602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54845967602.webp', 'https://www.flickr.com/photos/zaragozaantigua/54845967602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25100, 'Casa de la Paz 1992', 'Imagen capturada en las traseras de la "Casa de la Paz" habilitada en el abandonado hotelito del n‚Ē¨‚ēĎ 52 del paseo de Sagasta como semillero de insumisos al Servicio Militar Obligatorio. Al fondo, la medianera del "Edificio Rosales" en el n‚Ē¨‚ēĎ 50 del paseo, inmueble donde estaba radicada la emisora de radio controlada por la Conferencia Episcopal Espa‚Ēú‚Ėíola. Una pintada alusiva al preso ejeano Antonio Oriol pone en antecedentes el posado, en primer t‚Ēú¬ģrmino, de una irrepetible galer‚Ēú¬°a de insumisos representativa de la notable diversidad pol‚Ēú¬°tica de la ‚Ēú¬ģpoca que caracterizaba este amplio movimiento social, uno de los m‚Ēú√≠s importantes en el principio de la d‚Ēú¬ģcada.', 1992, 1992, 1992, 'Anos 90', 'UNIVERSIDAD', 41.64183400, -0.88693100, '0101000020E6100000DBDFD91EBD61ECBFFEBAD39D27D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50201821227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50201821227.webp', 'https://www.flickr.com/photos/zaragozaantigua/50201821227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25430, 'P.‚Ē¨‚ēĎ de Sagasta 1911', 'Vista del puente sobre la zanja del ferrocarril de la compa‚Ēú‚Ėí‚Ēú¬°a MZA, en el punto de cruce entre el paseo de Sagasta ( por arriba, de derecha a izquierda), y la trinchera, abajo, de la v‚Ēú¬°a del ferrocarril de los directos Madrid-Barcelona. Esta v‚Ēú¬°a viene desde el fondo, donde est‚Ēú√≠ la estaci‚Ēú‚Ēān de Campo Sepulcro, y va en direcci‚Ēú‚Ēān a la estaci‚Ēú‚Ēān de Miraflores. Fuente visual: hemerotecadigital.bne.es/', 1911, 1911, 1911, 'Anos 10', 'UNIVERSIDAD', 41.64222500, -0.88608400, '0101000020E61000009D4830D5CC5AECBF39D6C56D34D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20972383200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20972383200.webp', 'https://www.flickr.com/photos/zaragozaantigua/20972383200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25593, 'Dep‚Ēú‚Ēāsitos de Pignatelli 1965', 'M‚Ēú√Īs que interesante vista en altura centrada en los veteranos dep‚Ēú‚Ēāsitos de Pignatelli, junto al hom‚Ēú‚Ēānimo parque. En primer t‚Ēú¬ģrmino, el paseo de Cu‚Ēú¬ģllar y la v‚Ēú¬°a de San Fernando, que confronta las escuelas de la Milagrosa con el cuartel de Castillejos. La calle del Maestro Estremiana, hacia la izquierda, conduce al paseo de Ruise‚Ēú‚Ėíores, tras el que destaca el moderno Grupo Salduba. En la margen izquierda del r‚Ēú¬°o Huerva, despejado entorno ante el Hogar Sierra de Alcubierre, y vista parcial a la derecha de la antigua f‚Ēú√≠brica textil de C‚Ēú√≠ndido Castillo. Las instalaciones de la Editorial Luis Vives S.A., junto a la calle hom‚Ēú‚Ēānima, dan paso a las ordenadas Casas Baratas de Miralbueno y la gran estructura del colegio de La Salle. Finalmente y al fondo, el paseo de Fernando el Cat‚Ēú‚Ēālico y la plaza de San Francisco.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63621300, -0.88713500, '0101000020E6100000FA6184F06863ECBF2025766D6FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50359769397.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50359769397.webp', 'https://www.flickr.com/photos/zaragozaantigua/50359769397/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25737, 'Camino de las Torres 1951', 'Desde Juan Pablo Bonet, imagen del ‚Ēú‚ēĎltimo tramo del camino de las Torres, al fondo, y del cruce del paseo del General Mola. A la derecha, la manzana que ocupaba la TUDOR, expectante de nuevas edificaciones residenciales. A la izquierda, Casa Faci. Hay un carro, a la derecha, maniobrando temerariamente, y peatones cruzando por doquiera, pero a nadie parece importarle: a‚Ēú‚ēĎn no ha llegado la Era de los Autom‚Ēú‚Ēāviles. Fuente visual: Archivo P‚Ēú‚ēĎblico Municipal, Archivo Mora.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20313336656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20313336656.webp', 'https://www.flickr.com/photos/zaragozaantigua/20313336656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25738, 'Calle del Tenor Fleta 1951', '"Calle de Tenor Fleta. Entrada: General Mola (hoy P‚Ē¨‚ēĎ Sagasta) 23. Salida: Avenida S. Jos‚Ēú¬ģ 138." Los muretes del centro indican la trinchera del ferrocarril sin cubrir. Al fondo, a la izquierda, la Capilla-Rotonda de los PP. Agustinos y su Muro perimetral. Imagen capturada desde el Paseo de Mola. Fuente visual: Archivo P‚Ēú‚ēĎblico Municipal, Archivo Mora.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64209800, -0.88595500, '0101000020E61000002849D74CBE59ECBFDB696B4430D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20319195055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20319195055.webp', 'https://www.flickr.com/photos/zaragozaantigua/20319195055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25963, 'Casa de la Paz 1994', 'El 23 de diciembre de 1993 fue desalojada la Casa de la Paz, en el paseo de Sagasta 52. El edificio, de arquitectura ecl‚Ēú¬ģctica, construido en 1919 y abandonado en 1961, hab‚Ēú¬°a sido ocupado en 1987. En la imagen, de principios de 1994, miembros del colectivo de okupas de Zaragoza pintan el lema √Ē√á¬£Venceremos√Ē√á√ė sobre la tapia recientemente levantada ante la casa, posteriormente derribada.', 1994, 1994, 1994, 'Anos 90', 'UNIVERSIDAD', 41.64182000, -0.88638300, '0101000020E61000002D5F97E13F5DECBF99F5622827D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52491652137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52491652137.webp', 'https://www.flickr.com/photos/zaragozaantigua/52491652137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26014, 'Vista a‚Ēú¬ģrea Moncasi c.1990', 'Foto: Archivo Taumar (Irene Taul‚Ēú¬ģs y Rafael Margal‚Ēú¬ģ). Vista a‚Ēú¬ģrea del entorno comprendido entre el r‚Ēú¬°o Huerva (izquierda) y el paseo de Sagasta (derecha), unidos por la calle Moncasi (centro). Arriba, avenida de Goya. Abajo, calle Juan Pablo Bonet. Fuente: www.facebook.com/photo.php?fbid=1687671021456597&set=...', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.64174400, -0.88806900, '0101000020E6100000F2ECF2AD0F6BECBFBE33DAAA24D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22407906425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22407906425.webp', 'https://www.flickr.com/photos/zaragozaantigua/22407906425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21156, 'Talleres Carde y Escoriaza 1897', 'Vista exterior de los talleres de Carpinter‚Ēú¬°a Mec‚Ēú√≠nica Carde y Escoriaza, capturada desde la Subida de Cu‚Ēú¬ģllar con el arranque del camino de las Alcachoferas a la izquierda. Fruto de la asociaci‚Ēú‚Ēān del empresario franc‚Ēú¬ģs Guillermo Carde (de la firma Carde de Burdeos) con el zaragozano Nicol‚Ēú√≠s de Escoriaza (Talleres Escoriaza, fabricantes de carruajes para mercanc‚Ēú¬°as y viajeros) se constituye esta empresa en 1897 que comenz‚Ēú‚Ēā a construir veh‚Ēú¬°culos para el ferrocarril, y que pronto se especializar‚Ēú√≠ en material m‚Ēú‚Ēāvil como coches de tranv‚Ēú¬°as y trenes. Fuente visual: M‚Ē¨¬¨ Pilar Biel Ib‚Ēú√≠‚Ēú‚Ėíez, Zaragoza y la industrializaci‚Ēú‚Ēān: la arquitectura industrial 1875-1936, IFC, 2004.', 1897, 1897, 1897, 'Siglo XIX', 'UNIVERSIDAD', 41.63990000, -0.88619200, '0101000020E610000035423F53AF5BECBFEE5A423EE8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19190830373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19190830373.webp', 'https://www.flickr.com/photos/zaragozaantigua/19190830373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21229, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1905', 'En 1903 se parcel‚Ēú‚Ēā el "barrio de Ruise‚Ēú‚Ėíores" en torno a la calle as‚Ēú¬° denominada, a iniciativa del industrial Santiago Canti Polo, que emprendi‚Ēú‚Ēā la construcci‚Ēú‚Ēān de un grupo de hotelitos o viviendas unifamiliares en un terreno de su propiedad, siendo todas ellas proyectadas por el ingeniero Manuel Isasi Isasmendi. Estas viviendas eran consideradas "de recreo" por la burgues‚Ēú¬°a local, con la ventaja de que se hallaban "en las inmediaciones de Zaragoza". En la imagen promocional, los seis hotelitos referidos: por ejemplo, en la parte inferior, a la derecha, el denominado "Villa alta", que fue derribada en 1994. A su izquierda, el denominado "Villa Rosita", adquirido por Raimundo Balet y luego objeto de varias reformas, como la de 1919 con proyecto de Miguel ‚Ēú√ľngel Navarro P‚Ēú¬ģrez. Fuente visual: M‚Ē¨¬¨ Pilar Biel Ib‚Ēú√≠‚Ēú‚Ėíez, Zaragoza y la industrializaci‚Ēú‚Ēān: la arquitectura industrial 1875-1926, IFC, 2004.', 1905, 1905, 1905, 'Anos 1900', 'UNIVERSIDAD', 41.63680600, -0.88906600, '0101000020E610000083893F8A3A73ECBFC3F2E7DB82D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19017767854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19017767854.webp', 'https://www.flickr.com/photos/zaragozaantigua/19017767854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21507, 'Casa de Manuel Hern‚Ēú√≠ndez 1923', 'Imagen capturada por Juan Mora Insa del proyecto dise‚Ēú‚Ėíado por Regino Borobio para la casa de Manuel Hern‚Ēú√≠ndez en el Paseo de Ruise‚Ēú‚Ėíores n‚Ē¨‚ēĎ 22, esquina con un callej‚Ēú‚Ēān sin nombre que en 1949 recibir‚Ēú√≠ el de "Fernando de Antequera". Se trataba de un edificio unifamiliar con planta s‚Ēú‚Ēātano, baja y principal con aires modernistas y art d‚Ēú¬ģco, y la pl‚Ēú√≠stica de un espacio que se ofrece a una visual estrat‚Ēú¬ģgica entre dos calles. Estuvo en pie hasta que fue piqueteada en 1981, y sobre el solar (al que se sum‚Ēú‚Ēā el vecino n‚Ē¨‚ēĎ 24) se levant‚Ēú‚Ēā la actual construcci‚Ēú‚Ēān. En la imagen, la casa capturada desde el Paseo de Ruise‚Ēú‚Ėíores. A la derecha, el murete delimita el callej‚Ēú‚Ēān sin nombre. A la izquierda, el enorme jard‚Ēú¬°n trasero que, en bajada, llegaba hasta el camino tambi‚Ēú¬ģn arbolado por el que flu‚Ēú¬°a al aire la acequia de San Jos‚Ēú¬ģ (futura calle Doctor Alcay). Justo detr‚Ēú√≠s de la casa, cruzando el callej‚Ēú‚Ēān, se construir‚Ēú√≠ la Casa de Pedro Hern‚Ēú√≠ndez Luna (n‚Ē¨‚ēĎ 20 del paseo), obra de Regino y de Jos‚Ēú¬ģ Borobio dise‚Ēú‚Ėíada en 1931. Fuente visual: "Una mirada a trav‚Ēú¬ģs de la arquitectura: Regino y Jos‚Ēú¬ģ Borobio Ojeda", Daniel Estab‚Ēú¬ģn Boldova.', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.63680600, -0.88906600, '0101000020E610000083893F8A3A73ECBFC3F2E7DB82D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15607224169.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15607224169.webp', 'https://www.flickr.com/photos/zaragozaantigua/15607224169/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21520, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1923', 'Imagen capturada por Juan Mora Insa del proyecto de Regino Borobio para la casa de Manuel Hern‚Ēú√≠ndez en el Paseo de Ruise‚Ēú‚Ėíores n‚Ē¨‚ēĎ 22. A la derecha, esquina con un callej‚Ēú‚Ēān sin nombre que en 1949 recibir‚Ēú√≠ el de "Fernando de Antequera". A la izquierda, el paseo de Ruise‚Ēú‚Ėíores. Al fondo a la derecha, la nada edificatoria m‚Ēú√≠s absoluta hasta el camino del S‚Ēú√≠bado y la acequia que por ‚Ēú¬ģl flu‚Ēú¬°a. Esta vivienda estuvo en pie hasta que fue piqueteada en 1981, y sobre el solar (al que se adicion‚Ēú‚Ēā el vecino n‚Ē¨‚ēĎ 24, visible justo detr‚Ēú√≠s) se levant‚Ēú‚Ēā eso que hoy puede verse. Fuente visual: "Una mirada a trav‚Ēú¬ģs de la arquitectura: Regino y Jos‚Ēú¬ģ Borobio Ojeda", Daniel Estab‚Ēú¬ģn Boldova.', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.63680600, -0.88906600, '0101000020E610000083893F8A3A73ECBFC3F2E7DB82D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16518016194.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16518016194.webp', 'https://www.flickr.com/photos/zaragozaantigua/16518016194/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21548, 'Tudor c.1920', 'Dibujo de la f‚Ēú√≠brica de Acumuladores Tudor "La Pilar" en sus instalaciones en "Torrero" (cuando "Torrero" era considerado a partir de la actual Avenida de Goya), desde 1898 a 1945. Construida sobre la antigua harinera de Almech, la manzana del cruce del Camino de las Torres (en la parte inferior, hacia la izquierda) con la Avenida Siglo XX (que sube por la derecha hacia Torrero, con los ra‚Ēú¬°les del tranv‚Ēú¬°a). En la parte superior, a la derecha, el Parque Pignatelli, y la c‚Ēú‚ēĎpula de la iglesia de S. Fernando. La fila de ‚Ēú√≠rboles inmediatamente superior a la f‚Ēú√≠brica se‚Ēú‚Ėíala la actual calle Jos‚Ēú¬ģ Pellicer. Centrado en la parte superior, el barrio de los "Chiflaos" en torno a Pradilla, y la gran torre del final de Vista Alegre. El agua de la f‚Ēú√≠brica era de la acequia de San Jos‚Ēú¬ģ que por Ruise‚Ēú‚Ėíores ven‚Ēú¬°a del Canal . En 1935 la f‚Ēú√≠brica sufri‚Ēú‚Ēā un incendio importante, pero su utilizaci‚Ēú‚Ēān como industria de guerra entre 1936-39 prolong‚Ēú‚Ēā la permanencia en esta zona. Despu‚Ēú¬ģs, una nueva ubicaci‚Ēú‚Ēān, en terrenos junto a la carretera de Navarra, ser‚Ēú√≠ realidad partir de 1946. Fuente visual: AVV. San Jos‚Ēú¬ģ.', 1920, 1920, 1920, 'Anos 20', 'UNIVERSIDAD', 41.63974900, -0.88586900, '0101000020E61000008449F1F10959ECBF0953944BE3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20315103065.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20315103065.webp', 'https://www.flickr.com/photos/zaragozaantigua/20315103065/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21552, 'Vista de Zaragoza c.1920', 'Vista desde el paseo de Sagasta, esquina con el Camino de las Torres. A la derecha, edificios de la f‚Ēú√≠brica de acumuladores de la Tudor. Las torres de la izquierda corresponden a la yeser‚Ēú¬°a de Manuel Gracia, derribada en 1924 para construir Casa Faci. Al fondo, el Pilar, la Seo y otras torres de la ciudad. Fuente visual: Foto Gabriel Faci, DARA/AHPZ', 1920, 1920, 1920, 'Anos 20', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20952293484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20952293484.webp', 'https://www.flickr.com/photos/zaragozaantigua/20952293484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21624, 'P.‚Ē¨‚ēĎ de Sagasta 1927', 'El zaragozano Lorenzo Grad‚Ēú¬ģ (segundo por la izquierda) posa tras su prototipo de autom‚Ēú‚Ēāvil, aparcado frente al concesionario de la marca de veh‚Ēú¬°culos Oakland y Chevrolet (ambas de General Motors), regentado por Jos‚Ēú¬ģ Mar‚Ēú¬°a Orobitg en el n‚Ē¨‚ēĎ 35 del paseo de Sagasta, donde la casa de Baselga (actual n‚Ē¨‚ēĎ 43). Fuente: Colecci‚Ēú‚Ēān particular.', 1927, 1927, 1927, 'Anos 20', 'UNIVERSIDAD', 41.64059300, -0.88618900, '0101000020E6100000F165A208A95BECBFF58590F3FED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35830718064.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35830718064.webp', 'https://www.flickr.com/photos/zaragozaantigua/35830718064/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21718, 'Av. de la Rep‚Ēú‚ēĎblica 1934', 'Imagen de un "convoy" tranviario de la L‚Ēú¬°nea 5 camino del campo de Torrero, a presenciar un emocionante partido del "Zaragoza F.C.", entidad resultante de la absorci‚Ēú‚Ēān en 1932 del "Zaragoza C.D." por parte del "Iberia S.C." Los aficionados, entre ellos unos cuantos infantes equilibristas, se aferran como pueden a una atestada jardinera tirada por una unidad de la Serie 50. Hace fresco, pero con sol eso en Zaragoza no importa, por muy invierno que sea, y m‚Ēú√≠s si eres fan‚Ēú√≠tico del "sport". El convoy est‚Ēú√≠ subiendo por la Avenida de la Rep‚Ēú‚ēĎblica, a punto de acceder a la Avenida del Siglo XX para llegar, pasado el Canal Imperial, a su destino en la Avenida de Am‚Ēú¬ģrica, cerca del campo de "football". Hace poco que esta l‚Ēú¬°nea ya no pasa por el interior del Parque Pignatelli, como originalmente hac‚Ēú¬°a, pues a los usuarios les parec‚Ēú¬°a que estaba muy a desmano... En esta imagen, a la derecha hay visual, por encima del tranv‚Ēú¬°a, del chafl‚Ēú√≠n de la tardomodernista "Casa del escultor Palao", de Miguel ‚Ēú√ľngel Navarro. Al otro lado de la Avenida, a la izquierda, un pedazo de "La Pilar", la f‚Ēú√≠brica de la Sociedad Espa‚Ēú‚Ėíola del Acumulador Tudor que ah‚Ēú¬° estaba desde 1898. El tranv‚Ēú¬°a lleva una anuncio comercial de la "F‚Ēú√≠brica y Almac‚Ēú¬ģn de Muebles Aguerri", que fuera antes de Agust‚Ēú¬°n Nuviala, en el Camino de San Jos‚Ēú¬ģ n‚Ē¨‚ēĎ 110. Fuente visual: Luis Mompel Castelar, Archivo Heraldo de Arag‚Ēú‚Ēān.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19759112250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19759112250.webp', 'https://www.flickr.com/photos/zaragozaantigua/19759112250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21719, 'Incendio Tudor 1935', '"La Pilar" era la recia denominaci‚Ēú‚Ēān de la f‚Ēú√≠brica de la Sociedad Espa‚Ēú‚Ėíola del Acumulador Tudor que desde 1898 estaba ubicada entre el Camino de las Torres y el de las Alcachoferas. En octubre de ese a‚Ēú‚Ėío un enorme incendio arruin‚Ēú‚Ēā los ingenios fabriles, a pesar del af‚Ēú√≠n de los obreros que colaboraron en la extinci‚Ēú‚Ēān del fuego. La foto est‚Ēú√≠ capturada desde el arranque de la avenida del Siglo XX. Los ‚Ēú√≠rboles del fondo indican el acceso al serpenteante camino de las Alcachoferas. Sobre el firme, ra‚Ēú¬°les en bajada de la tranviaria l‚Ēú¬°nea de Torrero hacia la plaza de la Constituci‚Ēú‚Ēān. Fuente visual: foto Miguel Mar‚Ēú¬°n Chivite, para Heraldo de Arag‚Ēú‚Ēān. AVV. San Jos‚Ēú¬ģ.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63951700, -0.88595500, '0101000020E61000002849D74CBE59ECBF361E6CB1DBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19776980524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19776980524.webp', 'https://www.flickr.com/photos/zaragozaantigua/19776980524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21742, 'Carmelitas Descalzos 1935', 'En 1929 se puso la primera piedra del nuevo Convento e Iglesia de los Carmelitas Descalzos de la ciudad, en un solar de 2133 m2 junto a la proyectada plaza de Espa‚Ēú‚Ėía y el camino de Los Cubos, en el ensanche de Miralbueno. El proyecto llevaba la firma de Secundino Zuazo, y una elevada torre destacaba de la nueva construcci‚Ēú‚Ēān, pensada para una comunidad de 40 frailes. La enormidad del proyecto contaba con el benepl‚Ēú√≠cito pol‚Ēú¬°tico del r‚Ēú¬ģgimen de Primo de Rivera, y el apoyo econ‚Ēú‚Ēāmico de suscripciones y donaciones privadas. Las obras comenzaron a buen ritmo, pero grav‚Ēú¬°simos problemas con la compa‚Ēú‚Ėí‚Ēú¬°a constructora llevaron a los promotores a suspender pagos, de forma que ya en 1933 las obras quedaron varadas. Esta es la situaci‚Ēú‚Ēān que captura la imagen del conjunto de la iglesia y convento carmelita, desde la proyectada plaza de Espa‚Ēú‚Ėía. A la derecha, una de las viviendas baratas construidas en esa zona, seg‚Ēú‚ēĎn proyecto de Miguel ‚Ēú√ľngel Navarro y Secundino de Zuazo, para la Sociedad Zaragozana de Urbanizaci‚Ēú‚Ēān y Construcci‚Ēú‚Ēān. Fuente: Foto Mar‚Ēú¬°n Chivite, "Mundo Gr‚Ēú√≠fico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64017400, -0.89340000, '0101000020E610000082E2C798BB96ECBFF0DFBC38F1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21826660798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21826660798.webp', 'https://www.flickr.com/photos/zaragozaantigua/21826660798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21749, 'Ram de Viu 1935', 'Imagen parcial de las viviendas baratas de la Sociedad Zaragozana de Urbanizaci‚Ēú‚Ēān y Construcci‚Ēú‚Ēān, levantadas en 1928 junto al Huerva, en el ensanche de Miralbueno, seg‚Ēú‚ēĎn proyecto de Miguel ‚Ēú√ľngel Navarro y Secundino Zuazo. En este caso, se trata de las edificadas en la manzana 48, seg‚Ēú‚ēĎn proyecto de Miguel ‚Ēú√ľngel Navarro, en el arranque de la calle Ram de Viu, entre Mariano Superv‚Ēú¬°a, desde donde se hace la foto, y el vial luego llamado "Bruno Solano", hacia la derecha, tras la curva. Subsisten unas pocas de las originales viviendas unifamiliares. Las dem‚Ēú√≠s han sido sustituidas por modernos bloques habitacionales. Las placas de la calle tambi‚Ēú¬ģn son otras. Fuente: Foto Mar‚Ēú¬°n Chivite, "Mundo Gr‚Ēú√≠fico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63862100, -0.89451500, '0101000020E61000008E01D9EBDD9FECBFF8C43A55BED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22025743261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22025743261.webp', 'https://www.flickr.com/photos/zaragozaantigua/22025743261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21750, 'Gasc‚Ēú‚Ēān de Gotor 1934', 'La fenomenal invenci‚Ēú‚Ēān del "Duende" de Zaragoza en 1934, por su apabullante estolidez, triunf‚Ēú‚Ēā y fue extendida como encanto que propaga el viento. Pronto surgieron "primos" suyos en otras geograf‚Ēú¬°as peninsulares, y la prensa escrita se encarg‚Ēú‚Ēā de apostolear detalladamente sus presuntas manifestaciones, que inclu‚Ēú¬°an lanzamiento de piedras (Valencia), y alguna paliza gratuita (Castilla). Este de Zaragoza parec‚Ēú¬°a el m‚Ēú√≠s pac‚Ēú¬°fico, por eso triunf‚Ēú‚Ēā, inspir‚Ēú‚Ēā una falla valenciana, y se qued‚Ēú‚Ēā incrustado como un referente de la Zaragoza de aquellos a‚Ēú‚Ėíos, junto con el tremebundo asunto de la ni‚Ēú‚Ėía M‚Ē¨¬¨ de los Dolores Mall‚Ēú¬ģn, que dijo haber sido raptada por "los gitanos" en el Puente del 14 de julio, y que tambi‚Ēú¬ģn fue ampliamente cubierto por los medios de todo el pa‚Ēú¬°s, aun despu‚Ēú¬ģs de confesar que todo era mentira. En la imagen, encantada multitud zaragozana junto al edificio objeto de la devoci‚Ēú‚Ēān paranormal (a la izquierda), en la calle Gasc‚Ēú‚Ēān de Gotor, reunida a la espera de escuchar la quejosa "voz" de la inmaterial presencia. Al fondo, un despejado horizonte hasta la Avenida de la Rep‚Ēú‚ēĎblica, con espectral vista de Casa Faci. Fuente visual: Foto Mar‚Ēú¬°n Chivite ("Mundo Gr‚Ēú√≠fico", Madrid).', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63985000, -0.88714900, '0101000020E610000038BBB54C8663ECBF3D2CD49AE6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22026132866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22026132866.webp', 'https://www.flickr.com/photos/zaragozaantigua/22026132866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21755, 'La Dama Duende 1934', 'A finales del a‚Ēú‚Ėío 1934, muchas personas daban p‚Ēú√≠bulo a la existencia de un fantasma parlante ("duende") en un piso del n‚Ēú‚ēĎmero 2 de la calle de Gasc‚Ēú‚Ēān de Gotor. Como suceso inexplicable que era, o se cre‚Ēú¬°a en ‚Ēú¬ģl, o no, y hubo muchos que picaron. ‚Ē¨‚ĒźCuesti‚Ēú‚Ēān de fe?, ‚Ē¨‚Ēźmaravilla sobrenatural?, ‚Ē¨‚Ēźsue‚Ēú‚Ėío on‚Ēú¬°rico?, m‚Ēú√≠s bien result‚Ēú‚Ēā ser una material fantasmada-broma que puso a Zaragoza en el mapa de "lo inexplicado", al tremebundo borde del descacharrante e inane cuarto milenio. Todo comenz‚Ēú‚Ēā cuando la se‚Ēú‚Ėíorita de la imagen, que con 16 a‚Ēú‚Ėíos de edad serv‚Ēú¬°a como doncella de un matrimonio inquilino, dijo escuchar una extra‚Ēú‚Ėía voz en la cocina: el hornillo le hablaba. Por una perfecta conjunci‚Ēú‚Ēān c‚Ēú‚Ēāsmica, medi‚Ēú√≠tica, social, fenomenol‚Ēú‚Ēāgica, psicopatol‚Ēú‚Ēāgica, el l‚Ēú¬°o que se arm‚Ēú‚Ēā fue de los que marcan ‚Ēú¬ģpoca, de tal forma que varias d‚Ēú¬ģcadas despu‚Ēú¬ģs, cuando el inmueble escenario de los hechos fue derribado, el nuevo que se construy‚Ēú‚Ēā sobre su solar fue bautizado con orgullo como "Edificio Duende", y r‚Ēú¬°ase la gente. En la imagen, la muchacha Pascuala Alcocer, oidora primera de las revelaciones del "duende" hornero, fotografiada furtivamente cuando estaba tendiendo ropa a secar en el "encantado" edificio de la calle de Gasc‚Ēú‚Ēān y Gotor. Al fondo, las traseras de los hotelitos pares de la Avenida de la Rep‚Ēú‚ēĎblica, frente a Casa Faci. Fuente visual: Luis Garc‚Ēú¬°a de Linares (Semanario "Cr‚Ēú‚Ēānica", diciembre 1934)', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63985000, -0.88714900, '0101000020E610000038BBB54C8663ECBF3D2CD49AE6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22425933961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22425933961.webp', 'https://www.flickr.com/photos/zaragozaantigua/22425933961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21851, 'Av. de la Rep‚Ēú‚ēĎblica 1935', 'Imagen capturada durante el incendio que afect‚Ēú‚Ēā a la nave principal de la f‚Ēú√≠brica &quot;La Pilar&quot; de la Sociedad Espa‚Ēú‚Ėíola del Acumulador Tudor, sita en la avenida de la Rep‚Ēú‚ēĎblica n‚Ē¨‚ēĎ 87 y recayente al camino de las Alcachoferas. En primer plano, la esquina y el pretil que indica la salida de la f‚Ēú√≠brica de la acequia de San Jos‚Ēú¬ģ (antigua de las Adulas), y su continuaci‚Ēú‚Ēān en descenso por el camino de las Torres, hacia la izquierda. A‚Ēú¬ģreo, el tendido el‚Ēú¬ģctrico de la l‚Ēú¬°nea 5 del tranv‚Ēú¬°a. Fuente visual: www.mecd.gob.es/.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63940900, -0.88593500, '0101000020E610000061376C5B9459ECBF50E27327D8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35736348184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35736348184.webp', 'https://www.flickr.com/photos/zaragozaantigua/35736348184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21924, 'Av. del Siglo XX, 1931', 'Imagen capturada en el bulevar del arranque de la avenida del Siglo XX, natural continuidad hacia el sur del paseo de Sagasta. Un tranv‚Ēú¬°a de la l‚Ēú¬°nea de Torrero asciende hacia la terminal sure‚Ēú‚Ėía. A la derecha destaca la enorme nueva casa Faci, chaflanera entre el paseo de Sagasta y el final del camino de las Torres, frente a la que se extienden almacenes e instalaciones de la Tudor. A la izquierda e inmediatas, viviendas en altura de Palau y de Abizanda.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63974100, -0.88644800, '0101000020E6100000F3583332C85DECBF86747808E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/55061563766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/55061563766.webp', 'https://www.flickr.com/photos/zaragozaantigua/55061563766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23405, 'Plataforma Log‚Ēú¬°stica 2005', 'Vista a‚Ēú¬ģrea de la Plataforma Log‚Ēú¬°stica de Zaragoza (PLAZA), en 2005. Se trata de un pol‚Ēú¬°gono industrial de grandes dimensiones situado junto al Canal Imperial (derecha) y la autov‚Ēú¬°a Zaragoza-Madrid (abajo). Se gest‚Ēú‚Ēā en 2000, se comenz‚Ēú‚Ēā a construir en 2002 y se inaugur‚Ēú‚Ēā su primera fase en 2005. Ha protagonizado una trama de corrupci‚Ēú‚Ēān por malversaci‚Ēú‚Ēān de fondos entre 2004 y 2011. Fuente: www.skyscrapercity.com/', 2005, 2005, 2005, 'Siglo XXI', NULL, 41.64705900, -0.99633000, '0101000020E6100000FDC1C073EFE1EFBF8ECA4DD4D2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19298882103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19298882103.webp', 'https://www.flickr.com/photos/zaragozaantigua/19298882103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22030, 'Plaza de San Francisco 1946', 'La nov‚Ēú¬°sima segunda unidad de la serie 200 de los tranv‚Ēú¬°as, realizada en Material M‚Ēú‚Ēāvil y Construcciones y en servicio en la l‚Ēú¬°nea 11. Parque, transita por la plaza de San Francisco encaminada hacia la terminal de la plaza de Espa‚Ēú‚Ėía. Tras ella, la frondosa isleta central de la plaza que no deja ver el despejado panorama del campus universitario, y el inmueble en construcci‚Ēú‚Ēān del n‚Ē¨‚ēĎ 11 de la misma, esquinero con el paseo de Fernando el Cat‚Ēú‚Ēālico. A su lado, vaci‚Ēú‚Ēā donde una d‚Ēú¬ģcada m‚Ēú√≠s tarde se construir‚Ēú√≠ el edificio del n‚Ē¨‚ēĎ 12 de la plaza. Esta unidad tranviaria, algo modificada, perdura desde hace d‚Ēú¬ģcadas para formar parte del ut‚Ēú‚Ēāpico Museo de Transportes de Zaragoza.', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.64073500, -0.89498800, '0101000020E610000093FFC9DFBDA3ECBF8733BF9A03D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50813627796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50813627796.webp', 'https://www.flickr.com/photos/zaragozaantigua/50813627796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22137, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1954', 'Dibujo inserto en el folleto publicitario de la Residencia Femenina Universitaria Nuestra Se‚Ēú‚Ėíora del Pilar, en el paseo de Ruise‚Ēú‚Ėíores 6-8. Est‚Ēú√≠ dirigida desde 1954 por las Religiosas del Apostolado del Sagrado Coraz‚Ēú‚Ēān de Jes‚Ēú‚ēĎs. A la derecha, la calle del Porvenir. Fuente: www.todocoleccion.net', 1954, 1954, 1954, 'Anos 50', 'UNIVERSIDAD', 41.63792800, -0.88777900, '0101000020E61000002F6B6281AF68ECBFF299EC9FA7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24308228294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24308228294.webp', 'https://www.flickr.com/photos/zaragozaantigua/24308228294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22247, 'C‚Ē¨‚ēĎ del S‚Ēú√≠bado c.1955', 'Imagen capturada en el irregular camino del S‚Ēú√≠bado a la altura de la "replaceta" formada por su confluencia con la calle de la Luz (izquierda) y la calle de Gasc‚Ēú‚Ēān de Gotor (derecha). Al fondo de esta ‚Ēú‚ēĎltima calle destaca el alzado del nuevo colegio Calasancio construido seg‚Ēú‚ēĎn proyecto del arquitecto Jos‚Ēú¬ģ Luis Lafiguera, inaugurado en 1948 y con entrada principal en la calle de Sevilla. Aqu‚Ēú¬° presenta su aspecto antes de que fuera ampliado previo derribo del antiguo hotelito de Juan Solsona en cuyo solar se levant‚Ēú‚Ēā una nueva ala recayente a la calle de Gasc‚Ēú‚Ēān y Gotor (antigua de la Uni‚Ēú‚Ēān), adem‚Ēú√≠s del referencial torre‚Ēú‚Ēān angular entre ambas calles. Poco despu‚Ēú¬ģs y a partir de este punto el ascendente camino del S‚Ēú√≠bado perder‚Ēú¬°a su secular denominaci‚Ēú‚Ēān y se convertir‚Ēú¬°a en la calle del Arzobispo Morcillo.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63859500, -0.88909800, '0101000020E61000005B0C1EA67D73ECBFCF31207BBDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52032359764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52032359764.webp', 'https://www.flickr.com/photos/zaragozaantigua/52032359764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22342, 'Glorieta Vel‚Ēú√≠zquez 1965', 'Imagen desde alturas de la Glorieta Diego Vel‚Ēú√≠zquez, del final de General Mola, la entrada al Parque Pignatelli, y el comienzo de los paseos de Ruise‚Ēú‚Ėíores y de Cu‚Ēú¬ģllar. El chafl‚Ēú√≠n de la izquierda se‚Ēú‚Ėíala el final de la calle Mill‚Ēú√≠n Astray. Por Cu‚Ēú¬ģllar va descendiendo una unidad tranviaria compuesta de la l‚Ēú¬°nea 5 (Torrero-Delicias). Fuente visual: AVV. San Jos‚Ēú¬ģ.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63868300, -0.88600800, '0101000020E6100000DDD1FF722D5AECBF6EC1525DC0D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20213477529.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20213477529.webp', 'https://www.flickr.com/photos/zaragozaantigua/20213477529/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22415, 'Parque Pignatelli 1961', 'Nocturna imagen del parque de Pignatelli tras su remodelaci‚Ēú‚Ēān de 1961, que le dot‚Ēú‚Ēā de una de esas amables y atractivas fuentes con luces incorporadas, aunque la escasa centralidad de este parque, en la lejana periferia, y el hecho de no pasar coches alrededor, le restaba magnificencia y preciosismo. La estatua del p‚Ēľ√≤ocer que le dio nombre segu‚Ēú¬°a mirando hacia el canal, como cuando estaba en su original ubicaci‚Ēú‚Ēān de la glorieta de Santa Engracia. Fuente: Ediciones Arribas, Archivo Municipal de Zaragoza. C‚Ēú‚Ēādigo de referencia: ES. 50297. AM 04.01.02.01 Sobre 01538', 1961, 1961, 1961, 'Anos 60', 'UNIVERSIDAD', 41.63686900, -0.88504400, '0101000020E61000003BAC70CB4752ECBF096B63EC84D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25611744316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25611744316.webp', 'https://www.flickr.com/photos/zaragozaantigua/25611744316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22441, 'Vista a‚Ēú¬ģrea San Jos‚Ēú¬ģ 1960', 'Vista a‚Ēú¬ģrea desde el barrio de San Jos‚Ēú¬ģ, con el parque Pignatelli a la izquierda, junto al paseo de Cu‚Ēú¬ģllar. A la derecha, el camino de las Alcachoferas y la futura avenida del Tenor Fleta. Fuente: TAF Helic‚Ēú‚Ėďpters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63906100, -0.88343800, '0101000020E61000009065C1C41F45ECBF149337C0CCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30983157990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30983157990.webp', 'https://www.flickr.com/photos/zaragozaantigua/30983157990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22442, 'Paseo de Cu‚Ēú¬ģllar 1960', 'Vista a‚Ēú¬ģrea de la curva del paseo de Cu‚Ēú¬ģllar, centrada en los bloques de la calle Luis Sallenave. A la derecha, parque de Pignatelli. Al fondo, f‚Ēú√≠brica de cervezas La Zaragozana. Fuente: TAF Helic‚Ēú‚Ėďpters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63798700, -0.88414600, '0101000020E610000075745C8DEC4AECBFF722DA8EA9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30983259160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30983259160.webp', 'https://www.flickr.com/photos/zaragozaantigua/30983259160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22443, 'Vista a‚Ēú¬ģrea Cu‚Ēú¬ģllar 1960', 'Vista a‚Ēú¬ģrea centrada en el paseo de Cu‚Ēú¬ģllar, con el parque de Pignatelli a la derecha, y las iglesias de San Fernando y San Antonio al fondo. Fuente: TAF Helic‚Ēú‚Ėďpters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63805100, -0.88436000, '0101000020E6100000787FBC57AD4CECBF0D17B9A7ABD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30983364870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30983364870.webp', 'https://www.flickr.com/photos/zaragozaantigua/30983364870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25599, 'Agraria V‚Ēú¬°a Hispanidad 1970', 'Siega de herb‚Ēú√≠ceas en un campo de labor al oeste del Pol‚Ēú¬°gono Gran V‚Ēú¬°a, con el fondo de las calles de los Condes de Arag‚Ēú‚Ēān y de As‚Ēú¬°n y Palacios emergentes de bloques de viviendas. A la derecha, colegio del Sagrado Coraz‚Ēú‚Ēān y roset‚Ēú‚Ēān del Seminario Metropolitano Conciliar. En primer t‚Ēú¬ģrmino, artesanal pr‚Ēú√≠ctica agr‚Ēú¬°cola de la cosecha de alfalfa o alfance, segado con dalla o guada‚Ēú‚Ėía, recogido a mano, y cargado en un volquete tirado por caballer‚Ēú¬°a. Aunque parezca complicado viendo la imagen, estos campos dar‚Ēú√≠n paso a‚Ēú‚Ėíos despu‚Ēú¬ģs a los bloques de la calle de Robert Baden-Powell, el Andador de Manuel Guti‚Ēú¬ģrrez Mellado, el Andador de Quintana Lacacci, la avenida de Juan Pablo II, y el Complejo Aragonia.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63967700, -0.91060900, '0101000020E6100000382F4E7CB523EDBF6F8099EFE0D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14940446495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14940446495.webp', 'https://www.flickr.com/photos/zaragozaantigua/14940446495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23680, 'Aer‚Ēú‚Ēādromo Sanjurjo 1938', 'Imagen capturada en el aer‚Ēú‚Ēādromo Sanjurjo de Zaragoza cuando era utilizado como base de operaciones por la alemana Legi‚Ēú‚Ēān C‚Ēú‚Ēāndor como franca aliada de la Espa‚Ēú‚Ėía nacionalista. En este caso la fotograf‚Ēú¬°a ha sido realizada durante las evoluciones de varios ejemplares del bombardero ligero de la Luftwaffe "Dornier Do-17 E-1" (denominado originalmente L‚Ēú√≠piz Volador, redenominado de forma m‚Ēú√≠s castiza como Bacalao) all‚Ēú¬° estacionados. Fuente visual: www.todocoleccion.net', 1938, 1938, 1938, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44307707041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44307707041.webp', 'https://www.flickr.com/photos/zaragozaantigua/44307707041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22456, 'Las Acacias 1960', 'Vista casi cenital de buena parte del antiguo barrio de las Acacias, vulgo "de los Chiflaos", delimitado por el paseo de Cu‚Ēú¬ģllar (sur), las calles Vista Alegre (izquierda), Marqu‚Ēú¬ģs de Ahumada (centro), y Pradilla (derecha). Al norte, el camino de las Alcachoferas y la acequia del Entonar-Antonar, y la antigua calle del 14 de Abril, redenominada Francisco Cid‚Ēú‚Ēān. A la derecha, instalaciones de la cervecera La Zaragoza, junto a la calle Ram‚Ēú‚Ēān Berenguer IV (antigua de Agust‚Ēú¬°n Querol). El gran bloque en forma de "V" invertida es el motivo de la fotograf‚Ēú¬°a, ubicado en una antigua zona de bald‚Ēú¬°o en la que reca‚Ēú¬°an los huertos de los hotelitos preexistentes, e ilustra muy bien la estudiada integraci‚Ēú‚Ēān entre lo que hab‚Ēú¬°a antes, y lo moderno. Es importante porque marca tendencia sobre la mutaci‚Ēú‚Ēān que suceder‚Ēú√≠, a partir de entonces, en su entorno, salvo alguna contada excepci‚Ēú‚Ēān. Aunque parezca incre‚Ēú¬°ble, en el triangular espacio dejado por el nuevo bloque hasta el paseo de Cu‚Ēú¬ģllar, a‚Ēú‚Ėíos despu‚Ēú¬ģs crecer‚Ēú¬°a un bloque m‚Ēú√≠s moderno a‚Ēú‚ēĎn, en escala, y en integraci‚Ēú‚Ēān zonal. La futura calle Luis Sallenave, el vial resultante entre ambos bloques, que tiene sendas preciosas placas cer‚Ēú√≠micas en su entrada y salida, es una de las calles de Zaragoza m‚Ēú√≠s amargamente indescriptibles. En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63795500, -0.88372200, '0101000020E6100000CB2E185C7347ECBFEBA86A82A8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31645073671.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31645073671.webp', 'https://www.flickr.com/photos/zaragozaantigua/31645073671/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22486, 'Calle de Superv‚Ēú¬°a 1966', 'Imagen capturada en la cancha de balonmano situada en las traseras del Hogar "Sierra de Alcubierre", promovido en 1942 por el Auxilio Social de Falange Espa‚Ēú‚Ėíola para recoger hasta 160 hu‚Ēú¬ģrfanos de la "Revoluci‚Ēú‚Ēān y la Guerra", con dise‚Ēú‚Ėío del arquitecto Jos‚Ēú¬ģ Beltr‚Ēú√≠n Navarro. El ingreso principal estaba localizado en la moderna calle de Mariano Superv‚Ēú¬°a 27-29 (a la izquierda, fuera de plano), dentro del conjunto de las Casas Baratas de Miralbueno, junto al r‚Ēú¬°o Huerva. Al fondo, despejado e ins‚Ēú‚Ēālito panorama hasta los bloques impares del principio de la calle de Cosme Blasco y el gran Colegio Mayor de La Salle. A la izquierda, casitas de la calle de Francisco de La Ripa. Inop‚Ēú¬ľnadamente y a la derecha emerge la chimenea de la antigua f‚Ēú√≠brica textil de C‚Ēú√≠ndido Castillo, en una zona despu‚Ēú¬ģs edificada con modernos bloques de vivienda. Fuente visual: Gerardo Sancho Ramo, AMZ', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63864500, -0.89272300, '0101000020E61000005F622CD32F91ECBF80608E1EBFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40477693072.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40477693072.webp', 'https://www.flickr.com/photos/zaragozaantigua/40477693072/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22493, 'Calle de Sevilla 1966', 'Imagen capturada en la chaflanera esquina entre la calle de Gasc‚Ēú‚Ēān de Gotor y la de Sevilla, y centrada en el los bajos comerciales del moderno inmueble del n‚Ē¨‚ēĎ 17 de esa ‚Ēú‚ēĎltima calle, donde estaba radicado el establecimiento Marcal, especializado en molduras y marcos, as‚Ēú¬° como los papeles pintados, que en esa d‚Ēú¬ģcada y sobre todo en la siguiente protagonizaron de forma explosiva, para bien y para mal, la decoraci‚Ēú‚Ēān de las paredes en muchos hogares del pa‚Ēú¬°s. Hacia la izquierda, vista parcial de algunas de las parcelas que subsist‚Ēú¬°an en el lado de los impares del tramo de la calle de Sevilla desde su arranque en el cruce con la calle del Doctor Alcay. Pocos a‚Ēú‚Ėíos despu‚Ēú¬ģs comenzaron a ser derribadas y sustituidas por modernos inmuebles. En primer t‚Ēú¬ģrmino, trasera de un Renault Gordini. A la derecha, Comercial Par‚Ēú¬°s, que persevera hoy en d‚Ēú¬°a en sus veteranas funciones de ferreter‚Ēú¬°a y droguer‚Ēú¬°a.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63904400, -0.88793900, '0101000020E610000066F9BA0CFF69ECBF3E5A9C31CCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48120931677.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48120931677.webp', 'https://www.flickr.com/photos/zaragozaantigua/48120931677/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22558, 'Plaza San Francisco c.1970', 'Postal. Tranv‚Ēú¬°a. Monumento a Fernando el Cat‚Ēú‚Ēālico. Fuente: www.facebook.com/photo.php?fbid=1567234190171478&set=...', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64092800, -0.89485900, '0101000020E61000001D007157AFA2ECBF9C8BBFED09D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15207188111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15207188111.webp', 'https://www.flickr.com/photos/zaragozaantigua/15207188111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22590, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1977', 'Imagen del paseo de Ruise‚Ēú‚Ėíores en la acera de los pares, en el tramo en torno a la calle Fernando de Antequera. A la derecha, aspecto parcial del n‚Ē¨‚ēĎ 10, transformado en 2002; el representativo bloque de los n‚Ēú‚ēĎmeros 14-16, muestra de la arquitectura de autor de finales de los 60, proyectado por Enrique Delso Calavia; el n‚Ē¨‚ēĎ 18, superviviente en precario desde mediados del siglo pasado, aunque abandonado y pendiente de piqueta; el n‚Ē¨‚ēĎ 20, la antigua casa de Pedro Hern‚Ēú√≠ndez Luna (dise‚Ēú‚Ėío racionalista de los Borobia), reconvertida y transformada en los a‚Ēú‚Ėíos 40-50 en la actual Cl‚Ēú¬°nica del Pilar; y aspecto del n‚Ē¨‚ēĎ 22, la casa de Manuel Hern‚Ēú√≠ndez, en pie hasta que fue piqueteada en 1981, y sobre el solar (al que se sum‚Ēú‚Ēā su vecino n‚Ē¨‚ēĎ 24 de la izquierda) se levant‚Ēú‚Ēā la actual construcci‚Ēú‚Ēān. Fuente visual: "La evoluci‚Ēú‚Ēān urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63680600, -0.88906600, '0101000020E610000083893F8A3A73ECBFC3F2E7DB82D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15756223795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15756223795.webp', 'https://www.flickr.com/photos/zaragozaantigua/15756223795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22597, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1974', 'Luminoso paseo de los Ruise‚Ēú‚Ėíores con visual, a la izquierda, de los pares, en el tramo en torno a la calle Fernando de Antequera y Santiago Guallar, con aspecto del bloque de los n‚Ēú‚ēĎmeros 14-16, proyectado por Enrique Delso Calavia, cuando a‚Ēú‚ēĎn ten‚Ēú¬°a peces en su particular estanque; del n‚Ē¨‚ēĎ 18, superviviente en precario desde mediados del siglo pasado, aunque abandonado y pendiente de piqueta; y el n‚Ē¨‚ēĎ 20, la antigua casa de Pedro Hern‚Ēú√≠ndez Luna, transformada en los a‚Ēú‚Ėíos 40-50 en la actual Cl‚Ēú¬°nica del Pilar. En la acera de los impares, a la derecha, una despejada e irrepetible vista de la antigua "Casa del Poeta" Alberto Casa‚Ēú‚Ėíal Shackery, construida en 1930 por suscripci‚Ēú‚Ēān popular, y que ser‚Ēú√≠ piqueteada por sus herederos en 2004 para mejor aprovechar el espacio. Un poco antes, aspecto de los antiguos muros perimetrales del n‚Ē¨‚ēĎ 31-33, antes de no poder resistir el empuje de una otra piqueta. Fuente visual: www.facebook.com/photo.php?fbid=1567316920163205&set=...', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63680600, -0.88906600, '0101000020E610000083893F8A3A73ECBFC3F2E7DB82D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18040624868.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18040624868.webp', 'https://www.flickr.com/photos/zaragozaantigua/18040624868/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25601, 'Feria de Muestras 1975', 'Feria de Muestras 1975. Vista a‚Ēú¬ģrea de la Feria de Muestras celebrada ese a‚Ēú‚Ėío durante el mes de octubre.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.63751500, -0.89931400, '0101000020E6100000DCB75A272EC7ECBFCFDA6D179AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15084724301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15084724301.webp', 'https://www.flickr.com/photos/zaragozaantigua/15084724301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25604, 'La Romareda 1957', '"Estadio de La Romareda". Imagen del Estadio Municipal de La Romareda, el a‚Ēú‚Ėío de su inauguraci‚Ēú‚Ēān oficial. Captura realizada desde la inmediata "Residencia Sanitaria Jos‚Ēú¬ģ Antonio". Fuente: C‚Ēú¬ģsar Gracia Jarque. 1957.', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.63637700, -0.90139300, '0101000020E61000008BFCFA2136D8ECBF9B7631CD74D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15750753798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15750753798.webp', 'https://www.flickr.com/photos/zaragozaantigua/15750753798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22749, 'P.‚Ē¨‚ēĎ del General Mola 1976', 'Terminal imagen capturada a la altura del paseo del General Mola n‚Ē¨‚ēĎ 54, centrada en una espont‚Ēú√≠nea pancarta aparecida sobre los ca‚Ēú‚Ėíizos de obra tras el derribo a comienzos de 1976 de la que fuera sobresaliente casa de Emerenciano Garc‚Ēú¬°a, una de las m‚Ēú√≠s estimables y singulares muestras del modernismo arquitect‚Ēú‚Ēānico local, que en los prodigiosos a‚Ēú‚Ėíos 70 del pasado fue sustituida por un edificio menos modernista, m‚Ēú√≠s moderno, y de mayor aprovechamiento espacial. El texto de la pancarta constituye una enternecedora muestra de la lucha y reivindicaci‚Ēú‚Ēān que se realizaba en los grises a‚Ēú‚Ėíos 70, en el terreno de eso que se dice "cultura", o patrimonio cultural, que suele hacerse m‚Ēú√≠s pantanoso cuando se trata de una propiedad privada. En cierto modo, la movilizaci‚Ēú‚Ēān fue un ‚Ēú¬ģxito: en General Mola (luego Sagasta) n‚Ē¨‚ēĎ 54, casi no volvi‚Ēú‚Ēā a repetirse esta situaci‚Ēú‚Ēān tras la recuperaci‚Ēú‚Ēān de la democracia municipal en 1979... porque ya quedaba bien poco que tirar. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64136900, -0.88637300, '0101000020E610000049D6E1E82A5DECBF88D51F6118D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32577997394.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32577997394.webp', 'https://www.flickr.com/photos/zaragozaantigua/32577997394/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23473, 'P.‚Ē¨‚ēĎ del General Mola c.1960', 'Imagen capturada en el paseo del General Mola y centrada en el tramo de viviendas del lado de los pares que llegaba hasta la calle de Juan Pablo Bonet (al fondo, a la izquierda). Se trata de un tard‚Ēú¬°o tr‚Ēú¬°o de hotelitos o viviendas unifamiliares construidas en el paseo de Sagasta sobre una triangular parcela propiedad de Balbina Palomar. A la derecha, con llamativo remate en esquinero torre‚Ēú‚Ēān, el n‚Ēú‚ēĎmero 26 triplicado, que hab‚Ēú¬°a sido proyectado a finales de los a‚Ēú‚Ėíos veinte por el arquitecto Teodoro R‚Ēú¬°os Balaguer para Maximiano P‚Ēú¬ģrez Forni‚Ēú¬ģs. A su izquierda, formalmente muy similar, la casa de Pellejero en el n‚Ē¨‚ēĎ 26 cuadruplicado Estas viviendas de la imagen fueron derribadas al principio de la prodigiosa d‚Ēú¬ģcada de los setenta, y en su lugar fue construido un moderno y vertical bloque de viviendas. Fuente visual: www.rafaelcastillejo.com/', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.64030400, -0.88668300, '0101000020E6100000D369DD06B55FECBFBEBF417BF5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31693841768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31693841768.webp', 'https://www.flickr.com/photos/zaragozaantigua/31693841768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24109, 'Ensanche Miralbueno 1937', 'Imagen capturada durante la solemne bendici‚Ēú‚Ēān de los terrenos y colocaci‚Ēú‚Ēān de la primera piedra del Grupo de 27 Casas Baratas que la Central Obrera Nacionalsindicalista (CONS) iba a construir en la zona del Ensanche de Miralbueno, junto a la Gran V‚Ēú¬°a. Oficia el ritual de bendecir los terrenos el sacerdote Crist‚Ēú‚Ēābal Mateo, acompa‚Ēú‚Ėíado en primera fila por Jes‚Ēú‚ēĎs Muro, Jefe territorial de Falange Espa‚Ēú‚Ėíola, y del teniente coronel Buend‚Ēú¬°a, en representaci‚Ēú‚Ēān de la Quinta Divisi‚Ēú‚Ēān. Asistieron tambi‚Ēú¬ģn varios representantes del Ayuntamiento, de la Caja de Previsi‚Ēú‚Ēān Social de Arag‚Ēú‚Ēān, y Jos‚Ēú¬ģ Sinu‚Ēú¬ģs, director de la Caja de Ahorros y Monte de Piedad. Completan el conjunto otros jefes locales de Falange, "Flechas", "gastadores", "camaradas" de Segunda L‚Ēú¬°nea, empresarios y obreros. Ante ellos, la primera piedra a colocar, que portaba la informativa inscripci‚Ēú‚Ēān "‚Ē¨√≠Arriba Espa‚Ēú‚Ėía!" y la fecha del "11 de abril de 1937". Estas viviendas originalmente formaban parte de los terrenos de la Cooperativa de Casas Baratas Pablo Iglesias, que como es natural y tras el 18 de julio de 1936 fueron r‚Ēú√≠pidamente anuladas y concedidas a la CONS. Estas casas perduran y se localizan entre las calles de Ram de Viu, Mariano Superv‚Ēú¬°a y Francisco de la Ripa, en sus tramos comprendidos entre las calles de Cosme Blasco y Agust‚Ēú¬°n de Quinto.', 1937, 1937, 1937, 'Anos 30', 'UNIVERSIDAD', 41.63982100, -0.89259600, '0101000020E6100000164B917C2590ECBFA2258FA7E5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51867277272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51867277272.webp', 'https://www.flickr.com/photos/zaragozaantigua/51867277272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24456, 'C.‚Ē¨‚ēĎ del S‚Ēú√≠bado 1970', 'Ramal del Camino del S‚Ēú√≠bado inmediato a la trinchera del r‚Ēú¬°o Huerva, entre la nueva "Avenida de Goya", y la calle Juan Pablo Bonet. La cercan‚Ēú¬°a del r‚Ēú¬°o hab‚Ēú¬°a propiciado la implantaci‚Ēú‚Ēān en esta zona de numerosas peque‚Ēú‚Ėías industrias de transformaci‚Ēú‚Ēān, como calzado, g‚Ēú¬ģneros de punto, curtidos, e incluso una f‚Ēú√≠brica de bicicletas. La urbanizaci‚Ēú‚Ēān de la zona se aceler‚Ēú‚Ēā tras el cubrimiento de las v‚Ēú¬°as del ferrocarril de Madrid a Barcelona, a comienzos de los a‚Ēú‚Ėíos 60. Hasta entonces, las viviendas en la zona eran escasas, y de tipolog‚Ēú¬°a tradicional (parcelas). En la imagen, capturada durante la urbanizaci‚Ēú‚Ēān de la zona de las calles de Benavente, del Arzobispo Domenech y de Moncasi, estado del antiguo camino del S‚Ēú√≠bado entre el puente "de la V‚Ēú¬°a Transversal" (oficialmente del "Emperador Augusto", y conocido como "de los Gitanos"), que queda a la espalda, y los bloques de viviendas de los n‚Ēú‚ēĎmeros 8 y 9 de la actual calle Genoveva Torres Morales. El "1500", aparcado junto al portal del n‚Ē¨‚ēĎ 8. A continuaci‚Ēú‚Ēān, muros que delimitaban solares, un terroso camino que conectaba sinuosamente con la calle Benavente y la avenida de Goya, y antiguas construcciones industriales junto al r‚Ēú¬°o. Precisamente, a la izquierda, antigua f‚Ēú√≠brica de curtidos de la "Sociedad La Progresiva de expendedores de carnes", proyectada por Miguel ‚Ēú√ľngel Navarro en 1916. Como todos las instalaciones industriosas que jalonaban el Huerva en su tramo urbano, utilizaba el r‚Ēú¬°o como cloaca o vertedero de residuos, ya que la energ‚Ēú¬°a motriz era el‚Ēú¬ģctrica. Fue luego derribada.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64109600, -0.88942000, '0101000020E6100000F5108DEE2076ECBF57CC086F0FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19206356293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19206356293.webp', 'https://www.flickr.com/photos/zaragozaantigua/19206356293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24461, 'Tudor 1930', 'Imagen de "La Pilar", o f‚Ēú√≠brica de la Sociedad Espa‚Ēú‚Ėíola del Acumulador Tudor en su ubicaci‚Ēú‚Ēān entre el Camino de las Torres y el de las Alcachoferas. Instalada en 1898, su buena marcha econ‚Ēú‚Ēāmica posibilit‚Ēú‚Ēā que en 1916 Teodoro R‚Ēú¬°os dise‚Ēú‚Ėíara unos nuevos pabellones. El frontal de la f‚Ēú√≠brica daba a la subida a Torrero. A la izquierda, el Camino de las Torres. A la derecha, el Camino de las Alcachoferas. Al fondo, tras los ‚Ēú√≠rboles, los campos de Miraflores. La imagen se ha capturado, posiblemente, desde la casa del escultor Palao. Fuente visual: AVV. San Jos‚Ēú¬ģ.', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.63951700, -0.88595500, '0101000020E61000002849D74CBE59ECBF361E6CB1DBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19778469664.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19778469664.webp', 'https://www.flickr.com/photos/zaragozaantigua/19778469664/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24874, 'Casa Faci 1966', '1966. Foto Pomar‚Ēú‚Ēān. Cruce de Paseo Mola con el arranque del Camino de las Torres (al fondo, a la derecha). Desde un balc‚Ēú‚Ēān de la sensacionalista y fraudulenta "Casa del Duende", imagen de "Casa Faci", de Regino Borobio Ojeda, construida en 1925, y derribada en 1971.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.64011000, -0.88623900, '0101000020E610000062122EE4115CECBFD9EBDD1FEFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14741498557.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14741498557.webp', 'https://www.flickr.com/photos/zaragozaantigua/14741498557/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24892, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1943', 'Imagen de la "Casa Luis Gab‚Ēú√≠s", dise‚Ēú‚Ėíada por Regino y Jos‚Ēú¬ģ Borobio y construida en el Paseo de Ruise‚Ēú‚Ėíores n‚Ē¨‚ēĎ 2, en la manzanita que daba a la empinada calle Sevilla. La fachada principal y la puerta de acceso daban, precisamente, a esta calle. Era una vivienda unifamiliar de tres pisos (s‚Ēú‚Ēātano, bajo y principal), en el estilo regionalista-aragonesista imperante en el nuevo R‚Ēú¬ģgimen franquista. Peculiar era el remate en torre‚Ēú‚Ēān, personalizado a esta vivienda por ser la primera de la calle, con estrat‚Ēú¬ģgica visual. En 1976 fue piqueteada, y en su solar se levant‚Ēú‚Ēā la nueva sede del Colegio Oficial de M‚Ēú¬ģdicos de Zaragoza. Fuente visual: Archivo Borobio, en M‚Ēú‚Ēānica V‚Ēú√≠zquez Astorga, "Recorrido por el pasado de una zona urbana residencial: el paseo de Ruise‚Ēú‚Ėíores de Zaragoza", Artigrama n‚Ē¨‚ēĎ 22, 2007.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.63829800, -0.88709200, '0101000020E6100000286211C30E63ECBF158DB5BFB3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15155482223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15155482223.webp', 'https://www.flickr.com/photos/zaragozaantigua/15155482223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24893, 'Plaza de San Francisco 1969', 'Archivo Hist‚Ēú‚Ēārico Municipal. Gerardo Sancho Ramo. 14/12/1969. El 15 de octubre de 1969 fue inaugurado el Monumento a Fernando el Cat‚Ēú‚Ēālico de la Plaza de San Francisco, siendo Ces‚Ēú√≠reo Alierta el alcalde la ciudad. Obra de Juan de ‚Ēú√ľvalos, est‚Ēú√≠ caracterizada por el monumentalismo figurativo con que el R‚Ēú¬ģgimen pretend‚Ēú¬°a entroncar su legitimidad hist‚Ēú‚Ēārica en la Espa‚Ēú‚Ėía de los Reyes Cat‚Ēú‚Ēālicos. Este escultor hab‚Ēú¬°a realizado antes varios bultos redondos en el Valle de los Ca‚Ēú¬°dos (fascistas). En la imagen, la escultura del Cat‚Ēú‚Ēālico con un par de pintadas subversivas en el pedestal c‚Ēú‚ēĎbico, emborronadas apresuradamente antes de ser eliminadas. En la inferior puede leerse "LIBERTAD".', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.64093700, -0.89482600, '0101000020E61000002F89B3226AA2ECBFEFE53E390AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15202909412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15202909412.webp', 'https://www.flickr.com/photos/zaragozaantigua/15202909412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24949, 'Calle Superv‚Ēú¬°a 1973', 'Imagen parcial de la antigua vivienda unifamiliar, u hotel, n‚Ē¨‚ēĎ 32 edificada a finales de 1929 en la manzana 48 del proyecto de las Casas Baratas del ensanche de Miralbueno, junto al r‚Ēú¬°o Huerva, con dise‚Ēú‚Ėío de Miguel ‚Ēú√ľngel Navarro, en un nuevo vial luego denominado calle Superv‚Ēú¬°a (a la izquierda), vistosamente esquinero con la nueva calle de Ram de Viu (hacia la derecha), en airoso estilo ecl‚Ēú¬ģctico y contrastadas trazas regionalistas. En el momento de realizar al captura, esta casa era "Villa Mar‚Ēú¬°a Luisa", sita en la calle de Superv‚Ēú¬°a n‚Ē¨‚ēĎ 56, y el ata‚Ēú‚ēĎd de primer t‚Ēú¬ģrmino contiene los restos mortales de Luisa Lara Faguas, reci‚Ēú¬ģn fallecida, camino de la iglesia parroquial de San Juan de la Cruz para su funeral "corpore insepulto". Desde 1981, este provinciano edificio, junto con la mayor parte de sus convecinos de los tiempos de Miralbueno, fueron derribados para ser sustituidos por los modernos bloques levantados en su lugar. 42 arquitectos solicitaron declarar este sector de las Casas Baratas como conjunto hist‚Ēú‚Ēārico-art‚Ēú¬°stico, pero el Ayuntamiento no tuvo voluntad pol‚Ēú¬°tica para intentarlo. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63848400, -0.89439700, '0101000020E6100000137F1475E69EECBF7782FDD7B9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32828512391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32828512391.webp', 'https://www.flickr.com/photos/zaragozaantigua/32828512391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24983, 'Pignatelli 1904', 'Foto: Lete. Inauguraci‚Ēú‚Ēān del nuevo emplazamiento de la estatua de Ram‚Ēú‚Ēān Pignatelli "en las inmediaciones del Canal". Este espacio ser‚Ēú√≠ denominado despu‚Ēú¬ģs "parque Pignatelli". El monumento hab‚Ēú¬°a estado levantado en la glorieta de Pignatelli, luego plaza de Arag‚Ēú‚Ēān, desde 1859. A partir de octubre de 1904 fue sustituido por el actual, dedicado al Justiciazgo. Fuente: Diario ABC, 27-10-1904.', 1904, 1904, 1904, 'Anos 1900', 'UNIVERSIDAD', 41.63689100, -0.88506400, '0101000020E610000001BEDBBC7152ECBFF10EF0A485D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26093682588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26093682588.webp', 'https://www.flickr.com/photos/zaragozaantigua/26093682588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24992, 'P.‚Ē¨‚ēĎ del Siglo XX 1904', 'La inauguraci‚Ēú‚Ēān de la estatua de Ram‚Ēú‚Ēān Pignatelli en su nueva ubicaci‚Ēú‚Ēān en el desmonte junto al paseo del Siglo XX fue uno de los eventos destacados de las Fiestas del Pilar de ese a‚Ēú‚Ėío. Su original emplazamiento en la plaza de Arag‚Ēú‚Ēān hab‚Ēú¬°a sido ocupado por el moderno Monumento al Justiciazgo, un simb‚Ēú‚Ēālico cambio con el que las elites locales mostraban sus preferencias por los mitos rom‚Ēú√≠nticos y conservadores de siglos pret‚Ēú¬ģritos, antes que por los logros materiales de la luz de la Ilustraci‚Ēú‚Ēān.', 1904, 1904, 1904, 'Anos 1900', 'UNIVERSIDAD', 41.63688700, -0.88511800, '0101000020E6100000CD3AE3FBE252ECBFB01F628385D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50344646553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50344646553.webp', 'https://www.flickr.com/photos/zaragozaantigua/50344646553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24998, 'Casa de Pedro Hern‚Ēú√≠ndez Luna 1931', 'Foto Mar‚Ēú¬°n Chivite, 1931. Paseo de Ruise‚Ēú‚Ėíores, 20. Actualmente Cl‚Ēú¬°nica del Pilar. Edificio racionalista de Regino Borobio, 1931. Fuente visual: "Una mirada a trav‚Ēú¬ģs de la arquitectura: Regino y Jos‚Ēú¬ģ Borobio Ojeda", Daniel Estab‚Ēú¬ģn Boldova, 2013.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63726300, -0.88914100, '0101000020E61000002C0C91D3D773ECBFB5F97FD591D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14770916580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14770916580.webp', 'https://www.flickr.com/photos/zaragozaantigua/14770916580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25001, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1930', 'Alberto Casa‚Ēú‚Ėíal Shakery era un gaditano nato naturalizado zaragozano. De formaci‚Ēú‚Ēān cient‚Ēú¬°fica, inclin‚Ēú‚Ēā afici‚Ēú‚Ēān por los mitos y leyendas del costumbrismo y folklore rom‚Ēú√≠ntico del lugar, y se convirti‚Ēú‚Ēā en "el poeta" de lo baturro como constructo identitario del "ser aragon‚Ēú¬ģs". Sus obras sobre este tema, y una personalidad abierta, emp‚Ēú√≠tica y humor‚Ēú¬°stica, le alzaron como referente social popular‚Ēú¬°simo: recibi‚Ēú‚Ēā el t‚Ēú¬°tulo de "Hijo Adoptivo" y la Medalla de Oro de la ciudad, y una iniciativa social impulsada por el Ateneo Zaragozano le regal‚Ēú‚Ēā por suscripci‚Ēú‚Ēān popular una casa, llamada "del Poeta", para ‚Ēú¬ģl, su compa‚Ēú‚Ėíera, y las tres hijas y cuatro hijos comunes. Fue levantada en terrenos municipales inmediatos a los Dep‚Ēú‚Ēāsitos de Agua, en el Paseo de los Ruise‚Ēú‚Ėíores, en formas y estilo mucho m‚Ēú√≠s modestos que los de las cercanas y renombradas residencias burguesas de la zona. All‚Ēú¬° vivir‚Ēú¬°a hasta 1943, a‚Ēú‚Ėío de su muerte. La vivienda fue pasando de unas manos particulares a otras, y por aquellas cosas de los tr‚Ēú√≠mites, y de las cosas de esta ciudad, lleg‚Ēú‚Ēā al siglo XXI sin ninguna figura de protecci‚Ēú‚Ēān o catalogaci‚Ēú‚Ēān p‚Ēú‚ēĎblica, aun formando parte de la interesante n‚Ēú‚Ēāmina de edificios y construcciones que jalonaban esa zona. As‚Ēú¬° las cosas, en 2004 "La Casa del Poeta" fue piqueteada, y en su lugar se levantaron unas mejor aprovechadas viviendas particulares. En la imagen, aspecto de la "Casa del Poeta" situada justo en la esquina del Paseo de los Ruise‚Ēú‚Ėíores (izquierda), y un vial que en 1950 recibi‚Ēú‚Ēā el nombre de "Santiago Guallar" (derecha). Los muros de contenci‚Ēú‚Ēān salvan el enorme desnivel de la zona, una de las "terrazas" de Cu‚Ēú¬ģllar. Justo detr‚Ēú√≠s est‚Ēú√≠ el barbecho urban‚Ēú¬°stico expectante de los Dep‚Ēú‚Ēāsitos de Agua. Fuente: Foto Mart‚Ēú¬°nez (Mundo Gr‚Ēú√≠fico, noviembre 1930)', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.63721500, -0.88849700, '0101000020E6100000F702B342916EECBFA4C2D84290D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17112763737.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17112763737.webp', 'https://www.flickr.com/photos/zaragozaantigua/17112763737/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25009, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1930', 'Imagen de la soleada terraza del estiloso Restaurant Ruise‚Ēú‚Ėíores, ubicado cerca del arranque del paseo del mismo nombre, "a muy pocos metros del tranv‚Ēú¬°a de Torrero", como rezaba la publicidad de la ‚Ēú¬ģpoca, dado que esta zona segu‚Ēú¬°a pareciendo un poco a desmano de la sedetana urbe. La frondosa vegetaci‚Ēú‚Ēān indica el exuberante arbolado del paseo, al que se le a‚Ēú‚Ėíad‚Ēú¬°an en este caso los jardines de la casa del n‚Ē¨‚ēĎ 12, cuya fachada principal es parcialmente visible en un oportuno claro. Al fondo, los ‚Ēú‚ēĎltimos edificios del paseo de Sagasta, y el arranque de la avenida del Siglo XX. A la derecha, el comedor con servicio diario de men‚Ēú‚ēĎ y a la carta, y vistas m‚Ēú√≠s que interesantes a la ciudad. Fuente visual: peri‚Ēú‚Ēādico "Heraldo de Arag‚Ēú‚Ēān".', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.63740000, -0.88797200, '0101000020E610000054707841446AECBF363CBD5296D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32432959341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32432959341.webp', 'https://www.flickr.com/photos/zaragozaantigua/32432959341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25014, 'Avenida de la Rep‚Ēú‚ēĎblica 1934', 'Tarjeta Postal de la "Avenida de la Rep‚Ēú‚ēĎblica". Comenzaba en la Plaza de Arag‚Ēú‚Ēān (al fondo de la imagen), hasta el punto en que est‚Ēú√≠ hecha la foto,en la confluencia con el Camino de las Torres (hacia la derecha), con el Camino del S‚Ēú√≠bado y Gasc‚Ēú‚Ēān de Gotor (hacia la izquierda). A partir de este punto, comenzaba la Avenida del Siglo XXI, que llegaba hasta la Playa de Torrero. Ninguno de los edificios de la izquierda (los n‚Ēú‚ēĎmeros pares) sobreviven. De los de la derecha (n‚Ēú‚ēĎmeros impares), alguno. La imagen se corresponde con el estado de este tramo del antiguo paseo de Sagasta capturado antes de 1928.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63974100, -0.88644800, '0101000020E6100000F3583332C85DECBF86747808E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14674788707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14674788707.webp', 'https://www.flickr.com/photos/zaragozaantigua/14674788707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25023, 'Laboratorios ULTA 1977', 'La huelga laboral por motivos econ‚Ēú‚Ēāmicos en los Laboratorios Universal Lucha Terap‚Ēú¬ģutica Antiinfecciosa, Ulta, desvel‚Ēú‚Ēā el funcionamiento de una pr‚Ēú‚Ēāspera empresa hasta entonces considerada mod‚Ēú¬ģlica, basada en el paternalismo empresarial y en unas buenas conexiones con el poder pol‚Ēú¬°tico del R‚Ēú¬ģgimen. En Zaragoza fabricaba alimentos infantiles con el prestigio publicitario que le otorgaba la vinculaci‚Ēú‚Ēān con una empresa alemana tapadera, la Deutsche Ulta; con la Fundaci‚Ēú‚Ēān Fernando Cuenca Villoro y a trav‚Ēú¬ģs del Instituto de Investigaci‚Ēú‚Ēān Bioqu‚Ēú¬°mica y de Nutrici‚Ēú‚Ēān Don Juan Carlos I, sin investigaciones tangibles; y con la utilizaci‚Ēú‚Ēān de la imagen del doctor Grande Covi‚Ēú√≠n, destacado de la Fundaci‚Ēú‚Ēān. En la imagen, manifestaci‚Ēú‚Ēān de trabajadores y trabajadoras de Laboratorios ULTA en las inmediaciones de la empresa, al fondo, en la calle de Juan Pablo Bonet.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63997500, -0.88735100, '0101000020E61000002A55A2EC2D65ECBFF9A067B3EAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15603958197.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15603958197.webp', 'https://www.flickr.com/photos/zaragozaantigua/15603958197/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25032, 'Calle Juan Pablo Bonet 1934', 'El alcalde de Zaragoza, Miguel L‚Ēú‚Ēāpez de Gera, inaugura la placa alusiva al nuevo nombre de la Ronda de Circunvalaci‚Ēú‚Ēān o V‚Ēú¬°a Transversal: Juan Pablo Bonet. A la izquierda, bar esquinero con la calle de Anselmo Gasc‚Ēú‚Ēān de Gotor. Fuente visual: Heraldo de Arag‚Ēú‚Ēān.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63985000, -0.88714900, '0101000020E610000038BBB54C8663ECBF3D2CD49AE6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31376048700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31376048700.webp', 'https://www.flickr.com/photos/zaragozaantigua/31376048700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25039, 'Gasc‚Ēú‚Ēān de Gotor 1935', 'Imagen de la moderna y reciente fachada de acceso a la Tintorer‚Ēú¬°a Imperial de Jaime Masip, sita en el n‚Ē¨‚ēĎ 10 de la calle de Gasc‚Ēú‚Ēān de Gotor. Ante ella posa Maruja Soria, almuniense elegida Miss Arag‚Ēú‚Ēān. Junto a ella, el referido Masip, que contaba con sucursales de esta casa en Don Jaime I, M‚Ēú¬ģndez N‚Ēú‚ēĎ‚Ēú‚Ėíez, y Torre Nueva. Este tipo de comerciales protagonizados por la Miss del momento, eran habituales en la publicidad de la ‚Ēú¬ģpoca. En la cristalera del edificio se reflejan las vallas de obra del edificio en construcci‚Ēú‚Ēān del n‚Ē¨‚ēĎ 9, al otro lado de la calle. Fuente visual: www.mecd.gob.es/.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63955900, -0.88756300, '0101000020E6100000FF774485EA66ECBF656EBE11DDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35737164503.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35737164503.webp', 'https://www.flickr.com/photos/zaragozaantigua/35737164503/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25044, 'Avenida de la Rep‚Ēú‚ēĎblica/del General Mola 1937', 'Imagen capturada, posiblemente, desde las alturas de la modernista Casa de Palao, en el arranque de la avenida del Siglo XX, con una recurrente vista de la avenida de la Rep‚Ēú‚ēĎblica en su tramo inmediato al final, por la derecha, del camino de las Torres. Signo de los tiempos en esta tarjeta postal, destaca el arsesanal cambiazo de r‚Ēú‚Ēātulo de la misma, de "Avenida de la Rep‚Ēú‚ēĎblica", a "Avenida del General Mola", de resultas de la inmediata modificaci‚Ēú‚Ēān del nomencl‚Ēú√≠tor asociado, de alguna forma, a personas, ideas, valores, fechas y conmemoraciones vinculadas con la Segunda Rep‚Ēú‚ēĎblica Espa‚Ēú‚Ėíola, realizada por la nueva corporaci‚Ēú‚Ēān municipal nacionalista impuesta que asumi‚Ēú‚Ēā el gobierno municipal tras el triunfo del militar golpe de Estado del 19 de julio de 1936. En un primer momento, y hasta la realizaci‚Ēú‚Ēān de nuevas im‚Ēú√≠genes para iluminar postales tras la guerra, las im‚Ēú√≠genes anteriores fueron "recicladas", tal que esta. Adem‚Ēú√≠s, la imagen se corresponde con el aspecto de este tramo del paseo anterior a la d‚Ēú¬ģcada de los a‚Ēú‚Ėíos 30.', 1937, 1937, 1937, 'Anos 30', 'UNIVERSIDAD', 41.64003000, -0.88644800, '0101000020E6100000F3583332C85DECBFBD3AC780ECD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49219518067.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49219518067.webp', 'https://www.flickr.com/photos/zaragozaantigua/49219518067/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25049, 'Calle de Gasc‚Ēú‚Ēān de Gotor, 1934', 'Un par de guardias del Cuerpo de Seguridad y Asalto abren la hornilla de la cocina econ‚Ēú‚Ēāmica de la que sale una extra‚Ēú‚Ėía voz de hombre en el segundo piso derecha del n‚Ē¨‚ēĎ 2 de la calle de Gasc‚Ēú‚Ēān de Gotor. El fant‚Ēú√≠stico episodio, bautizado "el duende de la hornilla" o "el duende de Zaragoza", impacta en la opini‚Ēú‚Ēān p‚Ēú‚ēĎblica del momento.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.63987700, -0.88725300, '0101000020E610000075E448676064ECBF363B527DE7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51098766554.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51098766554.webp', 'https://www.flickr.com/photos/zaragozaantigua/51098766554/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25577, 'Juan Pablo Bonet 1962', 'John "Ganso" Kovatch, militar del ej‚Ēú¬ģrcito de los EE.UU de Norteam‚Ēú¬ģrica destinado en la Base A‚Ēú¬ģrea de Zaragoza, haciendo turismo en la ciudad. En la imagen, el chafl‚Ēú√≠n del edificio de la calle de Juan Pablo Bonet 25, en el que residi‚Ēú‚Ēā una temporada, de alquiler, junto al antiguo camino del S‚Ēú√≠bado (a la derecha), entonces lleno de instalaciones industriosas, al Huerva, y al "puente de los Gitanos" (antiguo puente de la V‚Ēú¬°a Transversal). El "coche del pueblo" dise‚Ēú‚Ėíado por Ferdinand Posche y Adolfo Hitler, mirando hacia el paseo del General Mola.', 1962, 1962, 1962, 'Anos 60', 'UNIVERSIDAD', 41.64057500, -0.88915200, '0101000020E6100000278925E5EE73ECBF4ED1915CFED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15110849157.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15110849157.webp', 'https://www.flickr.com/photos/zaragozaantigua/15110849157/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25586, 'Calle Viva Espa‚Ēú‚Ėía 1954', 'Vista de la calle de Viva Espa‚Ēú‚Ėía engalanada por celebraci‚Ēú‚Ēān de fiestas, en 1954. Vemos el ‚Ēú‚ēĎltimo tramo, sin salida al fondo, vallado por ser acceso al r‚Ēú¬°o Huerva. Fuente: www.facebook.com/photo.php?fbid=10203686625306944&set...', 1954, 1954, 1954, 'Anos 50', 'UNIVERSIDAD', 41.63968400, -0.89035400, '0101000020E6100000ED9BFBABC77DECBF22E3512AE1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21279479756.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21279479756.webp', 'https://www.flickr.com/photos/zaragozaantigua/21279479756/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25607, 'Carmelitas Descalzos 1931', 'En 1929 se puso la primera piedra del nuevo Convento e Iglesia de los Carmelitas Descalzos, al lado de la proyectada plaza de Espa‚Ēú‚Ėía y la Gran V‚Ēú¬°a zaragozana, junto al antiguo camino de Los Cubos, entre campos de ma‚Ēú¬°z. El proyecto llevaba la firma de Secundino Zuazo, y una elevada torre era elemento destacado de la nueva construcci‚Ēú‚Ēān, pensada para una comunidad de 40 carmelitas descalzos, que se vendr‚Ēú¬°an a esta ubicaci‚Ēú‚Ēān desde la provisional de Delicias. A la ceremonia asisti‚Ēú‚Ēā el arzobispo y las primeras autoridades militares y civiles (Capit‚Ēú√≠n General, Gobernador Civil, Alcalde...) Circunstancias hist‚Ēú‚Ēāricas torcieron el asunto, y el proyectado convento fue militarizado por los golpistas tras el 18 de julio de 1936, que lo utilizaron aprovechando la torre como centro de transmisiones. En 1943 el edificio termin‚Ēú‚Ēā en manos de La Salle, que lo reconvirti‚Ēú‚Ēā en colegio, hasta hoy. Los Carmelitas Descalzos se buscaron otro lugar. No muy lejos, en San Juan de la Cruz, y al a‚Ēú‚Ėío siguiente, ya estaban instalados. En la imagen, aspecto de las obras en 1931, vistas desde la plaza de Espa‚Ēú‚Ėía. Fuente: "Los Carmelitas Descalzos en Zaragoza", Fray Valent‚Ēú¬°n de la Cruz, 1995.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.64017400, -0.89340000, '0101000020E610000082E2C798BB96ECBFF0DFBC38F1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16383659385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16383659385.webp', 'https://www.flickr.com/photos/zaragozaantigua/16383659385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25613, 'Casas Baratas 1932', 'Detalle de la manzana 48, proyectada por Miguel ‚Ēú√ľngel Navarro, de la urbanizaci‚Ēú‚Ēān de Casas Baratas del ensanche de Miralbueno, en el actual entorno de las calles de Sta. Teresa de Jes‚Ēú‚ēĎs (frontal), Mariano Superv‚Ēú¬°a (traseras), y Luis Vives (derecha). Apenas subsisten unos pocos de los 21 originales hoteles unifamiliares. Los de la imagen, ciertamente no: casi todos en la reserva de la peque‚Ēú‚Ėía manzana de Ram de Viu- Mariano Superv‚Ēú¬°a-Bruno Solano. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1932, 1932, 1932, 'Anos 30', 'UNIVERSIDAD', 41.63894600, -0.89407700, '0101000020E6100000A662635E479CECBF7BF486FBC8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19324833871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19324833871.webp', 'https://www.flickr.com/photos/zaragozaantigua/19324833871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25617, 'Proyecto de ensanche 1923', 'Proyecto de zona de ensanche redactado. Plano de urbanizaci‚Ēú‚Ēān. Sociedad Rapid Cem Fer, Ayuntamiento de Zaragoza, junio de 1923. Orientado con el norte a la derecha, se trata del ensanche de Miralbueno. La plaza central proyectada corresponde a la llamada de Espa‚Ēú‚Ėía, luego de San Francisco. Fuente: Zaragoza 1908-2008. Colegio Oficial de Arquitectos de Arag‚Ēú‚Ēān, 2009.', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.64092800, -0.89485900, '0101000020E61000001D007157AFA2ECBF9C8BBFED09D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22146652259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22146652259.webp', 'https://www.flickr.com/photos/zaragozaantigua/22146652259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25619, 'La Ballena 2013', 'El colegio de las Hermanas Franciscanas del Esp‚Ēú¬°ritu Santo de Montpellier se inaugur‚Ēú‚Ēā en 1948 en la calle Andr‚Ēú¬ģs Piquer 5 de Zaragoza. Tras la uni‚Ēú‚Ēān en 1979 con el colegio de los Hermanos de La Salle, en la calle Santa Teresa 23 (en la foto, al fondo), comienzan los cursos conjuntos en 1981. En 2013 se levanta un patio elevado sobre el preexistente, seg‚Ēú‚ēĎn proyecto de 2012 de Guzm‚Ēú√≠n de Yarza, al que se da el nombre de La Ballena. Fuente visual: architizer255.rssing.com/', 2013, 2013, 2013, 'Siglo XXI', 'UNIVERSIDAD', 41.63971600, -0.89432400, '0101000020E610000097E4805D4D9EECBF2D5DC136E2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23857499073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23857499073.webp', 'https://www.flickr.com/photos/zaragozaantigua/23857499073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25631, 'Pl. de Espa‚Ēú‚Ėía 1929', 'Manzana n‚Ē¨‚ēĎ 48 de las casas baratas del Huerva con baja densidad incluida en el ensanche de Miralbueno, entorno de la proyectada plaza de Espa‚Ēú‚Ėía que luego terminar‚Ēú¬°a recibiendo el nombre de San Francisco. Esta imagen ha sido capturada durante la construcci‚Ēú‚Ēān de sus veintiuna viviendas unifamiliares promovidas en 1929 por la Sociedad Zaragozana de Urbanizaci‚Ēú‚Ēān y Construcci‚Ēú‚Ēān seg‚Ēú‚ēĎn proyecto del arquitecto Miguel ‚Ēú√ľngel Navarro P‚Ēú¬ģrez. Las de la escena se corresponden con las ocho viviendas pareadas del centro del tramo. La calle sin nombre de primer t‚Ēú¬ģrmino ser‚Ēú¬°a denominada de Santa Teresa de Jes‚Ēú‚ēĎs, entre las calles de Bruno Solano (al fondo) y Luis Vives. Ninguna de estas viviendas ha perdurado. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'UNIVERSIDAD', 41.63855700, -0.89500900, '0101000020E6100000710514EAE9A3ECBFE1D05B3CBCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34395919764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34395919764.webp', 'https://www.flickr.com/photos/zaragozaantigua/34395919764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25632, 'GE Basilio Para‚Ēú¬°so 1933', 'Imagen capturada durante la inauguraci‚Ēú‚Ēān oficial del grupo escolar Basilio Para‚Ēú¬°so, sito al sureste de la zona de casas baratas del ensanche de Miralbueno, cerca del cauce del r‚Ēú¬°o Huerva. La construcci‚Ēú‚Ēān y sustento de este colegio p‚Ēú‚ēĎblico fue sufragado a la memoria del pr‚Ēú‚Ēācer Basilio Para‚Ēú¬°so por su hijo. La primera maestra nacional de este centro fue Asunci‚Ēú‚Ēān Maga‚Ēú‚Ėía P‚Ēú¬ģrez, y Mariano G‚Ēú√≠lvez el primer maestro. La imagen ha sido capturada desde un vial sin nombre que m‚Ēú√≠s tarde ser‚Ēú√≠ denominado de Mariano Superv‚Ēú¬°a. A la lzquierda, un camino que luego sera incorporado como tramo final de la calle de Bruno Solano. Al inicio de la d‚Ēú¬ģcada de los a‚Ēú‚Ėíos setenta este edificio ser‚Ēú√≠ sustituido por uno nuevo, de cuatro alturas, en la misma ubicaci‚Ēú‚Ēān, que hoy sigue prestando servicio p‚Ēú‚ēĎblico como CEIP Basilio Para‚Ēú¬°so. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.63854000, -0.89380700, '0101000020E6100000AAF23D23119AECBF0B98C0ADBBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35552281084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35552281084.webp', 'https://www.flickr.com/photos/zaragozaantigua/35552281084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22677, 'Condes de Arag‚Ēú‚Ēān 1976', 'Imagen, desde la notable atalaya del n‚Ē¨‚ēĎ 7 de la calle Luis Bermejo, con una interesante panor‚Ēú√≠mica del explosivo crecimiento urban‚Ēú¬°stico de la ciudad en la zona finalmente denominada "Romareda", aunque sin a‚Ēú‚Ėíadirle el adjetivo "Nueva" y diferenciarlo as‚Ēú¬° del m‚Ēú√≠s antiguo y cercano a la ciudad "barrio de la Romareda", inmediato a la estaci‚Ēú‚Ēān de Campo Sepulcro. Este es una de los grandes paradigmas de Zaragoza donde, por m‚Ēú√≠gicas circunstancias, todas las cosas est‚Ēú√≠n donde est‚Ēú√≠n "as‚Ēú¬°, de toda la vida". En primer plano, el bloque del n‚Ē¨‚ēĎ 11 de la nueva calle Condes de Arag‚Ēú‚Ēān, que se nos revela a la izquierda como un periurbano vial, o portal entre dos mundos: el antiguo, con sus campos de herb‚Ēú√≠ceas y cultivos rururbanos, y el moderno, con sus campos de espigados cultivos residenciales. Al fondo, a la derecha, destaca la mole del Hospicio Provincial del Alto de Carabinas. La V‚Ēú¬°a de la Hispanidad a‚Ēú‚ēĎn asemeja un lejano cintur‚Ēú‚Ēān de ronda, como cuando era la Carretera de los Enlaces. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Referencia: ES. 50297. AM 04.01.02.11 Sobre 87227', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63864500, -0.90502900, '0101000020E610000089CF9D60FFF5ECBF80608E1EBFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25873569584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25873569584.webp', 'https://www.flickr.com/photos/zaragozaantigua/25873569584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25721, 'Calle de Pradilla 1899', 'Sobre terrenos de la antigua Torre de Allustante, empinados por su inmediatez con el ascendente Camino de Torrero, la Sociedad de Propietarios "La Amistad" promovi‚Ēú‚Ēā en 1892 la parcelaci‚Ēú‚Ēān particular de una nueva barriada, y la urbanizaci‚Ēú‚Ēān de nuevos viales en una zona virgen. Fue denominado "Barrio de las Acacias", por los espinosos ‚Ēú√≠rboles, aunque la socarroner‚Ēú¬°a ind‚Ēú¬°gena enseguida sac‚Ēú‚Ēā punta al asunto, y lo rebautiz‚Ēú‚Ēā "Barrio de los Chiflaos", porque no les cuadraba en la cabeza que gente de bien se subiera a vivir una zona cero glamurosa. M‚Ēú√≠s pronto que tarde, aun con chismorreos, fueron surgiendo nuevas calles como Vista Alegre, S‚Ēú√≠inz de Varanda, Marqu‚Ēú¬ģs de Ahumada, y Pradilla, y en unas d‚Ēú¬ģcadas se pod‚Ēú¬°an encontrar una cincuentena de casas de destacado porte, con amplios jardines, y con todos los servicios b‚Ēú√≠sicos de la ‚Ēú¬ģpoca. Como era una urbanizaci‚Ēú‚Ēān "particular", ten‚Ēú¬°a su guarda, y su cadena que, de noche, cerraba el acceso rodado. En la imagen, de muy mala calidad, porque la fuente no da para mejor cosa, vista de la calle Pradilla, con la calle S‚Ēú√≠inz de Varanda a la derecha. De la espectacularidad de esas fincas con torres, apenas queda un leve reflejo en unas pocas construcciones supervivientes, entre una mayor‚Ēú¬°a de nuevas, modernas y as‚Ēú¬ģpticas viviendas. Fuente: Revista "Nuevo Mundo", 1899.', 1899, 1899, 1899, 'Siglo XIX', 'UNIVERSIDAD', 41.63736000, -0.88348700, '0101000020E6100000EB1D6E878645ECBFA8E3310395D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19831895753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19831895753.webp', 'https://www.flickr.com/photos/zaragozaantigua/19831895753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25755, 'Parque Pignatelli 1990', 'Interior de la entrada al parque Pignatelli de Zaragoza, el 22 de marzo de 1990. Al fondo, paseo de Sagasta. A la izquierda, estatua de bronce con la inscripci‚Ēú‚Ēān "Los Ruise‚Ēú‚Ėíores". Ya no est‚Ēú√≠. Fuente: "Memoria de las calles de Zaragoza", Juli‚Ēú√≠n Ruiz Mar‚Ēú¬°n, Librer‚Ēú¬°a General, 1998.', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.63881800, -0.88620200, '0101000020E610000019CBF44BC45BECBF4E0CC9C9C4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21683725031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21683725031.webp', 'https://www.flickr.com/photos/zaragozaantigua/21683725031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25777, 'Espacio Parque Pignatelli 1989', 'Imagen capturada en el interior del antiguo dep‚Ēú‚Ēāsito de agua soterrado de Pignatelli cuando era utilizado como escenario de la exposici‚Ēú‚Ēān √Ē√á¬£III Premio de Escultura Pablo Gargallo√Ē√á√ė. Este espacio fue dise‚Ēú‚Ėíado por el arquitecto municipal Ricardo Magdalena en 1876 para depositar agua de boca y riego, con f‚Ēú√≠brica de ladrillo, pilares de arenisca y b‚Ēú‚Ēāveda que incluye hormig‚Ēú‚Ēān. De aqu‚Ēú¬° bajaba el agua que abastec‚Ēú¬°a, entre otras, la fuente de la Princesa o Neptuno. En 1983-87 este lugar fue intervenido para habilitarlo como municipal espacio expositivo (hasta 2006). En estos momentos (2017) se anuncia un ejecuci‚Ēú‚Ēān de un proyecto para estas instalaciones que supone la ampliaci‚Ēú‚Ēān del parque Pignatelli y mejorar la conexi‚Ēú‚Ēān viaria con el entorno, financiado con la construcci‚Ēú‚Ēān de 77 pisos de promoci‚Ēú‚Ēān privada. Fuente visual: www.zaragoza.es/', 1989, 1989, 1989, 'Anos 80', 'UNIVERSIDAD', 41.63743400, -0.88625400, '0101000020E6100000B75F3E59315CECBFE2ADF36F97D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38074284835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38074284835.webp', 'https://www.flickr.com/photos/zaragozaantigua/38074284835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25784, 'Calle de Pradilla c.1895', 'Ins‚Ēú‚Ēālita e impagable imagen capturada posiblemente desde la altura de la torre de Lacasa en el arranque de la calle de Vista Alegre, del original barrio de las Acacias, vulgo de los Chiflaos, urbanizado desde 1892 por la Sociedad de Propietarios La Amistad sobre terrenos de la antigua torre de Allustante. La calle de Pradilla, en descenso desde el camino de Torrero, se abre en el centro de la imagen para dar comienzo a la calle de S‚Ēú√≠inz de Varanda. Destaca el muestrario de la variopinta e irrepetible variedad de algunas de la 50 viviendas unifamiliares que conformaban esta barriada, todas con su correspondiente y apreciable zona ajardinada. Ninguna de ellas sobrevivir‚Ēú¬°a al devenir de los tiempos, sobre todo los de la segunda mitad de la centuria XX. Al fondo y a la derecha, feraz entorno de las torres de Catalina y de Monserrat, que flanqueaban el lado norte del camino de Lapuyade, o antigua Caba‚Ēú‚Ėíera, paralelo al arbolado y m‚Ēú√≠s alto cauce por donde flu‚Ēú¬°a al aire la nueva acequia del Plano, sobre el que emerge la neocl‚Ēú√≠sica c‚Ēú‚ēĎpula de la iglesia de San Fernando,', 1895, 1895, 1895, 'Siglo XIX', 'UNIVERSIDAD', 41.63736000, -0.88348700, '0101000020E6100000EB1D6E878645ECBFA8E3310395D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49032889787.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49032889787.webp', 'https://www.flickr.com/photos/zaragozaantigua/49032889787/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25791, 'Paseo de Cu‚Ēú¬ģllar 1966', 'Imagen centrada en los inmuebles de los n‚Ēú‚ēĎmeros 15, 17 y 19 del paseo de Cu‚Ēú¬ģllar y el n‚Ē¨‚ēĎ 76 A de la calle de Vista Alegre, veteranos de principios del siglo XX asociados al barrio de Vista Alegre y con fachada principal a la subida de Cu‚Ēú¬ģllar. El n‚Ē¨‚ēĎ 15 fue proyectado por el arquitecto Julio Bravo Folch para oficinas y viviendas de la Sociedad An‚Ēú‚Ēānima de Cr‚Ēú¬ģdito y Seguros "La Regeneraci‚Ēú‚Ēān". A su derecha y tras el ingreso a un camino particular que conectaba descendente con el camino de las Alcachoferas, el edificio de oficinas de la Sociedad de Seguro Infantil "La Actividad", proyectado por el arquitecto F‚Ēú¬ģlix Navarro P‚Ēú¬ģrez. Chafaneando con la calle de Vista Alegre destaca el n‚Ē¨‚ēĎ 76 A de esa calle, resultado de la construcci‚Ēú‚Ēān en 1906, de un inmueble previo de 1894 derribado, con proyecto posiblemente por el arquitecto Jos‚Ēú¬ģ Mar‚Ēú¬°a Pujol de Barber‚Ēú√≠. Estos cuatro inmuebles fueron derribados a finales de 1968 y principio de 1969 para dar paso al actual bloque de viviendas con el numeral 15-17-19 del paseo de Cu‚Ēú¬ģllar y el bloque del n‚Ē¨‚ēĎ 1 de la calle de Vista Alegre, en coherencia con el bloque de los n‚Ēú‚ēĎmeros 9-11-13 del paseo que en la imagen y a la izquierda se‚Ēú‚Ėíala el signo de los tiempos. En definitiva, otras excelentes muestras de la arquitectura local de comienzos del siglo XX desaparecidas de forma lamentable en beneficio del aprovechamiento vertical impersonal y descontextualizado.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63849200, -0.88439100, '0101000020E6100000390EBC5AEE4CECBFFA60191BBAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54384988668.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54384988668.webp', 'https://www.flickr.com/photos/zaragozaantigua/54384988668/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25927, 'P.‚Ē¨‚ēĎ del General Mola c.1956', 'Luminosa imagen capturada desde cierta altura del tramo medio del paseo del General Mola, orientada en direcci‚Ēú‚Ēān norte, hacia la plaza de Para‚Ēú¬°so, al fondo. En el lado de los impares, a la derecha, ya ha sido recrecido el original edificio de viviendas del n‚Ē¨‚ēĎ 37 (actual n‚Ē¨‚ēĎ 45), dise‚Ēú‚Ėíado por Mart‚Ēú¬°nez de Ubago para el conde de Monte Negr‚Ēú‚Ēān. Los hotelitos supervivientes, a uno y otro lado del paseo, seguir‚Ēú√≠n esta tendencia uno a uno, bien por recrecimiento, bien por derribo y obra nueva. Desde el barrio de Venecia desciende, a la derecha, una composici‚Ēú‚Ēān tranviaria motor-remolque de la serie 100, en servicio en la l‚Ēú¬°nea 5 (Venecia-Delicias). Fuente visual: www.ebay.es/', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.64007000, -0.88652300, '0101000020E61000009CDB847B655EECBF4B9352D0EDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34433725805.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34433725805.webp', 'https://www.flickr.com/photos/zaragozaantigua/34433725805/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26032, 'Camino de las Torres c.1945', 'Imagen capturada posiblemente desde la altura de la reciente torre del Sacrario Militare Italiano, que permite una interesante visual de las terrazas inferiores en descenso hacia la ciudad. En primer‚Ēú¬°simo plano, las enormes instalaciones de la f‚Ēú√≠brica TUDOR, poco antes de trasladarse a la carretera de Navarra. De izquierda a derecha, el camino de las Torres, y la calle de Col‚Ēú‚Ēān, al frente, que arranca de Tenor Fleta. A la derecha, el antiguo camino de las Alcachoferas, y tras Tenor Fleta, los muros perimetrales del colegio de los PP. Agustinos, y la chimenea de la Lanera Aragonesa. En el paseo de las Damas, luminosa, la fachada del antiguo convento de las Oblatas. Y al fondo, visi‚Ēú‚Ēān panor‚Ēú√≠mica de la ciudad vieja, con sus torres, c‚Ēú‚ēĎpulas, chimeneas, antes del estallido vertical. Fuente visual: Postal Garc‚Ēú¬°a Garrabella, en www.todocoleccion.net/', 1945, 1945, 1945, 'Anos 40', 'UNIVERSIDAD', 41.63980700, -0.88512700, '0101000020E61000009ACFB9DBF552ECBF3D601E32E5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30943425895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30943425895.webp', 'https://www.flickr.com/photos/zaragozaantigua/30943425895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23678, 'Aer‚Ēú‚Ēādromo Sanjurjo 1938', 'Imagen capturada en el aer‚Ēú‚Ēādromo Sanjurjo de Zaragoza y centrada en un Heinkel He-51 C-1 de la alemana Legi‚Ēú‚Ēān C‚Ēú‚Ēāndor en curiosa situaci‚Ēú‚Ēān de "kopfstand bei vor landung", o capotado en aterrizaje. Este moderno biplano fue utilizado como avi‚Ēú‚Ēān de caza hasta la llegada de los sovi‚Ēú¬ģticos modelos Polikarpov I-15 e I-16 (denominados "Chato" y "Mosca", respectivamente) a las Fuerzas A‚Ēú¬ģreas de la Rep‚Ēú‚ēĎblica Espa‚Ēú‚Ėíola. Desde entonces fue encomendado a labores de avi‚Ēú‚Ēān de asalto o ataque al suelo. Fuente visual: www.todocoleccion.net', 1938, 1938, 1938, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38528391930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38528391930.webp', 'https://www.flickr.com/photos/zaragozaantigua/38528391930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26065, 'Campo de la Victoria 1938', 'Imagen capturada desde la altura de la tribuna montada en el Campo de la Victoria con motivo del festejo organizado el 19 de abril con motivo del aniversario del Decreto de Unificaci‚Ēú‚Ēān de FET y JONS, con presencia del general Francisco Franco. Este despejado panorama edilicio fue denominado temporalmente "Campo de la Victoria", en el ensanche de Miralbueno, entre la original plaza de Espa‚Ēú‚Ėía y la prolongaci‚Ēú‚Ēān de la Gran V‚Ēú¬°a hasta el parque de Buenavista y el r‚Ēú¬°o Huerva. Al fondo y a la izquierda, las dos pioneras manzanas proyectadas por Secundino Zuazo que inauguraron el moderno desarrollo urban‚Ēú¬°stico de esta zona. A la derecha, la mole del proyectado nuevo convento de los carmelitas descalzos de San Jos‚Ēú¬ģ, militarizado tras el 18 de julio de 1936 por el ramo militar de transmisiones. Junto a ‚Ēú¬ģl, algunas de las seriadas viviendas unifamiliares proyectadas por Miguel ‚Ēú√ľngel Navarro dentro del proyecto de las Casas Baratas de Miralbueno. Al fondo se destacan la c‚Ēú‚ēĎpula de Santiago el Mayor, las dos torres y c‚Ēú‚ēĎpula central del templo del Pilar, y la torre de la Seo, adem‚Ēú√≠s del m‚Ēú√≠s cercano de la Previsi‚Ēú‚Ēān Social. Este gran espacio luego fue urbanizado y ordenado en nuevos viales denominados Bruno Solano, Andr‚Ēú¬ģs Piquer, Santa Teresa de Jes‚Ēú‚ēĎs, y plaza de San Francisco, denominaci‚Ēú‚Ēān impuesta a la prevista plaza de Espa‚Ēú‚Ėía como forma de solucionar la duplicidad una vez que a la antigua plaza de la Constituci‚Ēú‚Ēān el nuevo r‚Ēú¬ģgimen le impuso esa denominaci‚Ēú‚Ēān. Entre el mar de corporativas camisas azules destaca, en el centro de la escena, la albina zona conformada por las enfermeras falangistas.', 1938, 1938, 1938, 'Anos 30', 'UNIVERSIDAD', 41.63956500, -0.89510600, '0101000020E61000000E828E56B5A4ECBF47551344DDD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49972403028.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49972403028.webp', 'https://www.flickr.com/photos/zaragozaantigua/49972403028/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21501, 'Parque de Buena Vista 1927', 'Mar‚Ēú¬°n Chivite. 1927. En Zaragoza tambi‚Ēú¬ģn la lluvia es pertinaz, y cuando se pone, se pone, como cuando hubo que retrasar la "Fiesta automovilista" de octubre de ese a‚Ēú‚Ėío, despu‚Ēú¬ģs de los pilares, en terrenos "del que ha de ser futuro parque de Buena Vista" (sic). La cosa, organizada por la Real Asociaci‚Ēú‚Ēān Automovilista Aragonesa, consisti‚Ēú‚Ēā en una misa de campa‚Ēú‚Ėía y en la bendici‚Ēú‚Ēān ritual de todos y cada uno de los veh‚Ēú¬°culos asistentes. Fue una ceremonia de altura, con presencia del Capit‚Ēú√≠n General de la Regi‚Ēú‚Ēān Militar, el Gobernador Civil, y el Alcalde. Celebr‚Ēú‚Ēā un delegado del Prelado de la ciudad, y una banda de m‚Ēú‚ēĎsica sintoniz‚Ēú‚Ēā ambiental m‚Ēú‚ēĎsica sacra. Fue un ‚Ēú¬ģxito de cr‚Ēú¬°tica y p‚Ēú‚ēĎblico. En la imagen, aspecto del paseo central del futuro parque durante el desarrollo de la misa de campa‚Ēú‚Ėía en la semirrotonda final del paseo. Los coches, ordenadicos a la izquierda, y al fondo, el Huerva, el reciente puente sobre su cauce, y poca cosa m‚Ēú√≠s. En primer plano, rodilla en tierra del p‚Ēú‚ēĎblico asistente, en lo que hoy es la fuente cibern‚Ēú¬ģtica y la parte baja de la escalinata de acceso al Cabezo de Buena Vista. Fuente: "Arag‚Ēú‚Ēān : revista gr‚Ēú√≠fica de cultura aragonesa" (A‚Ēú‚Ėío III, N‚Ē¨‚ēĎ 26, noviembre 1927).', 1927, 1927, 1927, 'Anos 20', 'UNIVERSIDAD', 41.63440400, -0.89428200, '0101000020E6100000DCD8EC48F59DECBFCE39782634D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15481681297.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15481681297.webp', 'https://www.flickr.com/photos/zaragozaantigua/15481681297/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21551, 'Cabezo de Buena Vista 1922', 'Foto: Julio Requejo. Instant‚Ēú√≠nea en color tomada el 23 de enero de 1922 en el despu‚Ēú¬ģs Jard‚Ēú¬°n de Invierno del cabezo de Buena Vista de Zaragoza, con la gruta que encabezaba el paraje, entre las dos escaleras. Aunque el parque de Miguel Primo de Rivera se inaugur‚Ēú‚Ēā en 1929, el cabezo de Buena Vista era una zona de esparcimiento acondicionada desde hac‚Ēú¬°a d‚Ēú¬ģcadas. El lugar de la imagen ("La Gruta") fue el resultado del aprovechamiento de una gravera en la ladera del cabezo, convertida en refugio clim‚Ēú√≠tico en 1914. El aspecto actual se remonta a 1959. En primer plano, sentada en un banco, Rufina al sol, abrigada y elegante. Fuente visual: DARA/AHPZ.', 1922, 1922, 1922, 'Anos 20', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20757916724.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20757916724.webp', 'https://www.flickr.com/photos/zaragozaantigua/20757916724/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21610, 'Parque de Buenavista 1927', 'Plano del "Nuevo parque" proyectado en el cabezo de Buenavista y las huertas que se extend‚Ēú¬°an a sus pies hasta el r‚Ēú¬°o Huerva. Fue dise‚Ēú‚Ėíado por el ingeniero Mart‚Ēú¬°n Augusti. En 1929 fue inaugurado oficialmente por Miguel Primo de Rivera, que le dio su nuevo nombre. Fuente visual: www.flickr.com/photos/114031783@N02/', 1927, 1927, 1927, 'Anos 20', 'UNIVERSIDAD', 41.63445200, -0.89552300, '0101000020E6100000191BBAD91FA8ECBFDF701FB935D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29396651461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29396651461.webp', 'https://www.flickr.com/photos/zaragozaantigua/29396651461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22257, 'Fuente de Neptuno c.1966', 'En esta urbe, Neptuno ha sido durante varias d‚Ēú¬ģcadas, a su pesar, mercurial espectro p‚Ēú¬ģtreo, err‚Ēú√≠tico, vol‚Ēú√≠til, inestable, como recapitula Antonio Tausiet en tausiet.blogspot.com.es/2016/01/la-historia-errante-de-ne... La imagen capta su segunda juventud en el gran parque de la ciudad, aunque a su m‚Ēú¬°tica inmortalidad le importen bien poco las cosas de la edad. A la derecha, surge de la foresta la mole de la Casa Grande. Pero ‚Ēú¬ģl est‚Ēú√≠ bien donde est‚Ēú√≠, en redonda y acogedora plaza peatonal, en la imagen a‚Ēú‚ēĎn sin palmeras, ni argentinas cotorras, aunque s‚Ēú¬° con setos y parterres que hacen que el jard‚Ēú¬°n sea m‚Ēú√≠s franc‚Ēú¬ģs que ingl‚Ēú¬ģs. En la actualidad el c‚Ēú¬ģsped ha sustituido a los juegos florales. A la inmensa mayor‚Ēú¬°a zaragozana y forana le cae bien Neptuno, no en vano esta es una zona del parque donde se congrega mucha buena gente, pr‚Ēú√≠cticamente a todas las horas del d‚Ēú¬°a y aun la noche. Aunque de noche, algunas noches, descabezadas presencias enemigas la emprenden impunemente con el pobre Neptuno, y le quiebran los brazos, le roban el tridente, o se lo dejan averiado, sin poderes. Casi siempre, como consecuencia de los ataques, asemeja un dios que ya no rige ni gobierna sobre el acu‚Ēú√≠tico mundo. Est‚Ēú√≠ demediado, triste. Fuente: AYUNTAMIENTO DE ZARAGOZA/Archivo fotogr‚Ēú√≠fico ARRIBAS/Noviembre 196?', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63573200, -0.89657600, '0101000020E6100000A41CCC26C0B0ECBFA5828AAA5FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665421250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665421250.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665421250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25937, 'Tranv‚Ēú¬°a Academia 1969', 'Imagen capturada en la terminal de la tranviaria l‚Ēú¬°nea 10/Academia junto a la Academia General MIlitar, y centrada en el coche articulado n‚Ē¨‚ēĎ 251, entrado en servicio en 1959 como resultado de la reconstrucci‚Ēú‚Ēān de los antiguos coches n‚Ē¨‚ēĎ 92-93, y que termin‚Ēú‚Ēā un par de a‚Ēú‚Ėíos despu‚Ēú¬ģs en el desguace. A la derecha, su conductor.', 1969, 1969, 1969, 'Anos 60', NULL, 41.69851100, -0.86877800, '0101000020E61000004A7F2F8507CDEBBFB972F6CE68D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51834665450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51834665450.webp', 'https://www.flickr.com/photos/zaragozaantigua/51834665450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21612, 'Cabezo de Buenavista 1923', 'Imagen centrada en el emplazamiento del Monumento al rey Alfonso I el Batallador en lo alto del Cabezo de Buenavista, durante las tareas de construcci‚Ēú‚Ēān del pedestal sobre el que poco despu‚Ēú¬ģs se habr‚Ēú¬°a de instalar la estatua en m‚Ēú√≠rmol del cristiano monarca que conquist‚Ēú‚Ēā Saraqusta en 1118. Encargada en 1918 con motivo del centenario ocho de este evento, la estatua fue proyectada por el escultor Jos‚Ēú¬ģ Bueno. A comienzos de 1919 tuvo lugar el institucional acto de colocaci‚Ēú‚Ēān de la primera piedra del monumento, cuyo pedestal fue dise‚Ēú‚Ėíado por el arquitecto Miguel ‚Ēú√ľngel Navarro. La imagen fue realizada durante la instalaci‚Ēú‚Ēān del referido pedestal en la primavera de 1923, una entera legislatura despu‚Ēú¬ģs, y se habr‚Ēú¬°a tomado levemente escorada hacia la izquierda del frontal del monumento. Finalizado ya el escalonado pedestal y el prism‚Ēú√≠tico cuerpo inferior, se estaba comenzando a encajar las piedras del cuerpo cil‚Ēú¬°ndrico sobre el que se habr‚Ēú¬°a de colocar la estatua en octubre de ese a‚Ēú‚Ėío. En 1927 se instal‚Ēú‚Ēā finalmente el broc‚Ēú¬°neo le‚Ēú‚Ēān previsto, procedente de los talleres Averly. No consta que hubiera oficial inauguraci‚Ēú‚Ēān del monumento, tal vez por haberse dilatado tanto su terminaci‚Ēú‚Ēān respecto del evento al que se asociaba. En el Archivo Hist‚Ēú‚Ēārico Provincial de Zaragoza esta imagen todav‚Ēú¬°a se nos presenta referenciada con el desconcertante t‚Ēú¬°tulo: "Grupo de siete personas en la calle, bajo la torre mud‚Ēú¬ģjar de una iglesia, junto con un burro", y con el descriptor "Escenas rurales". Fuente visual: Archivo Gabriel Faci Abad, en AHPZ', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.63366800, -0.89337000, '0101000020E6100000D847A7AE7C96ECBFC84274081CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31141022308.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31141022308.webp', 'https://www.flickr.com/photos/zaragozaantigua/31141022308/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21613, 'C.‚Ē¨‚ēĎ de los Cubos c.1920', 'Posible posado de Manuel Hern‚Ēú√≠ndez, hijo de Gregorio Hern‚Ēú√≠ndez, seguramente autor de la foto, due‚Ēú‚Ėío de la f‚Ēú√≠brica de sombreros de la derecha, junto al brazal Bajo de la acequia de la Romareda, entre el Camino de los Cubos y el r‚Ēú¬°o Huerva, muy cerca del punto donde unos a‚Ēú‚Ėíos despu‚Ēú¬ģs comenzar‚Ēú√≠ el cubrimiento del primer tramo urbano de este r‚Ēú¬°o. Al fondo se ve la c‚Ēú‚ēĎpula de la iglesia de Santiago, y una torre del Pilar. A la espalda del fot‚Ēú‚Ēāgrafo, la trinchera del ferrocarril de Zaragoza a Barcelona.', 1920, 1920, 1920, 'Anos 20', 'UNIVERSIDAD', 41.64455700, -0.89106400, '0101000020E6100000FF9254A69883ECBF35B401D880D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31144527820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31144527820.webp', 'https://www.flickr.com/photos/zaragozaantigua/31144527820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21676, 'Ampliaci‚Ēú‚Ēān suroeste 1932', 'Vista a‚Ēú¬ģrea de la Gran V‚Ēú¬°a. En la esquina superior izquierda, el paseo de Sagasta. En la superior derecha, la prevista plaza de Espa‚Ēú‚Ėía. En el centro, el recinto ferial habilitado durante las fiestas mayores de octubre. Al comienzo de la Gran V‚Ēú¬°a, la explanada de los Campos El‚Ēú¬°seos, con los restos del antiguo vel‚Ēú‚Ēādromo. Y cruzando en curva, la trinchera del tren sin cubrir.', 1932, 1932, 1932, 'Anos 30', 'UNIVERSIDAD', 41.64411200, -0.89184400, '0101000020E61000004948A46DFC89ECBF077B134372D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14846214539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14846214539.webp', 'https://www.flickr.com/photos/zaragozaantigua/14846214539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21697, 'Plaza de Espa‚Ēú‚Ėía a‚Ēú‚Ėíos 30', 'Grupo de chavales jugando al f‚Ēú‚ēĎtbol en una explanada en el entorno de la proyectada plaza de Espa‚Ēú‚Ėía. Al fondo a la derecha, edificio de viviendas entre las calles de las Cortes de Arag‚Ēú‚Ēān y de Baltasar Graci‚Ēú√≠n. El edificio formaba parte del proyecto de ensanche de Miralbueno de 1928, como manzana de "Casas Baratas". Fue proyectado por Zuazo, Navarro y Ribas, y construido en 1930.', 1930, 1930, 1939, 'Anos 30', 'UNIVERSIDAD', 41.64065500, -0.89426500, '0101000020E610000059A31EA2D19DECBF6B82A8FB00D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15465921496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15465921496.webp', 'https://www.flickr.com/photos/zaragozaantigua/15465921496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21745, 'Gran V‚Ēú¬°a 1931', 'Durante la madrugada del 19 de marzo, se declar‚Ēú‚Ēā un incendio en la f‚Ēú√≠brica de sombreros de Manuel Hern‚Ēú√≠ndez y Compa‚Ēú‚Ėí‚Ēú¬°a, localizada en el camino de los Cubos n‚Ē¨‚ēĎ 275. Edificio, instalaciones y maquinaria quedaron en situaci‚Ēú‚Ēān de siniestro total, y los cien obreros empleados, sin trabajo. Esta antigua f‚Ēú√≠brica formaba parte del complejo industrial de Miralbueno, entre el Camino de los Cubos y la acequia de la Romareda a un lado, una pronunciada curva del r‚Ēú¬°o Huerva a sus espaldas, y la v‚Ēú¬°a del ferrocarril MZA. Muy cerca quedaba la f‚Ēú√≠brica de espejos "La Veneciana", la de aparatos de precisi‚Ēú‚Ēān "Amado Laguna de Rins", "Fundici‚Ēú‚Ēān Pellicer y Juan", "f‚Ēú√≠brica de hielo Archanco"... El cubrimiento del r‚Ēú¬°o Huerva en su tramo urbano, unos a‚Ēú‚Ėíos antes, hab‚Ēú¬°a puesto a esta f‚Ēú√≠brica en un aprieto, pues quedaba casi en medio de la proyectada y espaciosa nueva "Gran V‚Ēú¬°a", que se deten‚Ēú¬°a justo en sus inmediaciones. La imagen tras el incendio est‚Ēú√≠ capturada, precisamente, desde la Gran V‚Ēú¬°a. En la parte superior derecha, apenas queda en pie la parte del muro con la "S" final del gran r‚Ēú‚Ēātulo "F‚Ēú√≠brica de sombreros". Declarada en ruina, fue derribada tiempo despu‚Ēú¬ģs. La urbanizaci‚Ēú‚Ēān de la Gran V‚Ēú¬°a continu‚Ēú‚Ēā, como "paseo de Fernando el Cat‚Ēú‚Ēālico", y a comienzos de la d‚Ēú¬ģcada de los 50 del pasado siglo, en los restos de su solar se levant‚Ēú‚Ēā una nueva manzana de viviendas. Fuente visual: Foto Palacio ("La Uni‚Ēú‚Ēān Ilustrada", M‚Ēú√≠laga).', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.64472200, -0.89110300, '0101000020E610000076C24B70EA83ECBF8081204086D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21880500090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21880500090.webp', 'https://www.flickr.com/photos/zaragozaantigua/21880500090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21747, 'Casas Baratas Miralbueno 1935', 'Imagen del proyectado conjunto iglesia-convento de los carmelitas descalzos, desde el interior de una de las manzanas con nuevas viviendas baratas de la Sociedad Zaragozana de Urbanizaci‚Ēú‚Ēān y Construcci‚Ēú‚Ēān, junto al Huerva, en el ensanche de Miralbueno. A la izquierda, las casas recayentes al vial luego denominado "Sta. Teresa de Jes‚Ēú‚ēĎs". Al fondo, las de la calle "Agust‚Ēú¬°n de Quinto". A la derecha, las traseras de "Ram de Viu". De las originales 13 casas proyectadas para esta manzana, subsisten de alguna forma 7 de ellas. Fuente: Foto Mar‚Ēú¬°n Chivite, "Mundo Gr‚Ēú√≠fico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63962300, -0.89376400, '0101000020E6100000D8F2CAF5B699ECBF7C629D2ADFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22002804332.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22002804332.webp', 'https://www.flickr.com/photos/zaragozaantigua/22002804332/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21748, 'Bruno Solano 1935', 'Imagen de conjunto de una manzana de recientes viviendas de la Sociedad Zaragozana de Urbanizaci‚Ēú‚Ēān y Construcci‚Ēú‚Ēān, levantadas en 1928 junto al Huerva, en el ensanche de Miralbueno, seg‚Ēú‚ēĎn proyecto de Miguel ‚Ēú√ľngel Navarro y Secundino Zuazo. Estaba ubicada en una nueva zona de urbanizaci‚Ēú‚Ēān de la ciudad, en torno a una gran plaza denominada "de Espa‚Ēú‚Ėía", en cuyas proximidades se estaba construyendo el Campus Universitario. En este caso, la imagen captura la manzana 44, proyectada por Zuazo, y delimitada por los viales luego denominados "Bruno Solano", que cruza en primer plano de derecha a izquierda; "Sta. Teresa de Jes‚Ēú‚ēĎs", enfrente, por el que se accede a las viviendas"; "Agust‚Ēú¬°n de Quinto", a la izquierda,entre las viviendas y el malogrado complejo conventual de los Carmelitas Descalzos; y Ram de Viu, por las traseras. De las originales 13 casas proyectadas para esta manzana, subsisten (de alguna forma) 7 de ellas. Fuente: Foto Mar‚Ēú¬°n Chivite, "Mundo Gr‚Ēú√≠fico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63945200, -0.89420500, '0101000020E6100000056EDDCD539DECBF4FAE2990D9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22016210835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22016210835.webp', 'https://www.flickr.com/photos/zaragozaantigua/22016210835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21833, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1935', 'Membrete comercial de la harinera "La Imperial de Arag‚Ēú‚Ēān", propiedad de Rubio y Margalejo S.L., sucesores del negocio de Manuel Monares, sucesor a su vez de Valls y Garmendia, y ‚Ēú¬ģstos de Palomar, Mend‚Ēú¬°vil y Baselga, que impulsaron esta factor‚Ēú¬°a harinera a mediados de los a‚Ēú‚Ėíos 60 del siglo XIX. El dibujo de la f‚Ēú√≠brica presenta la reconocible (y superviviente) fachada pincipal, remodelada en los a‚Ēú‚Ėíos 20 por Miguel ‚Ēú√ľngel Navarro, recayente al paseo del Canal, por donde una derivaci‚Ēú‚Ēān de agua surt‚Ēú¬°a a la f‚Ēú√≠brica, que se vertebraba en torno a un peque‚Ēú‚Ėío patio central, con naves de una, dos y tres alturas, en funci‚Ēú‚Ēān de los acusados desniveles del terreno. A la derecha, el paseo de Ruise‚Ēú‚Ėíores. Al fondo, representaci‚Ēú‚Ēān idealizada y fant‚Ēú√≠stica de Zaragoza, pues aparece el Pilar y la Seo. Esta f‚Ēú√≠brica se mantuvo activa hasta principios de los a‚Ēú‚Ėíos 80 del pasado siglo. Fuente visual: colecci‚Ēú‚Ēān de Enrique Baile, en Gran Archivo Zaragoza Antigua (GAZA).', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63413000, -0.89098500, '0101000020E6100000FB3F87F9F282ECBFCCB4FD2B2BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33440031750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33440031750.webp', 'https://www.flickr.com/photos/zaragozaantigua/33440031750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21902, 'Ferial 1939', 'Imagen capturada desde cierta altura en el ferial de atracciones instalado durante las Fiestas del Pilar del a‚Ēú‚Ėío 1939 (oficialmente denominado por el r‚Ēú¬ģgimen "A‚Ēú‚Ėío de la Victoria") en el Campo de la Victoria, despejado entorno de la nueva plaza de San Francisco (antes de Espa‚Ēú‚Ėía), donde la actual calle de Bruno Solano. Hacia el fondo, el arbolado paseo de Fernando el Cat‚Ēú‚Ēālico (antes avenida de Francisco Giner de los R‚Ēú¬°os), y las pioneras manzanas 49 y 50 de Casas Baratas del ensanche de Miralbueno, finalizadas a principios de la d‚Ēú¬ģcada con proyecto del arquitecto Secundino Zuazo Ugalde (delimitadas actualmente entre las calles de Cortes de Arag‚Ēú‚Ēān, Corona de Arag‚Ēú‚Ēān, Baltasar Graci‚Ēú√≠n y avenida de Goya). Al fondo y hacia la derecha, la torre de San Pablo y la c‚Ēú‚ēĎpula de la iglesia de Santiago el Mayor se‚Ēú‚Ėíalan la distancia de la ciudad consolidada.', 1939, 1939, 1939, 'Anos 30', 'UNIVERSIDAD', 41.63962100, -0.89517100, '0101000020E6100000D57B2AA73DA5ECBFDB6AD619DFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51470891212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51470891212.webp', 'https://www.flickr.com/photos/zaragozaantigua/51470891212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21936, 'Grupo Francisco Caballero 1946', 'AHPZ. Estudio Coyne. La manzana entre las calles Andr‚Ēú¬ģs Piquer, Santa Teresa, Luis Vives y Bruno Solano, configura el denominado "Grupo Francisco Caballero" de 113 viviendas protegidas, con proyecto de Jos‚Ēú¬ģ de Yarza Garc‚Ēú¬°a y Alejandro Allanegui P‚Ēú¬ģrez, finalizadas en 1946. Imagen tomada desde la calle Bruno Solano, en un entorno que se estaba edificando. Al fondo, la calle Luis Vives con las tapias de la Editorial Vives.', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63934000, -0.89474200, '0101000020E6100000B9718BF9B9A1ECBF2783A3E4D5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15194622218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15194622218.webp', 'https://www.flickr.com/photos/zaragozaantigua/15194622218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22033, 'Calle de Toledo 1941', 'Imagen capturada en el primer tramo de la calle de Toledo, comprendido entre las calles de Burgos y la de Salamanca, y centrada en los inmuebles en construcci‚Ēú‚Ēān de los n‚Ēú‚ēĎmeros 4, 6 y 8. Esta despejada zona que se extend‚Ēú¬°a entre la estaci‚Ēú‚Ēān de Cari‚Ēú‚Ėíena y la carretera de Valencia se convirti‚Ēú‚Ēā a finales de los a‚Ēú‚Ėíos veinte en el emplazamiento del Circo Krone, de forma que cuando fue urbanizada tras la guerra civil de 1936-1939 se le dio el nombre no oficial y provisional de "urbanizaci‚Ēú‚Ēān Circo Krone" para que la gente de la ‚Ēú¬ģpoca pudiera ubicarla. De esta forma, fueron trazadas las calles de Salamanca, Toledo, ‚Ēú√ľvila y Burgos (un homenaje a algunas de las capitales de provincia que secundaron desde el minuto uno el golpe de Estado del 18 de julio de 1936), y la iniciativa privada se encarg‚Ēú‚Ēā de la promoci‚Ēú‚Ēān inmobiliaria de las viviendas y bajos comerciales, con precios de venta al p‚Ēú‚ēĎblico de 225.000 pesetas la casa entera (como anuncia el cartel de primer t‚Ēú¬ģrmino, a la derecha) y 20.000 el piso...', 1941, 1941, 1941, 'Anos 40', 'UNIVERSIDAD', 41.64776700, -0.89573900, '0101000020E6100000490ED8D5E4A9ECBFCA367007EAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52201208707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52201208707.webp', 'https://www.flickr.com/photos/zaragozaantigua/52201208707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22059, 'Puente de los Gitanos 1951', 'Ayuntamiento de Zaragoza/Archivo Mora. Junio 1951. "Calle de Juan Pablo Bonet. Puente sobre el R‚Ēú¬°o Huerva". Este puente se denomin‚Ēú‚Ēā originalmente "de la V‚Ēú¬°a Transversal", por estar situado en una nueva calle que enlazaba el ensanche de Miralbueno con el paseo de Sagasta. Se construy‚Ēú‚Ēā donde antes hubo una pasarela de hierro y madera, denominada de "Castillo" por enlazar la f‚Ēú√≠brica as‚Ēú¬° denominada, con el Camino del S‚Ēú√≠bado. Se comenzaron las obras del puente el 1 de febrero de 1932. Cost‚Ēú‚Ēā al Ayuntamiento 800.000 pts., y fue inaugurado sin ceremonia oficial el 1 de septiembre de 1933. Su construcci‚Ēú‚Ēān, hecha por la Sociedad "Angel A‚Ēú¬°sa y Hermano", es mixta de sillarejo de piedra de Calatorao en pilas y tajamares, y hormig‚Ēú‚Ēān armado. Est‚Ēú√≠ formado por 3 tableros que configuran un espacio de 52 m. de largo, y 20 m. de ancho (12 para calzada y 4 para cada acera). Con el tiempo, ese nombre cay‚Ēú‚Ēā en el olvido, y la gente comenz‚Ēú‚Ēā a llamarlo "de los gitanos" porque en los a‚Ēú‚Ėíos 40 y 50 n‚Ēú‚Ēāmadas de ese pueblo a su paso por Zaragoza acampaban temporalmente bajo ‚Ēú¬ģl. En los a‚Ēú‚Ėíos 60, cuando la zona estaba ya bastante urbanizada, a caballo entre el paseo del General Mola y el paseo de Fernando el Cat‚Ēú‚Ēālico, se le dio oficialmente el imperial nombre de "puente del Emperador Augusto", aunque el nombre no cal‚Ēú‚Ēā entre la gente, para cabreo de la Zaragoza oficialista. Hasta nuestros d‚Ēú¬°as.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64077500, -0.88974700, '0101000020E610000001DA56B3CE78ECBF158C4AEA04D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14931198266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14931198266.webp', 'https://www.flickr.com/photos/zaragozaantigua/14931198266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22126, '&quot;V‚Ēú¬°a Verde&quot; 1959', 'Imagen de las obras de establecimiento de la doble v‚Ēú¬°a ferroviaria entre las estaciones de Campo Sepulcro y Miraflores, 3.7 kil‚Ēú‚Ēāmetros de "zanja" que pronto se convertir‚Ēú¬°a en "trinchera" mental. Al fondo, el puente con t‚Ēú‚ēĎnel bajo el paseo de Calvo Sotelo. Desde all‚Ēú¬° proven‚Ēú¬°an los directos a Barcelona que paraban en Campo Sepulcro; daba continuidad rodada hacia el paseo de Fernando el Cat‚Ēú‚Ēālico, a la izquierda; y permit‚Ēú¬°a al brazal bajo de la acequia de la Romareda seguir su antiguo fluir hacia el "centro", a la derecha. El puente bajo el que se ha capturado esta imagen era denominado "de la V‚Ēú¬°a Verde" desde su construcci‚Ēú‚Ēān all‚Ēú√≠ por 1911, y estaba tendido junto a la margen izquierda del r‚Ēú¬°o Huerva, permitiendo la continuidad de tr‚Ēú√≠nsito por la ribera, en forma de paseo, desde el puente de la V‚Ēú¬°a Perimetral, o del Emperador Augusto, o de los Gitanos, m‚Ēú√≠s al sur. Fuente visual: AMZ.', 1959, 1959, 1959, 'Anos 50', 'UNIVERSIDAD', 41.64390100, -0.89126900, '0101000020E61000003509DE904685ECBF4C6E14596BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23121869781.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23121869781.webp', 'https://www.flickr.com/photos/zaragozaantigua/23121869781/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22131, 'P.‚Ē¨‚ēĎ de Fernando el Cat‚Ēú‚Ēālico c.1955', '"Zaragoza. Avenida Fernando el Cat‚Ēú‚Ēālico". Un ins‚Ēú‚Ēālito vistazo desde las alturas del n‚Ē¨‚ēĎ 34 del paseo de Calvo Sotelo, muy despejado antes de la construcci‚Ēú‚Ēān de la macizada manzana entre Dato-Doctor Cerrada-Calvo Sotelo, en direcci‚Ēú‚Ēān hacia Fernando el Cat‚Ēú‚Ēālico. Los huecos entre edificios se corresponden con solares a‚Ēú‚ēĎn sin edificar, en una zona de la ciudad que entonces parec‚Ēú¬°a muy lejana del "centro", y resultaba dif‚Ēú¬°cil pensar que la ciudad llegara a extenderse mucho m‚Ēú√≠s en esta direcci‚Ēú‚Ēān. En primer t‚Ēú¬ģrmino, a la derecha, el desemboque de la calle Ricla en la de Doctor Cerrada. Casi en el centro de la imagen, y tras la trinchera del ferrocarril de los directos Madrid-Barcelona, la esquina achaflanada del cine "Gran V‚Ēú¬°a". Al fondo, a la izquierda, emerge borrosa la torre del recinto de la Feria de Muestras. Un tranv‚Ēú¬°a de la l‚Ēú¬°nea 11 "Parque" regresa hacia la plaza de Espa‚Ēú‚Ėía. Fuente visual: Editorial Garrabella www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.64532400, -0.89071700, '0101000020E61000002CB81FF0C080ECBF76A911FA99D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23761608172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23761608172.webp', 'https://www.flickr.com/photos/zaragozaantigua/23761608172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22193, 'Puente F.C. sobre Huerva 1959', 'Imagen capturada durante las obras de establecimiento de la doble v‚Ēú¬°a ferroviaria entre las estaciones de Campo Sepulcro y Miraflores (l‚Ēú¬°nea de Barcelona), y centrada en el desdoble del puente del ferrocarril sobre el r‚Ēú¬°o Huerva. Se ha terminado de asegurar la primera de las nuevas plataformas sobre las que luego se instalar‚Ēú√≠ el tendido ferroviario. A su inmediata izquierda, el paso antiguo, con los protectores laterales, que ser‚Ēú√≠ posteriormente desmantelado. Cuando la obra est‚Ēú¬ģ finalizada, todo ser‚Ēú√≠ soterrado. Al fondo, y a la izquierda, vista de la pasarela peatonal de la calle Zumalac‚Ēú√≠rregui. En el centro de la imagen, antiguas parcelas recayentes a esa calle Fuente visual: Archivo Municipal de Zaragoza.', 1959, 1959, 1959, 'Anos 50', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32807286703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32807286703.webp', 'https://www.flickr.com/photos/zaragozaantigua/32807286703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22199, 'Puente de la V‚Ēú¬°a Verde 1959', 'Imagen capturada durante las obras de establecimiento de la doble v‚Ēú¬°a ferroviaria entre las estaciones de Campo Sepulcro y Miraflores (l‚Ēú¬°nea de Barcelona), y centrada en el puente de la V‚Ēú¬°a Verde, construido en 1911 junto a la margen izquierda del r‚Ēú¬°o Huerva, y que daba continuidad de tr‚Ēú√≠nsito por la ribera, en forma de paseo, desde el puente de la V‚Ēú¬°a Perimetral, o del Emperador Augusto, o de los Gitanos, m‚Ēú√≠s al sur, hasta el paseo de Calvo Sotelo. A la derecha, por donde se realiza el ensanchamiento de la zanja, y arriba, al nivel de la calle, el Instituto Nacional de Ense‚Ēú‚Ėíanza Media √Ē√á¬£Goya√Ē√á√ė estaba a punto de ser inaugurado oficialmente. Un poco m‚Ēú√≠s adelante, a la izquierda del caminante entre los ra‚Ēú¬°les, el tendido ferroviario salva el r‚Ēú¬°o Huerva mediante un puentecillo que tambi‚Ēú¬ģn ser‚Ēú√≠ desdoblado. Al fondo, brumoso panorama de la margen derecha del r‚Ēú¬°o, en el entorno de las calles de Moriones, Benavente, y el camino del S‚Ēú√≠bado. Posteriormente, todo este espacio ser‚Ēú√≠ cubierto, y desde 2012 aqu‚Ēú¬° se encuentra la estaci‚Ēú‚Ēān ferroviaria de Zaragoza-Goya, para servicios de cercan‚Ēú¬°as, y media distancia. Fuente visual: Archivo Municipal de Zaragoza.', 1959, 1959, 1959, 'Anos 50', 'UNIVERSIDAD', 41.64369600, -0.89071700, '0101000020E61000002CB81FF0C080ECBF73486AA164D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33554752576.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33554752576.webp', 'https://www.flickr.com/photos/zaragozaantigua/33554752576/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22243, 'C‚Ē¨‚ēĎ del S‚Ēú√≠bado c.1955', 'Imagen capturada desde la altura de una antigua parcela del lado de los pares del camino del S‚Ēú√≠bado poco despu‚Ēú¬ģs del cruce con la calle de la Luz, que en esta fotograf‚Ēú¬°a aparece luminosa en el centro de la escena formando una "replaceta" donde confluyen tanto el camino del S‚Ēú√≠bado, desde la izquierda, como la calle de Anselmo Gasc‚Ēú‚Ēān de Gotor desde el fondo y por la derecha, tras pasar por la calle del Porvenir. A la derecha e inmediato, reciente inmueble esquinero entre el camino y la calle de la Luz. A la sombra y en el centro del terroso camino, luego redenominado calle del Arzobispo Dom‚Ēú¬ģnech y finalmente desdoblado como calle del Arzobispo Morcillo, vecinos de la Explanada del S‚Ēú√≠bado en torno a una orquesta durante las fiestas de la barriada.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63829800, -0.88967800, '0101000020E6100000E00F3FFF3D78ECBF158DB5BFB3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51267739476.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51267739476.webp', 'https://www.flickr.com/photos/zaragozaantigua/51267739476/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22244, 'C.‚Ē¨‚ēĎ del S‚Ēú√≠bado c.1957', 'Imagen capturada en el tramo del camino del S‚Ēú√≠bado inmediato al espacio donde a la izquierda y fuera de plano estaba prevista la construcci‚Ēú‚Ēān del Grupo Salduba, con el despejado aspecto de campos de cultivo y torre agr‚Ēú¬°cola entre el riego del S‚Ēú√≠bado y la trinchera del r‚Ēú¬°o Huerva. Al fondo y tras el parque de Primo de Rivera, despunta la torre-mirador de la Feria Nacional de Muestras. A la derecha, traseras de las viviendas proyectadas por el arquitecto Antonio Ch‚Ēú‚Ēāliz Alcrudo en la calle del Arzobispo Apaolaza, y la ampliaci‚Ēú‚Ēān de la Editorial Luis Vives S.A.', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.63713500, -0.89288500, '0101000020E6100000C3D842908392ECBF8811C2A38DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51311705514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51311705514.webp', 'https://www.flickr.com/photos/zaragozaantigua/51311705514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22245, 'Casas baratas Huerva c.1957', 'Imagen capturada desde las traseras de una antigua parcela del lado de los pares del camino del S‚Ēú√≠bado poco despu‚Ēú¬ģs del cruce con la calle de la Luz. Tras los ‚Ēú√≠rboles y las parcelas de primer t‚Ēú¬ģrmino que en descenso llevan hasta la trinchera del r‚Ēú¬°o Huerva, pasando por las calles de Mario Lasala Vald‚Ēú¬ģs y la propia del R‚Ēú¬°o Huerva, vista excepcional a la derecha de las naves industriales de la antigua f‚Ēú√≠brica textil de los Hijos de C‚Ēú√≠ndido Castillo, al otro lado del r‚Ēú¬°o y ribere‚Ēú‚Ėía a ‚Ēú¬ģl. Despu‚Ēú¬ģs, viviendas de las Casas Baratas del Huerva recayentes a la calle de Domingo y Francisco La Ripa, y vista de las incipientes construcciones en el entorno de la calle de San Juan de la Cruz, donde destaca la torre de la parroquia del Carmen y de San Jos‚Ēú¬ģ, entre las calles de Luis Ram de Viu y de Santa Teresa de Jes‚Ēú‚ēĎs.', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.64044700, -0.89141600, '0101000020E61000004432E4D87A86ECBF21E9D32AFAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51317689291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51317689291.webp', 'https://www.flickr.com/photos/zaragozaantigua/51317689291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22368, 'Avenida de Goya c.1966', 'Postal. Ediciones Arribas. Vista de la avenida de Goya en el cruce con los paseos de Calvo Sotelo y de Fernando el Cat‚Ēú‚Ēālico. El aparcamiento en superficie del primer t‚Ēú¬ģrmino est‚Ēú√≠ feliz y actualmente ocupado por la estaci‚Ēú‚Ēān ferroviaria de cercan‚Ēú¬°as Zaragoza-Goya.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.64390100, -0.89126900, '0101000020E61000003509DE904685ECBF4C6E14596BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21445166159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21445166159.webp', 'https://www.flickr.com/photos/zaragozaantigua/21445166159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22379, 'Vista a‚Ēú¬ģrea Parque Grande 1964', 'Vista a‚Ēú¬ģrea del parque Primo de Rivera, con el Cabezo de Buenavista y su Jard‚Ēú¬°n de Invierno. Al fondo la Residencia Sanitaria Jos‚Ēú¬ģ Antonio o Casa Grande y el barrio de la Romareda. Fuente: Colecci‚Ēú‚Ēān Rafael Margal‚Ēú¬ģ.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22303469792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22303469792.webp', 'https://www.flickr.com/photos/zaragozaantigua/22303469792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22388, 'Padre Claret c.1960', 'Imagen de la trinchera del ferrocarril de los directos Madrid-Barcelona procedente de la estaci‚Ēú‚Ēān de Campo Sepulcro, en la zona entre los paseos de Teruel (a la espalda) y el de Calvo Sotelo (girando al fondo, hacia la izquierda). A ambos lados de este tramo se les denominaba "Padre Antonio Mar‚Ēú¬°a Claret". La imagen ha sido capturada desde uno de los pasos peatonales que salvaban la trinchera, a la altura de la calle Antonio C‚Ēú√≠novas. Delante est‚Ēú√≠ el que comunicaba los dos tramos dispares de la calle del Carmen. M‚Ēú√≠s adelante, al fondo, destaca reci‚Ēú¬ģn terminado el nuevo e imponente "Templo o Santuario del Coraz‚Ēú‚Ēān de Mar‚Ēú¬°a", de la Congregaci‚Ēú‚Ēān de los Misioneros Hijos del Inmaculado Coraz‚Ēú‚Ēān de Mar‚Ēú¬°a, o "Claretianos". Unos pocos a‚Ēú‚Ėíos m‚Ēú√≠s tarde, este entorno sufrir‚Ēú√≠ una interesante metamorfosis cuando se proceda al soterramiento de las v‚Ēú¬°as del tren, y el nuevo vial resultante sea denominado "Avenida de Goya", como otra nueva gran v‚Ēú¬°a para el tr‚Ēú√≠fico rodado. De rebote, la preexistente calle de Goya, continuacion de la de Contamina, deber‚Ēú√≠ ser redenominada como "Juseppe Mart‚Ēú¬°nez".', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.64645900, -0.89370000, '0101000020E610000029ED0DBE3099ECBF399A232BBFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22713941820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22713941820.webp', 'https://www.flickr.com/photos/zaragozaantigua/22713941820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22393, 'Avenida Goya 1966', 'Obras de construcci‚Ēú‚Ēān de la avenida de Goya, soterrando las v‚Ēú¬°as del ferrocarril, que en este punto pasan sobre el r‚Ēú¬°o Huerva. Al fondo, el Instituto Goya. Fuente visual: Foto Leonardo P‚Ēú¬ģrez Obis, donada por ‚Ēú√ľngel Hern‚Ēú√≠ndez Mostajo para www.rafaelcastillejo.com', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22755427039.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22755427039.webp', 'https://www.flickr.com/photos/zaragozaantigua/22755427039/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22419, 'Parque Grande c.1967', 'Nocturna imagen, con vista desde el Cabezo de Buenavista, del acceso al parque Primo de Rivera por el puente del trece de setiembre, convertida en entra‚Ēú‚Ėíable postal por la Editorial Garc‚Ēú¬°a Garrabella. Al fondo, los grandes hitos de la moderna ciudad en esta alejada zona del centro: la "Residencia Sanitaria Jose Antonio", el campo municipal de la Romareda, y el recinto de la Feria de Muestras. Junto al aparcado veh‚Ēú¬°culo, unos a‚Ēú‚Ėíos despu‚Ēú¬ģs ser‚Ēú√≠ reinstalada la maravillosa fuente luminosa de la plaza de Para‚Ēú¬°so, cuando la convivencia con el tr‚Ēú√≠fico rodado a motor de explosi‚Ēú‚Ēān sea insostenible. Por eso, para la mayor‚Ēú¬°a de ciudadanos, este lugar, el Parque, es una especie de "vertedero", o "contenedor" de lo que la ciudad expulsa. Una especie de exilio. Que le pregunten a la fuente d‚Ēú‚Ēānde querr‚Ēú¬°a estar. Fuente: www.ebay.es/', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.63440400, -0.89428200, '0101000020E6100000DCD8EC48F59DECBFCE39782634D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26304391624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26304391624.webp', 'https://www.flickr.com/photos/zaragozaantigua/26304391624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22421, 'Parque Primo de Rivera c.1968', 'Fuentes del paseo de San Sebasti‚Ēú√≠n del parque Primo de Rivera. Fuente: Foto para postal de Comercial Josan. Cesi‚Ēú‚Ēān de la familia de Jos‚Ēú¬ģ Mar‚Ēú¬°a Sanz Gonz‚Ēú√≠lez a Rafael Castillejo. Dataci‚Ēú‚Ēān y procesado:', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.63543000, -0.89545700, '0101000020E61000003C2D3F7095A7ECBFDA722EC555D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27142460830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27142460830.webp', 'https://www.flickr.com/photos/zaragozaantigua/27142460830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22484, 'Calle de Benavente 1968', 'Imagen capturada al final de la calle de Benavente durante las obras de urbanizaci‚Ēú‚Ēān del entorno de la moderna avenida de Goya. A la derecha e inmediatos, pronunciados desniveles y terraplenes que descienden hacia el r‚Ēú¬°o Huerva desde un estrecho vial a‚Ēú‚ēĎn sin nombre que conduce, al fondo, a las ruinas de la antigua f‚Ēú√≠brica de curtidos "La Progresiva", en un ramal del que fuera camino del S‚Ēú√≠bado. A la izquierda y vecinos del moderno gran bloque esquinero que centra la imagen, perduran algunas de las antiguas parcelas de la zona, e incluso parece destacarse la chimenea de la vieja f‚Ēú√≠brica de tejidos de punto de Santiago Vicente, tambi‚Ēú¬ģn en el antiguo camino del S‚Ēú√≠bado, en un tramo ya redenominado calle del Arzobispo Dom‚Ēú¬ģnech. Fuente visual: AMZ.', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.64313500, -0.89003000, '0101000020E610000025AFCE31207BECBFDCF4673F52D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40148132124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40148132124.webp', 'https://www.flickr.com/photos/zaragozaantigua/40148132124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22503, 'Carmelitas, c.1965', 'Imagen centrada en la iglesia parroquial de San Juan de la Cruz, de la orden de los carmelitas descalzos de San Jos‚Ēú¬ģ, establecida desde 1945 en el n‚Ē¨‚ēĎ 8 de esta hom‚Ēú‚Ēānima calle, entre las calles de Ram de Viu (a la izquierda), y la de Santa Teresa de Jes‚Ēú‚ēĎs (a la derecha).', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64106400, -0.89252100, '0101000020E61000006DC83F33888FECBF4C5299620ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49918928306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49918928306.webp', 'https://www.flickr.com/photos/zaragozaantigua/49918928306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22577, 'Calvo Sotelo c.1975', 'Postal Comercial Jos‚Ēú√≠n. Vista del paseo de Calvo Sotelo en su confluencia con la Avenida Goya, tomada desde Fernando el Cat‚Ēú‚Ēālico.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.64436600, -0.89170300, '0101000020E6100000C3D7D7BAD488ECBFC153C8957AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15536105155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15536105155.webp', 'https://www.flickr.com/photos/zaragozaantigua/15536105155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22581, 'Padres Pa‚Ēú‚ēĎles 1973', 'Archivo Municipal. Gerardo Sancho Ramo. 25/02/1973. Imagen del piqueteo del Convento-Residencia de los Padres Pa‚Ēú‚ēĎles de la Avenida de Goya, en la manzana entre el Paseo de Teruel y la calle de C‚Ēú√≠novas. La valla se‚Ēú‚Ėíala el punto desde el que las v‚Ēú¬°as del ferrocarril estaban ya soterradas desde 1960. La Congregaci‚Ēú‚Ēān de la Misi‚Ēú‚Ēān, llamada en Espa‚Ēú‚Ėía de los PP. Pa‚Ēú‚ēĎles, se estableci‚Ēú‚Ēā en esta ubicaci‚Ēú‚Ēān de Zaragoza en 1924, cuando el Paseo de Teruel era la "Carretera de Zaragoza a Teruel", como Casa Principal de la ciudad. Vendieron la titularidad del terreno en 1972 por motivos econ‚Ēú‚Ēāmicos, y sobre el solar se edificaron los actuales bloques de viviendas del n‚Ēú‚ēĎmero 96 de la avenida de Goya. Fuente Visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64744300, -0.89359300, '0101000020E6100000A7E7DD585098ECBF17838769DFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15584999125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15584999125.webp', 'https://www.flickr.com/photos/zaragozaantigua/15584999125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22607, 'Calle Santander 1970', 'Imagen un tanto encharcada de la calle de Santander en su parte m‚Ēú√≠s cercana al pretil y paso sobre las v‚Ēú¬°as del ferrocarril. El aparente marasmo circulatorio no es tal: los veh‚Ēú¬°culos est‚Ēú√≠n aparcados seg‚Ēú‚ēĎn una ordenaci‚Ēú‚Ēān flexible, abierta, y tolerante, que se beneficia de la ausencia, precisamente, de tr‚Ēú√≠fico rodado. Al otro lado de las v‚Ēú¬°as, Anselmo Clav‚Ēú¬ģ presenta el tel‚Ēú‚Ēān de fondo del antiguo edificio de la Casa de Convalecientes, que desde finales de los a‚Ēú‚Ėíos cincuenta estaba ocupado por el Colegio Polit‚Ēú¬ģcnico Nuestra Se‚Ēú‚Ėíora del Pilar. Por encima, sobresalen los grandes bloques del paseo de Teruel, que en poco tiempo tendr‚Ēú¬°an unos replicantes sobre el solar de este interesante edificio dise‚Ēú‚Ėíado por Julio Bravo. Interesante, pero antiguo, y peque‚Ēú‚Ėío. Muy peque‚Ēú‚Ėío. Fuente visual: Archivo P‚Ēú‚ēĎblico Municipal.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64878500, -0.89362600, '0101000020E6100000965E9B8D9598ECBF53910A630BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19023617963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19023617963.webp', 'https://www.flickr.com/photos/zaragozaantigua/19023617963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22691, 'Julio Cejador Frauca 1977', 'Imagen de la calle Julio Cejador Frauca (antiguo Camino Viejo de Cuarte), capturada casi ya desde el paseo de Mariano Renovales, con una interesante visual del periurbano y solariego estado de las cosas desde este punto y hasta la parcela del n‚Ēú‚ēĎmero 10-12, donde una d‚Ēú¬ģcada despu‚Ēú¬ģs se abrir‚Ēú√≠ un nuevo vial denominado "Los Jilgueros". A la derecha, inmediatas, las traseras de la veterana harinera "La Imperial", con notable fachada al Canal Imperial, unos metros m‚Ēú√≠s arriba. Al fondo, el arranque de esta calle desde el paseo de Ruise‚Ēú‚Ėíores, en el punto de acceso al modernizado complejo del "Colegio Pompiliano". Por detr‚Ēú√≠s de ‚Ēú¬ģste, emerge por verticalidad la estructura del destacable "Edificio Ruise‚Ēú‚Ėíores", o "Casa de los Peces" del paseo. Fuente visual: amable aportaci‚Ēú‚Ēān personal de Pablo Vald‚Ēú¬ģs.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63485200, -0.89230500, '0101000020E61000003DD52137C38DECBF6DE690D442D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26918478456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26918478456.webp', 'https://www.flickr.com/photos/zaragozaantigua/26918478456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22738, 'Plaza San Francisco c.1973', 'Un tranv‚Ēú¬°a de la l‚Ēú¬°nea 11, "Parque-San Jos‚Ēú¬ģ", pasa por la plaza de San Francisco, procecente del parque Primo de Rivera. Fuente: Heraldo de Arag‚Ēú‚Ēān.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64066800, -0.89493700, '0101000020E61000000B5F5FEB52A3ECBFFFCBB56801D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31496043090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31496043090.webp', 'https://www.flickr.com/photos/zaragozaantigua/31496043090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22787, 'P.‚Ē¨‚ēĎ Fernando el Cat‚Ēú‚Ēālico 1976', 'Imagen capturada en el arranque del paseo de Fernando el Cat‚Ēú‚Ēālico desde el cruce con la avenida de Goya. Perduran sobre el firme los rieles de la tranviaria l‚Ēú¬°nea 11 Parque-San Jos‚Ēú¬ģ, clausurada a principios de ese a‚Ēú‚Ėío. El peatonal and‚Ēú¬ģn central del paseo muestra su conversi‚Ēú‚Ēān, con el benepl‚Ēú√≠cito municipal, en aparcamiento en superficie para veh‚Ēú¬°culos privados. A la derecha, el cine Gran V‚Ēú¬°a. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64426000, -0.89189000, '0101000020E61000005F24B4E55C8AECBF7C0F971C77D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38505128251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38505128251.webp', 'https://www.flickr.com/photos/zaragozaantigua/38505128251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22799, 'P.‚Ē¨‚ēĎ de Ruise‚Ēú‚Ėíores 1971', 'Imagen capturada en el paseo de Ruise‚Ēú‚Ėíores, a la altura del ingreso al nuevo complejo edilicio en construcci‚Ēú‚Ēān del n‚Ē¨‚ēĎ 26, edificado sobre el solar dejado por el antiguo Colegio Pompiliano de las Madres escolapias. A la derecha, el inmediato n‚Ē¨‚ēĎ 24, hotelito proyectado por Francisco Albi‚Ēú‚Ėíana para Victoriano Carbon‚Ēú¬ģ, cuyo muro perimetral ha sido afectado por el derribo, y un alba‚Ēú‚Ėíil se encuentra reponiendo el tramo m‚Ēú√≠s esquinero de ‚Ēú¬ģste. Unos a‚Ēú‚Ėíos despu‚Ēú¬ģs esta antigua casa tambi‚Ēú¬ģn ser‚Ēú√≠ derribada para dar paso a nuevas viviendas de la elite local, y este peque‚Ēú‚Ėío y reconstruido tramo del muro de ladrillo ser‚Ēú√≠ la ‚Ēú‚ēĎnica traza que llegar‚Ēú¬°a hasta nuestros d‚Ēú¬°as. Al fondo y a la izquierda, tras la arboleda y la acequia al aire de San Jos‚Ēú¬ģ, el Grupo Salduba. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1971, 1971, 1971, 'Anos 70', 'UNIVERSIDAD', 41.63635900, -0.88949400, '0101000020E6100000889FFF1EBC76ECBFF4C1323674D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46724937411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46724937411.webp', 'https://www.flickr.com/photos/zaragozaantigua/46724937411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22842, 'Cascada ornamental 1989', 'Nuestra Zaragoza, agosto de 1989. Construcci‚Ēú‚Ēān de la cascada ornamental con escalinata a los pies de la estatua de Alfonso I en el Cabezo. Supuso protestas ecologistas por la eliminaci‚Ēú‚Ēān de arbolado.', 1989, 1989, 1989, 'Anos 80', 'UNIVERSIDAD', 41.63426300, -0.89406300, '0101000020E6100000680932022A9CECBF0B08AD872FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15008550386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15008550386.webp', 'https://www.flickr.com/photos/zaragozaantigua/15008550386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22858, 'Cabezo de Buena Vista 1987', 'Luis M‚Ēú¬°nguez. 1987. Imagen del Parque Primo de Rivera desde la torre-mirador de la Feria de Muestras. Este pulm‚Ēú‚Ēān "verde" (sentido figurado) data de 1927, aunque el foco de la captura se fija especialmente en el Cabezo de Buena Vista, una zona que ya en 1925 hab‚Ēú¬°a sido modificada, pues de apenas un monte pelado, se planific‚Ēú‚Ēā un espacio lleno de olmos, acacias y pinos de repoblaci‚Ēú‚Ēān. Pronto se convirti‚Ēú‚Ēā en el mirador natural de la ciudad, al poco se instal‚Ēú‚Ēā all‚Ēú¬° al Batallador y su mascota, y la gente iba a pasar un rato agradable. En la imagen, aspecto del final del Paseo de San Sebasti‚Ēú√≠n, y su entronque con la Avenida de los Bearneses, en tiempos en que para llegar al Cabezo no hab‚Ēú¬°a escaleras blancas. Al fondo, tel‚Ēú‚Ēān de fondo del transcanalino barrio de Venecia. Entre el verdor, a la derecha de la estatua, un par de a‚Ēú‚Ėíos antes se hab‚Ēú¬°a inaugurado un monumento a los aragoneses confinados en campos de concentraci‚Ēú‚Ēān nazi-alemanes. No se le ve, como ahora.', 1987, 1987, 1987, 'Anos 80', 'UNIVERSIDAD', 41.63426000, -0.89396400, '0101000020E61000009CA4F9635A9BECBF9A94826E2FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15630227287.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15630227287.webp', 'https://www.flickr.com/photos/zaragozaantigua/15630227287/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22936, 'Cabezudos ap‚Ēú‚Ēācrifos c.1985', 'Foto: Jos‚Ēú¬ģ Carlos Rodr‚Ēú¬°guez. Manifestaci‚Ēú‚Ēān anti OTAN animada por cabezudos no pertenecientes a la comparsa municipal, a su paso por el paseo de Fernando el Cat‚Ēú‚Ēālico, a la altura del 33. Est‚Ēú√≠n a punto de llegar a la plaza de San Francisco. Al fondo se abre a la derecha la calle de San Juan de la Cruz. Fuente: www.facebook.com/photo.php?fbid=1401819319859258&set=...', 1985, 1985, 1985, 'Anos 80', 'UNIVERSIDAD', 41.64155000, -0.89425000, '0101000020E610000004560E2DB29DECBFD95F764F1ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32503616501.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32503616501.webp', 'https://www.flickr.com/photos/zaragozaantigua/32503616501/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23052, 'Gran V‚Ēú¬°a 1994', 'Imagen capturada desde la altura del inmueble del n‚Ē¨‚ēĎ 2 del paseo de Fernando el Cat‚Ēú‚Ēālico y centrada en la rotonda automovil‚Ēú¬°stica situada en el estrat‚Ēú¬ģgico punto donde confluyen el arranque de este paseo, el final de la Gran V‚Ēú¬°a, y se cruza la avenida de Goya. Para embellecer este duro entorno, cuando en 1995 gan‚Ēú‚Ēā las elecciones municipales el Partido Popular de Luisa Fern‚Ēú√≠ndez Rudi, se baraj‚Ēú‚Ēā la posibilidad de ubicar aqu‚Ēú¬° la estatua ecuestre del general Jos‚Ēú¬ģ Palafox realizada en bronce por Ignacio Rodr‚Ēú¬°guez Ruiz (I‚Ēú‚Ėíaki), que finalmente ser‚Ēú¬°a inaugurada a finales del a‚Ēú‚Ėío 2000 por el sustituto alcalde Jos‚Ēú¬ģ Atar‚Ēú¬ģs en la moderna plaza de Jos‚Ēú¬ģ Mar‚Ēú¬°a Forqu‚Ēú¬ģ. En la ubicaci‚Ēú‚Ēān de la imagen se instalar‚Ēú¬°a una recurrente fuentecilla.', 1994, 1994, 1994, 'Anos 90', 'UNIVERSIDAD', 41.64425500, -0.89192000, '0101000020E61000000ABFD4CF9B8AECBF6AA4A5F276D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50443828023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50443828023.webp', 'https://www.flickr.com/photos/zaragozaantigua/50443828023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23054, 'P.‚Ē¨‚ēĎ de Teruel 1994', 'Imagen del paseo de Teruel, poco antes de su desemboque en la avenida de Francisco de Goya, capturada tras el derribo, a la izquierda, del inmueble del n‚Ē¨‚ēĎ 37 y centrada en la antigua vivienda unifamiliar del n‚Ē¨‚ēĎ 39 que poco despu‚Ēú¬ģs ser‚Ēú¬°a tambi‚Ēú¬ģn derribada, y sobre cuyos solares se levantar‚Ēú¬°a poco despu‚Ēú¬ģs el actual inmueble del n‚Ē¨‚ēĎ 37-39 del paseo. La escala de la casa y el patio de acceso la se‚Ēú‚Ėíalaban como una reliquia de otras ‚Ēú¬ģpocas que, lamentablemente, no sobrevivi‚Ēú‚Ēā a esta d‚Ēú¬ģcada.', 1994, 1994, 1994, 'Anos 90', 'UNIVERSIDAD', 41.64791100, -0.89306800, '0101000020E61000000455A3570394ECBFFDDB65BFEED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50446016076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50446016076.webp', 'https://www.flickr.com/photos/zaragozaantigua/50446016076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23080, 'Calle Santa Teresa 2000', 'A finales de los a‚Ēú‚Ėíos 20 del pasado siglo, en un vial del entonces nuevo ensanche de Miralbueno, que tras el 18 de julio de 1936 ser‚Ēú√≠ denominado calle Santa Teresa de Jes‚Ēú‚ēĎs, fue construida una casa en estilo racionalista (dise‚Ēú‚Ėío de Secundino Zuazo) que se convirti‚Ēú‚Ēā en residencia de la familia del fil‚Ēú‚Ēālogo Jos‚Ēú¬ģ Manuel Blecua (nacido en 1939). Se le adjudic‚Ēú‚Ēā el n‚Ē¨‚ēĎ 37 de la calle. Al comienzo de la d‚Ēú¬ģcada de los 90, su propietaria vendi‚Ēú‚Ēā el terreno a una constructora para ser piqueteada la casa, y aprovechar con m‚Ēú√≠s rentabilidad econ‚Ēú‚Ēāmica su hasta entonces desperdiciado potencial porcentaje de edificabilidad. Algunos ciudadanos, entre 1994 y 2000, intentaron impedirlo, pero la ‚Ēú‚ēĎltima palabra municipal (Gerencia de Urbanismo) dio luz verde al progreso, y el 21 de abril de 2000 esta casita fue encaminada hacia su transformaci‚Ēú‚Ēān en un bloque de cinco pisos y diez apartamentos que fue denominado "Edificio Blecua", otro ejemplo de la compatibilidad entre la ecolog‚Ēú¬°a patrimonial y el desarrollo urban‚Ēú¬°stico en esta ciudad. Fuente: blogs.heraldo.es/', 2000, 2000, 2000, 'Siglo XXI', 'UNIVERSIDAD', 41.63945200, -0.89420500, '0101000020E6100000056EDDCD539DECBF4FAE2990D9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17046904979.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17046904979.webp', 'https://www.flickr.com/photos/zaragozaantigua/17046904979/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23153, 'Avenida Goya 2009', 'Foto: V‚Ēú¬°ctor Lax. Fuente en el cruce de la avenida de Goya (izquierda) con el fin de la Gran V‚Ēú¬°a (derecha), instalada en la segunda mitad de los noventa. Ser‚Ēú√≠ eliminada en 2011 con motivo de la implantaci‚Ēú‚Ēān del tranv‚Ēú¬°a y de la construcci‚Ēú‚Ēān de la estaci‚Ēú‚Ēān de cercan‚Ēú¬°as Zaragoza-Goya, inaugurada en 2012. Fuente: Heraldo de Arag‚Ēú‚Ēān.', 2009, 2009, 2009, 'Siglo XXI', 'UNIVERSIDAD', 41.64426000, -0.89189000, '0101000020E61000005F24B4E55C8AECBF7C0F971C77D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32342265053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32342265053.webp', 'https://www.flickr.com/photos/zaragozaantigua/32342265053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23165, 'Avenida Goya 2009', 'Foto: Javier Cebollada/ Agencia EFE. Vista de la avenida de Goya en marzo de 2009, desde su cruce con la calle de Calatayud. A la izquierda, iglesia parroquial del Coraz‚Ēú‚Ēān de Mar‚Ēú¬°a, en el n‚Ēú‚ēĎmero 67. A la derecha, obras en los edificios de la calle de las Cortes de Arag‚Ēú‚Ēān 32 y la avenida de Goya 60. Este ‚Ēú‚ēĎltimo inmueble ser‚Ēú√≠ recrecido durante el proceso. Sobre el andamio, publicidad de la Uni‚Ēú‚Ēān de Ateos y Librepensadores, colocada tras la negativa de TUZSA a incluir en los autobuses urbanos el eslogan "Probablemente dios no existe. Deja de preocuparte y disfruta la vida". Se trataba de una campa‚Ēú‚Ėía nacida en el Reino Unido en 2008, promovida por la British Humanist Association (1896). Fuente: Heraldo de Arag‚Ēú‚Ēān.', 2009, 2009, 2009, 'Siglo XXI', 'UNIVERSIDAD', 41.64490900, -0.89280200, '0101000020E610000063B5F97FD591ECBFB2F2CB608CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32653934190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32653934190.webp', 'https://www.flickr.com/photos/zaragozaantigua/32653934190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23212, 'Avenida Goya 2011', 'Foto: V‚Ēú¬°ctor Lax. Vista de la avenida de Francisco de Goya, tramo comprendido entre la Gran V‚Ēú¬°a (izquierda) y el paseo de Sagasta (al fondo). Se est‚Ēú√≠n efectuando las obras de construcci‚Ēú‚Ēān de la estaci‚Ēú‚Ēān ferroviaria Zaragoza-Goya, que ser‚Ēú√≠ inaugurada en abril de 2012. En primer tramo, obras del tranv‚Ēú¬°a. Fuente: Heraldo de Arag‚Ēú‚Ēān.', 2011, 2011, 2011, 'Siglo XXI', 'UNIVERSIDAD', 41.64398400, -0.89128700, '0101000020E6100000CF328B506C85ECBFDA9255116ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35794892414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35794892414.webp', 'https://www.flickr.com/photos/zaragozaantigua/35794892414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23223, 'Colegio Jes‚Ēú‚ēĎs y Mar‚Ēú¬°a 2016', 'Vista desde la avenida de Goya del solar del antiguo colegio de las religiosas de Jes‚Ēú‚ēĎs y Mar‚Ēú¬°a, fundado en 1930 y en desuso desde 1997, cuando se constituy‚Ēú‚Ēā el colegio de los jesuitas unificado en el edificio de la Romareda y se vendi‚Ēú‚Ēā el complejo a la promotora Bilbao Patrimonial Wilcox, de la familia Llorente Sanz. Un solar de casi 9.000 m2 entre la avenida de Goya y la calle de las Cortes de Arag‚Ēú‚Ēān, cuyo estatus ya en 2002 y 2008 se ide‚Ēú‚Ēā permutar, de usos sociales (deportivos, culturales, educativos, sanitarios, asistenciales, religiosos o de espect‚Ēú√≠culos) a urban‚Ēú¬°sticos (residenciales), por parte del Gobierno municipal del PSOE. En 2016, con Zaragoza en Com‚Ēú‚ēĎn al frente del Ayuntamiento, se neg‚Ēú‚Ēā la recalificaci‚Ēú‚Ēān a los propietarios, que intentaban levantar 380 pisos. Ya a finales de 2020, con el Partido Popular, se volvi‚Ēú‚Ēā a desempolvar el proyecto, inici‚Ēú√≠ndose los tr‚Ēú√≠mites para modificar el PGOU vigente (de 2001) con los votos a favor de PP, PSOE, Ciudadanos y Vox. La intentona pretend‚Ēú¬°a esta vez construir 170 viviendas libres y conseguir de rond‚Ēú‚Ēān la venta del edificio escolar de 1939 al Ayuntamiento, una vez incrementado su valor tras la permuta y con la carga p‚Ēú‚ēĎblica de su consiguiente rehabilitaci‚Ēú‚Ēān. En 2024 se inici‚Ēú‚Ēā el derribo.', 2016, 2016, 2016, 'Siglo XXI', 'UNIVERSIDAD', 41.64617400, -0.89296100, '0101000020E6100000834F73F22293ECBF44C362D4B5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51247730305.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51247730305.webp', 'https://www.flickr.com/photos/zaragozaantigua/51247730305/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25008, 'C.‚Ē¨‚ēĎ de Cuarte 1899', 'Imagen de la f‚Ēú√≠brica de "peinado" de hilados de lana y confecci‚Ēú‚Ēān de tejidos de fajas de Joaqu‚Ēú¬°n Herrero, luego continuada por su hijo, cuya direcci‚Ēú‚Ēān publicitaria y comercial la situaba en el paseo de Ruise‚Ēú‚Ėíores, si bien su ubicaci‚Ēú‚Ēān visual parece orientarnos algo m‚Ēú√≠s cerca del antiguo camino de Cuarte, que es el vial que aparece en la imagen, entre las escalonadas terrazas en descenso desde el nivel del Canal Imperial de Arag‚Ēú‚Ēān (a la derecha, fuera de plano), junto a la acequia que derivaba agua primero a la f‚Ēú√≠brica de harinas de Monares, y luego a esta instalaci‚Ēú‚Ēān textil, para terminar en la acequia de las Adulas, o de San Jos‚Ēú¬ģ. Fuente visual: posiblemente foto Coyne, en "Arag‚Ēú‚Ēān Ilustrado" n‚Ē¨‚ēĎ 2 (7 de enero de 1899).', 1899, 1899, 1899, 'Siglo XIX', 'UNIVERSIDAD', 41.63487600, -0.89165000, '0101000020E61000000E4FAF946588ECBFF581E49D43D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31634637183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31634637183.webp', 'https://www.flickr.com/photos/zaragozaantigua/31634637183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25991, 'Vista a‚Ēú¬ģrea El Pilar 1927', 'Foto Gaspar, 1927. Vista a‚Ēú¬ģrea de la plaza del Pilar de Zaragoza y su entorno. Fuente: La Esfera, 13 de agosto de 1927.', 1927, 1927, 1927, 'Anos 20', 'CASCO HIST‚Ēú√īRICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19850094498.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19850094498.webp', 'https://www.flickr.com/photos/zaragozaantigua/19850094498/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23324, 'Iglesia del Coraz‚Ēú‚Ēān de Mar‚Ēú¬°a 1964', 'Fototeca Universidad de Sevilla. Antonio Palau. Agosto de 1964. "Iglesia del Coraz‚Ēú‚Ēān de Mar‚Ēú¬°a". La Congregaci‚Ēú‚Ēān de los Misioneros Hijos del Inmaculado Coraz‚Ēú‚Ēān de Mar‚Ēú¬°a, o "Claretianos", llevaban instalados en la ciudad desde 1924, primero en la Avenida Central n‚Ē¨‚ēĎ 8 (actual calle Zumalac‚Ēú√≠rregui), luego en la Avenida Siglo XX n‚Ē¨‚ēĎ 37 (actual P‚Ē¨‚ēĎ de Cu‚Ēú¬ģllar), y en 1940 en una peque‚Ēú‚Ėía capilla de la calle del Carmen (en el actual S. Antonio M‚Ē¨¬¨ Claret n‚Ē¨‚ēĎ 9-11). Al comienzo de los a‚Ēú‚Ėíos 50, adquirieron terrenos para construir el "Templo o Santuario del Coraz‚Ēú‚Ēān de Mar‚Ēú¬°a", junto a la trinchera del ferrocarril (actual Avenida de Goya n‚Ē¨‚ēĎ 65). Las obras comenzaron en 1954, bajo la direcci‚Ēú‚Ēān del arquitecto Eduardo Lagunilla de Plandolit. En 1956 retomaron el culto ya aqu‚Ēú¬°, y el templo fue finalizado en mayo de 1964, con la denominaci‚Ēú‚Ēān de "Parroquia del Coraz‚Ēú‚Ēān de Mar‚Ēú¬°a". En este 2014 han cumplido los 50 a‚Ēú‚Ėíos en esa ubicaci‚Ēú‚Ēān. La imagen ha sido tomada desde la Avenida de Goya, capturando la fachada principal, y un aspecto del lateral que daba al solar hoy ocupado por el bloque de viviendas del n‚Ē¨‚ēĎ 67 de la Avenida. Fuente visual: fototeca.us.es/imagen.jsp?id=25794&tipo=v&elto=18... Fuente textual: www.cormariazaragoza.es/?-HISTORIA-PDF-BODAS-DE-ORO-', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.64534400, -0.89340000, '0101000020E610000082E2C798BB96ECBFBD55D7A19AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15448577199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15448577199.webp', 'https://www.flickr.com/photos/zaragozaantigua/15448577199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23347, 'Av. de Goya 1967', 'Imagen capturada desde cierta altura del despejado tramo final de la moderna avenida de Goya durante la fase de urbanizaci‚Ēú‚Ēān tras el reciente soterramiento de la l‚Ēú¬°nea ferroviaria de Barcelona a su paso por la que fuera antigua calle del Padre Claret. A la derecha, manzanas del lado de los pares entre las calles del Carmen, C‚Ēú√≠novas y el paseo de Teruel, entre las que destaca la del convento-residencia de los PP. Pa‚Ēú‚ēĎles. Al fondo, entorno de la estaci‚Ēú‚Ēān de Campo Sepulcro Fuente visual: AMZ.', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.64645900, -0.89370000, '0101000020E610000029ED0DBE3099ECBF399A232BBFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40881298151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40881298151.webp', 'https://www.flickr.com/photos/zaragozaantigua/40881298151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23386, 'Canal Imperial 1925', 'Imagen convertida en postal por Lucien Roisin, tomada desde la margen derecha del Canal Imperial, en el entorno de la acentuada curva que, hacia la derecha, lo conduce al largo y recto tramo del embarcadero de Venecia, y el puente de Am‚Ēú¬ģrica. A la izquierda aparece parcialmente el chalet Buenavista y el camino que conduce al cabezo del mismo nombre, en el parque de Buenavista, antes de que el dictador Primo de Rivera lo inaugurara oficialmente. Al fondo, un descenso en pronunciada pendiente nos llevar‚Ēú¬°a al camino viejo de Cuarte, al del S‚Ēú√≠bado, y a la acequia de las Adulas, o de San Jos‚Ēú¬ģ. A la derecha, asoma la fachada de la harinera "La Imperial de Arag‚Ēú‚Ēān", esquinera con el paseo de Ruise‚Ēú‚Ėíores. En el lugar escogido por Roisin para capturar esta fotograf‚Ēú¬°a, varias d‚Ēú¬ģcadas despu‚Ēú¬ģs ser‚Ēú√≠ construida una alta pasarela peatonal sobre el Canal para conectar con el barrio de Venecia, que subsiste. Fuente visual: www.todocoleccion.net/', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.63268200, -0.89156800, '0101000020E6100000C51F459DB987ECBF4A6249B9FBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30918229051.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30918229051.webp', 'https://www.flickr.com/photos/zaragozaantigua/30918229051/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23394, 'P.‚Ē¨‚ēĎ del Canal c.1926', 'Invernal imagen capturada en el paseo del Canal, en la curva tras la que al fondo se eleva el cabezo de Buenavista. A la izquierda, vista de la antigua vivienda unifamiliar en el n‚Ē¨‚ēĎ 31 de la V‚Ēú¬°a de Pignatelli, en el barrio de Venecia. Por el Canal Imperial de Arag‚Ēú‚Ēān desciende una barca a remos encaminada hacia el embarcadero recreativo ubicado aguas abajo. Tras ella, vivienda del guarda del cabezo de Buenavista, y lateral del chalet de Las Palmeras. A la derecha, fachada canalina de la f‚Ēú√≠brica de harinas de Monares. En primer t‚Ēú¬ģrmino, sombra del fot‚Ēú‚Ēāgrafo autor de la instant‚Ēú√≠nea.', 1926, 1926, 1926, 'Anos 20', 'UNIVERSIDAD', 41.63388000, -0.89067500, '0101000020E610000071AC8BDB6880ECBF53CBD6FA22D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48511149287.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48511149287.webp', 'https://www.flickr.com/photos/zaragozaantigua/48511149287/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23639, 'Puente V‚Ēú¬°a Transversal 1933', 'Dentro del Plan de Ensanche de ese a‚Ēú‚Ėío, la Avenida Perimetral estaba previsto que fuera una nueva v‚Ēú¬°a urbana con que enlazar las carreteras de Madrid y de Castell‚Ēú‚Ēān sin pasar por el centro de la ciudad. Junto con la Avenida del Ferrocarril MZA, esta v‚Ēú¬°a se convertir‚Ēú¬°a en una ronda de circunvalaci‚Ēú‚Ēān, con m‚Ēú√≠s de cinco kil‚Ēú‚Ēāmetros de desarrollo. Para realizarla hab‚Ēú¬°a que superar la trinchera del Huerva mediante un nuevo puente. En la imagen, el Puente de la V‚Ēú¬°a Transversal. Al fondo, el ensanche de la Gran V‚Ēú¬°a. Al fondo, la torre del Cuartel de Transmisiones del Ej‚Ēú¬ģrcito de Tierra, que en 1943 se convertir‚Ēú√≠ en el Colegio de La Salle Gran V‚Ēú¬°a. M‚Ēú√≠s tarde, este puente recibir‚Ēú¬°a el nombre de "Emperador Augusto" (popularmente "de los Gitanos"), y la ronda de circunvalaci‚Ēú‚Ēān se quedar‚Ēú¬°a en calle de Juan Pablo Bonet.', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.64077500, -0.88974700, '0101000020E610000001DA56B3CE78ECBF158C4AEA04D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15137486006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15137486006.webp', 'https://www.flickr.com/photos/zaragozaantigua/15137486006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23953, 'Cine Gran V‚Ēú¬°a 1943', 'Esquina de la calle Padre Claret con el paseo de Calvo Sotelo (tramo luego redenominado Fernando el Cat‚Ēú‚Ēālico). Abajo a la derecha, el pretil del t‚Ēú‚ēĎnel ferroviario, que estaba a‚Ēú‚ēĎn sin cubrir. En el chafl‚Ēú√≠n, el cine Gran V‚Ēú¬°a reci‚Ēú¬ģn inaugurado ese mismo a‚Ēú‚Ėío.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.64410300, -0.89227700, '0101000020E6100000C022BF7E888DECBFB42094F771D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14761800597.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14761800597.webp', 'https://www.flickr.com/photos/zaragozaantigua/14761800597/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24033, 'Parque de Buenavista 1931', 'Imagen panor‚Ēú√≠mica, desde las alturas del cabezo de Buena Vista, del paseo central del hom‚Ēú‚Ēānimo parque, donde ten‚Ēú¬°a lugar una marcial promesa de fidelidad a la bandera por parte de una remesa de reclutas del cuerpo de instrucci‚Ēú‚Ēān. Al fondo, tras cruzar el puente del 14 de julio sobre el r‚Ēú¬°o Huerva, la mole del cuartel de artiller‚Ēú¬°a de Palafox. Como consecuencia derivada de la llegada de la Segunda Rep‚Ēú‚ēĎblica en abril de ese a‚Ēú‚Ėío, en el ‚Ēú√≠mbito castrense fueron reformados sus actos identitarios, entre los que destacaba la jura de bandera, que fue sustituida por la ceremonia de la promesa de fidelidad a la bandera, con una nueva f‚Ēú‚Ēārmula que modificaba antiguos conceptos, como dios, y rey: "Pregunta. ‚Ē¨‚ĒźPromet‚Ēú¬ģis ser fieles a la Naci‚Ēú‚Ēān, leales al Gobierno de la Rep‚Ēú‚ēĎblica y obedecer y respetar y no abandonar al que os mande? Respuesta. S‚Ēú¬°, prometo. R‚Ēú¬ģplica. La Ley os amparar‚Ēú√≠ y la Naci‚Ēú‚Ēān os premiar‚Ēú√≠ si lo hac‚Ēú¬ģis, y si no, ser‚Ēú¬ģis castigados." Fuente visual: Foto Palacio, "La Hormiga de Oro".', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63440400, -0.89428200, '0101000020E6100000DCD8EC48F59DECBFCE39782634D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26355462601.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26355462601.webp', 'https://www.flickr.com/photos/zaragozaantigua/26355462601/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24077, 'P.‚Ē¨‚ēĎ de Fernando el Cat‚Ēú‚Ēālico 1943', 'Imagen capturada en el ensanche de Miralbueno y centrada en la moderna manzana de viviendas dise‚Ēú‚Ėíada por los arquitectos Miguel ‚Ēú√ľngel Navarro P‚Ēú¬ģrez y Jos‚Ēú¬ģ Luis Navarro Anguela en el arranque de los n‚Ēú‚ēĎmeros pares del tramo de la Gran V‚Ēú¬°a redenominado como paseo de Fernando el Cat‚Ēú‚Ēālico. En la achaflanada esquina destaca el nov‚Ēú¬°simo cinemat‚Ēú‚Ēāgrafo Gran V‚Ēú¬°a, reci‚Ēú¬ģn inaugurado ese mismo a‚Ēú‚Ėío. A ambos lados del paseo central sobresalen los soportes del tendido el‚Ēú¬ģctrico de la tranviaria l‚Ēú¬°nea 11 Parque. A izquierda y derecha, muretes que delimitaban la trinchera al aire del ferrocarril de los directos a Barcelona. Fuente visual: herederos Palomar-Palomar, AMZ.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.64410300, -0.89227700, '0101000020E6100000C022BF7E888DECBFB42094F771D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38282945746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38282945746.webp', 'https://www.flickr.com/photos/zaragozaantigua/38282945746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22277, 'Troleb‚Ēú‚ēĎs 1966', '1966. El Troleb‚Ēú‚ēĎs 74 de la L‚Ēú¬°nea "Ciudad Jard‚Ēú¬°n" incorpor‚Ēú√≠ndose a San Juan Bosco desde la calle Pedro de Luna, para retornar a la Terminal de la Plaza de Santa Engracia. Esta unidad formaba parte de los 12 trolebuses de dos pisos adquiridos en 1961 a la compa‚Ēú‚Ėí‚Ēú¬°a "London Transport". Esta L‚Ēú¬°nea, como todas las de troleb‚Ēú‚ēĎs, ser‚Ēú√≠ sustituida por autobuses en octubre de 1975, con la misma "justificaci‚Ēú‚Ēān" que para el caso de los tranv‚Ēú¬°as. A la izquierda, las parcelas de la Ciudad Jard‚Ēú¬°n. Al fondo, la mole del Edificio Torresol. A la derecha, el edificio de la Escuela de Magisterio. Los arbolitos est‚Ēú√≠n algo m‚Ēú√≠s crecidos.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.64451200, -0.90193000, '0101000020E61000003F00A94D9CDCECBF95F0845E7FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14974185081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14974185081.webp', 'https://www.flickr.com/photos/zaragozaantigua/14974185081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24093, 'CM Cardenal Xavierre 1943', 'Imagen capturada durante la provechosa visita a la ciudad del ministro de Educaci‚Ēú‚Ēān Nacional, el turolense Jos‚Ēú¬ģ Ib‚Ēú√≠‚Ēú‚Ėíez Mart‚Ēú¬°n, a finales de junio de ese a‚Ēú‚Ėío. Durante la tercera jornada de estancia en la ciudad, y tras recibir la Medalla de Caballero del Pilar, se dirigi‚Ēú‚Ēā a terrenos inmediatos a la Ciudad Universitaria para colocar la primera piedra del Colegio Mayor Cardenal Xavierre de los PP. Dominicos. En su emotivo discurso, record‚Ēú‚Ēā los "‚Ēú√≠ureos d‚Ēú¬°as del siglo XVI", y record‚Ēú‚Ēā a los dominicos "el ineludible deber de ayudar al r‚Ēú¬ģgimen en la ingente empresa de educar a una parte de la juventud universitaria y as‚Ēú¬° lograr fecundos resultados para el destino inmortal de la patria". Esto era as‚Ēú¬° porque "la nueva universidad, inspirada en el m‚Ēú√≠s profundo sentido cat‚Ēú‚Ēālico, ha de formar a los espa‚Ēú‚Ėíoles selectos, a hombres completos que entiendan c‚Ēú‚Ēāmo deben servir a su patria en la m‚Ēú√≠s noble ambici‚Ēú‚Ēān falangista de dar a Espa‚Ēú‚Ėía una fuerte unidad interior, un indiscutible prestigio exterior y la garant‚Ēú¬°a de asegurar el pleno cumplimiento del destino de Espa‚Ēú‚Ėía en el quehacer universal". En la imagen, el ministro acompa‚Ēú‚Ėíado por locales jerarqu‚Ēú¬°as religiosas, entre las que destaca el arzobispo Rigoberto Dom‚Ēú¬ģnech Valls, y militares e institucionales como el rector de la Universidad, Miguel Sancho Izquierdo, que era a la vez decano de la Facultad de Derecho, y concejal del Ayuntamiento. Hacia el fondo, despejado fondo edilicio en torno al paseo de Fernando el Cat‚Ēú‚Ēālico.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.64162500, -0.89552500, '0101000020E61000004703780B24A8ECBFE3A59BC420D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49367239193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49367239193.webp', 'https://www.flickr.com/photos/zaragozaantigua/49367239193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24170, 'Pasarela r‚Ēú¬°o Huerva 1965', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 1965. "Pasarela sobre el r‚Ēú¬°o Huerva". Cruzar el Huerva desde la Avenida de Goya se pod‚Ēú¬°a hacer mediante el tren, o por una pasarela peatonal que ascend‚Ēú¬°a desde Zumalac‚Ēú√≠rregui. Cuando las obras de cubrimiento de al trinchera del ferrocarril, esta pasarela era un observatorio muy privilegiado para supervisar los trabajos y contemplar los avances de cada d‚Ēú¬°a.. En la imagen, y a pesar de las expl‚Ēú¬°citas contraindicaciones, gente versada en obras p‚Ēú‚ēĎblicas observando desde la pasarela c‚Ēú‚Ēāmo crec‚Ēú¬°an los muros de la doble v‚Ēú¬°a en el nuevo puente sobre el Huerva (izquierda).', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64372600, -0.89024600, '0101000020E610000055A2EC2DE57CECBFDECA129D65D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14810459188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14810459188.webp', 'https://www.flickr.com/photos/zaragozaantigua/14810459188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
